INSERT OR IGNORE INTO ability(id, eid, key, name, description, ability_type, cost, game_id, version, created_by_sub, created_at, updated_at, deleted_at)
VALUES
  (1, 'd1000000-0000-0000-0000-000000000001', 'wh2_dlc09_character_abilities_curse_of_djaf', 'Curse of Djaf', 'The essence of the Jackal-headed God imbues the bearer''s weapons with an insatiable hunger for the souls of the living.', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (2, 'd1000000-0000-0000-0000-000000000002', 'wh2_dlc09_character_abilities_curse_of_khsar', 'Curse of Khsar', 'The harsh, howling desert winds cut through everything, be it armour or clothing or raw flesh.', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (3, 'd1000000-0000-0000-0000-000000000003', 'wh2_dlc09_character_abilities_restore', 'Restore', 'Reaching behind the wall of death to bring back the soul and bind it to you takes skill, but like anything, practice makes perfect!', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (4, 'd1000000-0000-0000-0000-000000000004', 'wh2_dlc09_character_abilities_stay_here_ill_get_help', '"Stay Here, I''ll Get Help!"', 'It''s not running away. It''s knowing when and where to be to secure the best advantage.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (5, 'd1000000-0000-0000-0000-000000000005', 'wh2_dlc09_character_abilities_strike_of_tombs', 'Tombstrike', 'He whose will transcends death can strike out from beyond the grave, to devastating effect.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (6, 'd1000000-0000-0000-0000-000000000006', 'wh2_dlc09_character_abilities_tomb_king_rally', 'Reanimate', 'It takes an iron will and unnatural - supernatural - strength to rally bound troops routed by magical means.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (7, 'd1000000-0000-0000-0000-000000000007', 'wh2_dlc09_character_passive_blessing_of_asaph', 'Blessing of Asaph', 'The Asp Goddess healing touch floods Khalida''s body, permeating the husk of her corpse and snapping her back to vital, vengeful Unlife.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (8, 'd1000000-0000-0000-0000-000000000008', 'wh2_dlc09_character_passive_stone_shaper', 'Stone Shaper', 'The strength at the base of the pillar; a near-immovable force.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (9, 'd1000000-0000-0000-0000-000000000009', 'wh2_dlc09_character_passive_tretchs_raiders', 'Tretch''s Raiders', 'A master of exploiting others'' weaknesses, Tretch and his band are never where you expect them and always where they can do most damage.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (10, 'd1000000-0000-0000-0000-00000000000a', 'wh2_dlc09_character_passive_unyielding_will', 'Unyielding Will', 'Inalienable and unassailable in all things, Settra''s strength is such that he never needs to return to his sarcophagus.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (11, 'd1000000-0000-0000-0000-00000000000b', 'wh2_dlc09_character_passive_wrath_of_the_creator', 'Wrath of the Creator', 'Hatred this strong is infectious, contagious, and inescapable.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (12, 'd1000000-0000-0000-0000-00000000000c', 'wh2_dlc09_faction_passive_realm_of_souls_tier_1', 'Realm of Souls I', 'From within the Realm of Souls – Nehekhara’s revered afterlife – deceased warriors are called forth and bound to mortal remains, to find purpose once again through war.', 'wh_type_regeneration', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (13, 'd1000000-0000-0000-0000-00000000000d', 'wh2_dlc09_faction_passive_realm_of_souls_tier_2', 'Realm of Souls II', 'The spirits of warriors slain can be summoned from the Realm of Souls and bound to corporeal bodies, so that they may fight for the Tomb Kings as they did in life.', 'wh_type_regeneration', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (14, 'd1000000-0000-0000-0000-00000000000e', 'wh2_dlc09_faction_passive_realm_of_souls_tier_3', 'Realm of Souls III', 'The Liche Priests use the very breath of Nehekhara’s gods to reach into the Realm of Souls, retrieving the spirits of dead soldiers for binding and eternal service to their Tomb King’s will.', 'wh_type_regeneration', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (15, 'd1000000-0000-0000-0000-00000000000f', 'wh2_dlc09_lord_abilities_sand_storm', 'Sandstorm', 'A violent vortex that whips up a cloud of razor-sharp desert sand to lacerate and consume the foe.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (16, 'd1000000-0000-0000-0000-000000000010', 'wh2_dlc09_lord_abilities_the_liber_mortis', 'The Liber Mortis', 'One of the fabled nine Books of Nagash, this tome is one of the most potent sources of Necromantic magic in existence.', 'wh_type_area_of_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (17, 'd1000000-0000-0000-0000-000000000011', 'wh2_dlc09_lord_abilities_venom_wave', 'Venom Wave', 'Even if you survive the explosion, a surge of noxious fumes follows in its deadly wake.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (18, 'd1000000-0000-0000-0000-000000000012', 'wh2_dlc09_lord_abilities_wrath_of_ptra', 'Wrath of Ptra', 'The heavenly fire of Ptra''s rage, directed at those who dare stand against his servants.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (19, 'd1000000-0000-0000-0000-000000000013', 'wh2_dlc09_lord_passive_my_will_be_done', 'My Will Be Done', 'Death is no obstacle to those with unalterable, unassailable determination.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (20, 'd1000000-0000-0000-0000-000000000014', 'wh2_dlc09_lord_passive_the_curse', 'The Curse', 'Like an insect sting at the point of death, striking out at the killer, sapping their strength as if shot by a thousand arrows.', 'wh_type_area_of_direct_damage', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (21, 'd1000000-0000-0000-0000-000000000015', 'wh2_dlc09_spell_death_spirit_leech_bound', 'Spirit Leech', 'The Wizard extends an ebon hand towards the chosen foe, leeching its spirit through tainted sorcery.', 'wh_type_direct_damage', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (22, 'd1000000-0000-0000-0000-000000000016', 'wh2_dlc09_unit_abilities_death_from_above', 'Death from Above', 'It’s raining death! A deadly rain of skulls comes down with bone-shattering force, sending lethal splinters flying in all directions.', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (23, 'd1000000-0000-0000-0000-000000000017', 'wh2_dlc09_unit_passive_covenant_of_power', 'Covenant of Power', 'The magical power surrounding the Casket of Souls allows the Liche Priests to infuse their incantations with a portion of its energy.', 'wh_type_augment_of_the_winds', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (24, 'd1000000-0000-0000-0000-000000000018', 'wh2_dlc09_unit_passive_guardian', 'Guardian', 'In the midst of a bloodbath it''s good to know that someone has your back.', 'wh_type_area_of_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (25, 'd1000000-0000-0000-0000-000000000019', 'wh2_dlc09_unit_passive_spirit_conduit', 'Spirit Conduit', 'As a channel between the mortal world and the Realm of Souls, a Hierotitan amplifies the Liche Priest’s incantations.', 'wh_type_augment_of_the_winds', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (26, 'd1000000-0000-0000-0000-00000000001a', 'wh2_dlc09_unit_passive_unstable_mark_ii_sand', 'Disintegrating', 'The Dark Magic that holds these subjects together has failed. As the Necromantic energy flows out of them, nothing is left but a pile of iron and bones in the sand.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (27, 'd1000000-0000-0000-0000-00000000001b', 'wh2_dlc09_unit_passive_unstable_sand', 'Crumbling', 'In the blasted desert of deepest Nehekhara, the dead rarely remain so. Those dragged back to screaming, clanking Unlife are bound forever to the Tomb King whose will they exist only to serve.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (28, 'd1000000-0000-0000-0000-00000000001c', 'wh2_dlc10_hero_passive_quicksilver_shot', 'Quicksilver Shot', 'The warriors of Avelorn are famed for their ability to fire and reload in the blink of an eye.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (29, 'd1000000-0000-0000-0000-00000000001d', 'wh2_dlc10_item_passive_banner_of_avelorn', 'Banner of Avelorn', 'Crafted anew when an Everqueen ascends to the throne, the banner is a beacon of life and light.', 'wh_type_area_of_augments_of_the_winds', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (30, 'd1000000-0000-0000-0000-00000000001e', 'wh2_dlc10_lord_abilities_gaze_of_khaine', 'Gaze of Khaine', 'Those who fall under the glare of Hellebron share her lust and rage.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (31, 'd1000000-0000-0000-0000-00000000001f', 'wh2_dlc10_lord_abilities_mislead', 'Mislead', 'As a follower of the Trickster God, Loec, the Shadow King is a master of deception and distraction.', 'wh_type_hiding', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (32, 'd1000000-0000-0000-0000-000000000020', 'wh2_dlc10_lord_abilities_oath_of_vengeance', 'Oath of Vengeance', 'From the Dammaz Kron, the High King recounts an ancestral grudge towards the foe, driving the Dawi into a vengeful rage.', 'wh_type_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (33, 'd1000000-0000-0000-0000-000000000021', 'wh2_dlc10_lord_abilities_red_ruin', 'Red Ruin', 'Seeking a mighty death - despite his kingly obligations - Ungrim recklessly carves a path of red ruin through foolish enemies.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (34, 'd1000000-0000-0000-0000-000000000022', 'wh2_dlc10_lord_passive_blood_frenzy', 'Blood Frenzy', 'The Bride of Khaine is a consummate murderer; as she reaps the blood, her desire for further slaughter intensifies.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (35, 'd1000000-0000-0000-0000-000000000023', 'wh2_dlc10_lord_passive_boon_of_isha', 'Boon of Isha', 'Under Isha''s embrace, those of fey heart will be protected; that is the Everqueen''s will.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (36, 'd1000000-0000-0000-0000-000000000024', 'wh2_dlc10_spell_bound_lesser_doombolt', 'Lesser Doombolt', 'The sky opens and a bolt of burning, pure Chaos black lightning hurtles towards the foe.', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (37, 'd1000000-0000-0000-0000-000000000025', 'wh2_dlc10_spell_bound_soul_stealer_ror', 'Soul Stealer', 'Tendrils of solidified darkness writhe outwards, draining the lifeforce from foes and renewing the caster’s own vigour.', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (38, 'd1000000-0000-0000-0000-000000000026', 'wh2_dlc10_spell_bound_soulblight', 'Soulblight', 'Harnessing the sickly power of Shyish, the Wizard weakens the foe''s will to survive the battle.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (39, 'd1000000-0000-0000-0000-000000000027', 'wh2_dlc10_spell_bound_word_of_pain', 'Word of Pain', 'As the caster utters a forbidden name, their enemies are wracked with waves of agony.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (40, 'd1000000-0000-0000-0000-000000000028', 'wh2_dlc10_unit_abilities_frost_breath', 'Frost Breath', 'This ice-cold breath delivers freezing death, slowing down those who are fortunate to survive the exposure.', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (41, 'd1000000-0000-0000-0000-000000000029', 'wh2_dlc10_unit_abilities_frost_wyrm_breath', 'Frost Breath', 'This ice-cold breath delivers freezing death, slowing down those who are fortunate to survive the exposure.', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (42, 'd1000000-0000-0000-0000-00000000002a', 'wh2_dlc10_unit_passive_abyssal_howl', 'Abyssal Howl', 'The Kharibdyss lets out a spine-chilling howl, terrifying those who would dare to stand in its path.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (43, 'd1000000-0000-0000-0000-00000000002b', 'wh2_dlc10_unit_passive_guardian', 'Guardian', 'In the midst of a bloodbath it''s good to know that someone has your back.', 'wh_type_area_of_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (44, 'd1000000-0000-0000-0000-00000000002c', 'wh2_dlc10_unit_passive_the_trial_of_blades', 'The Trial of Blades', 'The laughing warrior-women dance into battle, spinning their blades with a ferocious grace.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (45, 'd1000000-0000-0000-0000-00000000002d', 'wh2_dlc10_unit_passive_unbinding_alith_anar', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (46, 'd1000000-0000-0000-0000-00000000002e', 'wh2_dlc11_character_abilities_all_hands_hoay', 'All Hands Hoay!', '"Everyone on deck! We ''ave them now!"', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (47, 'd1000000-0000-0000-0000-00000000002f', 'wh2_dlc11_character_abilities_ballistic_enchantment', 'Enchanted Ballistics', 'These particular balls give the shooter a magical advantage over their targets.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (48, 'd1000000-0000-0000-0000-000000000030', 'wh2_dlc11_character_abilities_cackle_fruit', 'Cackle Fruit', 'These particular eggs bog the foe down in ectoplasmic goo, slowing their charge and leaving them prone.', 'wh_type_magic_missile', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (49, 'd1000000-0000-0000-0000-000000000031', 'wh2_dlc11_character_abilities_ghosts_of_the_past_0', 'Ghosts of the Past', '"Pale warriors, death-pale were they all; They cried—‘La Belle Dame sans Merci thee hath in thrall!"', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (50, 'd1000000-0000-0000-0000-000000000032', 'wh2_dlc11_character_abilities_hornswaggle', 'Hornswaggle', '"Do pay attention or this one''ll ''ave the shirt from yer back!"', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (51, 'd1000000-0000-0000-0000-000000000033', 'wh2_dlc11_character_abilities_taunt', 'Taunt', '"You''re nowt but a bunch of lily-livered landlubbers! Know that your deaths will be short - soon you''ll serve under the black flag!"', 'wh_type_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (52, 'd1000000-0000-0000-0000-000000000034', 'wh2_dlc11_hero_abilities_bomb_throw', 'Bomb-Throw', 'Supernatural reserves of strength can be brought to bear with devastating effect.', 'wh_type_magic_missile', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (53, 'd1000000-0000-0000-0000-000000000035', 'wh2_dlc11_hero_abilities_more_powder', 'More Powder!', '"Where''s that powder monkey? Get him up ''ere now!"', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (54, 'd1000000-0000-0000-0000-000000000036', 'wh2_dlc11_hero_passive_dead_eyes', 'Dead Eyes', 'What dead eyes see can never be unseen, nor spoken of.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (55, 'd1000000-0000-0000-0000-000000000037', 'wh2_dlc11_lord_abilities_claws_of_mourkain', 'Claws of Mourkain', 'From deep within the Marshes of Madness, the Strigoi shall rise again!', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (56, 'd1000000-0000-0000-0000-000000000038', 'wh2_dlc11_lord_abilities_dark_protection', 'Dark Protection', '"If you need the strength, then turn to me…"', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (57, 'd1000000-0000-0000-0000-000000000039', 'wh2_dlc11_lord_abilities_dreaded_duelist', 'Dreaded Duellist', '"There are but a few who''ve faced ''im and lived to tell the tale - you can count them on the fingers of Bernard''s ''ands… and ''e''s got no ''ands."', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (58, 'd1000000-0000-0000-0000-00000000003a', 'wh2_dlc11_lord_abilities_ghoul_king_of_ushoran', 'Ghoul King of Ushoran', 'From his shattered kingdom, Prince Ushoran reaches forth and makes Lahmian dreams a twisted, hateful reality.', 'wh_type_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (59, 'd1000000-0000-0000-0000-00000000003b', 'wh2_dlc11_lord_abilities_heart_piercing', 'Heart Piercing', 'When supernatural strength and speed work together, lesser opponents have little chance to counter.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (60, 'd1000000-0000-0000-0000-00000000003c', 'wh2_dlc11_lord_abilities_lightning_reflexes', 'Lightning Reflexes', '{{tr:character_skills_localised_description_wh2_dlc11_skill_vmp_bloodline_lahmian_self_lightning_reflexes}}', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (61, 'd1000000-0000-0000-0000-00000000003d', 'wh2_dlc11_lord_abilities_mananns_luck', 'Manann''s Luck', 'The Seafather looks after his own.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (62, 'd1000000-0000-0000-0000-00000000003e', 'wh2_dlc11_lord_abilities_power_siphon', 'Power Siphon', 'By which opponents are prevented from marshalling their abilities to counteract Harkon''s own lore.', 'wh_type_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (63, 'd1000000-0000-0000-0000-00000000003f', 'wh2_dlc11_lord_abilities_seduction', 'Seduction', '"Come to my cabin… You''ll find it most comfortable I am sure…"', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (64, 'd1000000-0000-0000-0000-000000000040', 'wh2_dlc11_lord_abilities_song_of_enthrallment', 'Song of Enthrallment', '"From which tide do you hide? The dark moon’s tide is not on our side, so that is the tide that you must bribe."', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (65, 'd1000000-0000-0000-0000-000000000041', 'wh2_dlc11_lord_abilities_spearfishers_net', 'Spearfisher''s Net', '"Look at ''em all, trapped like stranded sea-turtles they are!"', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (66, 'd1000000-0000-0000-0000-000000000042', 'wh2_dlc11_lord_abilities_storm_of_the_night', 'Storm of the Night', 'When light is absent, the storm rages all the worse, filling the living with existential dread.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (67, 'd1000000-0000-0000-0000-000000000043', 'wh2_dlc11_lord_abilities_wraith_storm', 'Wraith Storm', 'A bombardment of unearthly projectiles; a storm that''s extremely hard to weather.', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (68, 'd1000000-0000-0000-0000-000000000044', 'wh2_dlc11_lord_passive_honour_or_death', 'Honour or Death', 'Unsurprisingly, some beings reconsider their options when faced with certain death.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (69, 'd1000000-0000-0000-0000-000000000045', 'wh2_dlc11_lord_passive_magical_void', 'Magical Void', 'Beyond the power to raise and bind his Undead hordes, Harkon is barren; in fact, he emanates a field of anti-magic.', 'wh_type_area_of_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (70, 'd1000000-0000-0000-0000-000000000046', 'wh2_dlc11_lord_passive_merciless_slaver', 'Merciless Slaver', 'Sometimes death is preferable to surrender.', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (71, 'd1000000-0000-0000-0000-000000000047', 'wh2_dlc11_unit_passive_abandon_ship', 'Abandon Ship!', '"Every man for ''imself! Swim for it!!"', 'wh_type_summon_unit', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (72, 'd1000000-0000-0000-0000-000000000048', 'wh2_dlc11_unit_passive_extra_powder', 'Black Powder Aplenty', 'Because you can never have too much.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (73, 'd1000000-0000-0000-0000-000000000049', 'wh2_dlc11_unit_passive_gaseous_demise', 'Gaseous Demise', 'Some drowned sailors lurch from the sea swollen with noxious gases, ready to explode upon contact with enemy blades. Keep well back!', 'wh_type_explosion', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (74, 'd1000000-0000-0000-0000-00000000004a', 'wh2_dlc11_unit_passive_noxious_unstable_mark_ii', 'Noxious Disintegration', 'Corpses bloated from spending too long at sea are like foul, decomposing balloons waiting to burst.', 'wh_type_explosion', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (75, 'd1000000-0000-0000-0000-00000000004b', 'wh2_dlc11_unit_passive_the_hunger', 'The Hunger', 'As the Vampires rip apart their victims they feast on the blood that spills forth – gaining strength and replacing lost stamina.', 'wh_type_regeneration', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (76, 'd1000000-0000-0000-0000-00000000004c', 'wh2_dlc11_unit_passive_unbinding_deckhands_mob', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (77, 'd1000000-0000-0000-0000-00000000004d', 'wh2_dlc11_unit_passive_unbinding_gunnery_mob', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (78, 'd1000000-0000-0000-0000-00000000004e', 'wh2_dlc11_unit_passive_unbinding_knights_of_the_realm', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (79, 'd1000000-0000-0000-0000-00000000004f', 'wh2_dlc11_unit_passive_unbinding_rotting_prometheans', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (80, 'd1000000-0000-0000-0000-000000000050', 'wh2_dlc12_character_abilities_brass_orb', 'Brass Orb', 'Possession of this orb enables the user to inexorably drag the foe into a turbulent vortex of pain and death.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (81, 'd1000000-0000-0000-0000-000000000051', 'wh2_dlc12_character_abilities_brass_orb_tech_lab_doom_flayer', 'Brass Orb', 'Possession of this orb enables the user to inexorably drag the foe into a turbulent vortex of pain and death.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (82, 'd1000000-0000-0000-0000-000000000052', 'wh2_dlc12_character_abilities_supreme_shield_of_the_old_ones', 'Supreme Shield of the Old Ones', 'More than just a shield, this one channels the visceral power of the Old Ones to protect its bearer from magical attack.', 'wh_type_area_of_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (83, 'd1000000-0000-0000-0000-000000000053', 'wh2_dlc12_lord_abilities_drop_sphere_of_tepok', 'Drop Sphere of Tepok', 'This magical rock causes a rather large explosion that stuns enemies, slowing them down for the kill.', 'wh_type_bombardment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (84, 'd1000000-0000-0000-0000-000000000054', 'wh2_dlc12_lord_abilities_focus_instincts', 'Focus Instincts', 'By which the mind is concentrated on the task at hand, allowing it to be carried out effectively whilst keeping passion and abandon firmly in check.', 'wh_type_area_of_augments', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (85, 'd1000000-0000-0000-0000-000000000055', 'wh2_dlc12_lord_abilities_master_of_the_skies', 'Master of the Skies', 'With the utmost speed and agility, Tiktaq''to leads his death-defying Terradon squadron from atop his prized-specimen mount, Zwup.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (86, 'd1000000-0000-0000-0000-000000000056', 'wh2_dlc12_lord_abilities_unlimited_power', 'Unlimited Power!', 'Unlimited power corrupts the already-totally-corrupted utterly.', 'wh_type_augment_of_the_winds', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (87, 'd1000000-0000-0000-0000-000000000057', 'wh2_dlc12_lord_abilities_warriors_crest', 'Warrior''s Crest', 'It''s not just for decoration, you know!', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (88, 'd1000000-0000-0000-0000-000000000058', 'wh2_dlc12_unit_abilities_ark_of_sotek', 'Ark of Sotek', 'Sotek''s crawling, swarming allies surround the bearer, affording them further might and protection in the struggle to come.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (89, 'd1000000-0000-0000-0000-000000000059', 'wh2_dlc12_unit_abilities_burning_alignment', 'Burning Alignment', 'A scorching ray of light blasts forth from the sky, putting the foe to flight or screaming, burning death - preferably the latter!', 'wh_type_wind', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (90, 'd1000000-0000-0000-0000-00000000005a', 'wh2_dlc12_unit_abilities_drop_rocks_character', 'Drop Rocks', 'Crude though it may be, swiftly swooping in low to pepper the foe with rocks remains a most effective tactic.', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (91, 'd1000000-0000-0000-0000-00000000005b', 'wh2_dlc12_unit_abilities_drop_rocks_of_chotec', 'Drop Rocks of Chotec', 'Of all the ways to go, being crushed is amongst the least pleasant, but it''s a lot worse if you''re on fire and screaming at the same time!', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (92, 'd1000000-0000-0000-0000-00000000005c', 'wh2_dlc12_unit_abilities_drop_rocks_of_sundering', 'Drop Rocks of Sundering', 'More than just a pile of rubble, these rocks also split armour apart, negating its protective capability.', 'wh_type_bombardment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (93, 'd1000000-0000-0000-0000-00000000005d', 'wh2_dlc12_unit_abilities_refuse_to_die', 'Refuse to Die', 'The surprising ability to hold back death despite some seriously heavy opposition…', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (94, 'd1000000-0000-0000-0000-00000000005e', 'wh2_dlc12_unit_abilities_shield_of_chaqua', 'Shield of Chaqua', 'This ancient golden screen - as old as the fabled golden city of the Lizardmen - confers missile resistance to both the bearer and their allies.', 'wh_type_area_of_augments', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (95, 'd1000000-0000-0000-0000-00000000005f', 'wh2_dlc12_unit_abilities_toad_rage', 'Toad Rage', 'The presence of the hated Lustrian Blot Toad sends the merciless Ripperdactyls into a barely-controlled frenzy of extreme violence!', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (96, 'd1000000-0000-0000-0000-000000000060', 'wh2_dlc12_unit_passive_arcane_configuration', 'Arcane Configuration', 'Command of this ability means never again having to run out of the Winds before the fight is well and truly done.', 'wh_type_augment_of_the_winds', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (97, 'd1000000-0000-0000-0000-000000000061', 'wh2_dlc12_unit_passive_demagoguery', 'Rabble-Rouse', 'The more prominent the warrior, the better they are at stirring up subordinates to fight the ghastliest of enemies.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (98, 'd1000000-0000-0000-0000-000000000062', 'wh2_dlc12_unit_passive_portent_of_warding', 'Portent of Warding', 'Knowing where the trap is - that''s the first step in evading it.', 'wh_type_area_of_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (99, 'd1000000-0000-0000-0000-000000000063', 'wh2_dlc12_unit_passive_the_best_defence', 'The Best Defence', 'There''s no better defence than attack… preferably with this mass of whirling blades. Stay on the right side of it if you want to live!', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (100, 'd1000000-0000-0000-0000-000000000064', 'wh2_dlc12_unit_passive_thunderous_one', 'Judgement of the Uxmac', 'The final word of the Old Ones to those not part of the Great Plan – short, clear and extremely deadly!', 'wh_type_bombardment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (101, 'd1000000-0000-0000-0000-000000000065', 'wh2_dlc13_character_abilities_big_boom', 'Big Boom', 'An explosion of this size rattles rather more than just teeth!', 'wh_type_magic_missile', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (102, 'd1000000-0000-0000-0000-000000000066', 'wh2_dlc13_character_abilities_patch_up', 'Patch Up', 'As a battlefield surgeon of great repute, Hertwig is able to swiftly dress the wounds of targeted friendly units, restoring their health.', 'wh_type_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (103, 'd1000000-0000-0000-0000-000000000067', 'wh2_dlc13_character_ability_hunters_call', 'Hunter''s Call', 'When he shouts to stand and fight, his loyal men listen and heed their leader.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (104, 'd1000000-0000-0000-0000-000000000068', 'wh2_dlc13_character_ability_ishas_rain', 'Isha''s Rain', 'Several arrows rain down swiftly from the sky, striking anything caught within their area of effect.', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (105, 'd1000000-0000-0000-0000-000000000069', 'wh2_dlc13_character_ability_shatter', 'Shatter', 'He hits the ground with such force that anyone nearby is shaken to their very core!', 'wh_type_breath', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (106, 'd1000000-0000-0000-0000-00000000006a', 'wh2_dlc13_final_battle_character_abilities_rodrik_ward_save_reduction', 'Oppressive Fighter', 'Massively reduce enemy Lords'' melee defence in Final Battle', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (107, 'd1000000-0000-0000-0000-00000000006b', 'wh2_dlc13_lord_abilities_fire_arrow', 'Arrow of Aqshy', 'These arrows will kill of course, but are mainly used to cause a disorientating, explosive spectacle to unnerve the enemy.', 'wh_type_magic_missile', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (108, 'd1000000-0000-0000-0000-00000000006c', 'wh2_dlc13_lord_abilities_hail_of_fire', 'Hail of Fire', 'It may be cruel, but the power to burn the foe to ash is extremely useful when you want to be sure of winning.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (109, 'd1000000-0000-0000-0000-00000000006d', 'wh2_dlc13_lord_abilities_hunters_snare', 'Hunter''s Snare', 'This traditional trapper''s tool is a noose made from wire; if the foe struggles, it simply tightens, cutting into the flesh.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (110, 'd1000000-0000-0000-0000-00000000006e', 'wh2_dlc13_lord_abilities_kill_shot', 'Focused Shot', 'There’s no need to rush when your target has little prospect of escape.', 'wh_type_magic_missile', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (111, 'd1000000-0000-0000-0000-00000000006f', 'wh2_dlc13_lord_abilities_miasma_of_despair', 'Miasma of Despair', 'Being able to slow the foe, drain it of energy and the will to fight on, is a mighty power to wield.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (112, 'd1000000-0000-0000-0000-000000000070', 'wh2_dlc13_lord_abilities_monstrous_strength', 'Monstrous Strength', 'Fools brace themselves for the impact – realists get well out of the way!', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (113, 'd1000000-0000-0000-0000-000000000071', 'wh2_dlc13_lord_abilities_oil_flask', 'Oil Flask', 'The distilled essence of Aqshy weakens the foe''s ability to withstand its righteous flames.', 'wh_type_magic_missile', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (114, 'd1000000-0000-0000-0000-000000000072', 'wh2_dlc13_lord_abilities_primal_roar', 'Primal Roar', 'The rallying cry of the ancient, endless, deathless, and vicious.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (115, 'd1000000-0000-0000-0000-000000000073', 'wh2_dlc13_lord_abilities_rock_of_itza', 'Rok of Itza', 'He is the stone upon which the Lizardmen''s enemies are broken.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (116, 'd1000000-0000-0000-0000-000000000074', 'wh2_dlc13_lord_passive_fleet_footed', 'Fleet-Footed', 'The true hunter knows how to move swiftly when the forest''s many predators approach, lest they become the hunted themselves.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (117, 'd1000000-0000-0000-0000-000000000075', 'wh2_dlc13_lord_passive_to_the_death', 'To the Death', 'Never knowing pain or fear, Gor-Rok''s assault is unrelenting.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (118, 'd1000000-0000-0000-0000-000000000076', 'wh2_dlc13_unit_abilities_bathed_in_blood', 'Bathed in Blood', '"Wade through blood and spill a bath-full more" is the code by which the legendary Carroburg Greatswords live and die.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (119, 'd1000000-0000-0000-0000-000000000077', 'wh2_dlc13_unit_abilities_blinding_radiance', 'Blinding Radiance', 'Their lances gleam with such luminosity that the foe cannot see to adequately defend themselves against the Templars'' devastating charge.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (120, 'd1000000-0000-0000-0000-000000000078', 'wh2_dlc13_unit_abilities_emergency_vent', 'Emergency Vent', 'Steam must be let off from time to time, which leads to screaming, scalding death for any foe too close to the Emperor''s Wrath during battle.', 'wh_type_explosion', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (121, 'd1000000-0000-0000-0000-000000000079', 'wh2_dlc13_unit_passive_dread_aversion', 'Dread Aversion', 'When you''re up to your neck in corpses - and perhaps not all of them are properly dead - it''s useful to be able to suppress your natural feelings of fear and dread.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (122, 'd1000000-0000-0000-0000-00000000007a', 'wh2_dlc13_unit_passive_grim_resolve', 'Stern Resolve', 'The Empire''s dark guardians do not retreat nor surrender, even when faced with seemingly insurmountable odds.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (123, 'd1000000-0000-0000-0000-00000000007b', 'wh2_dlc13_unit_passive_kaboom', 'Kaboom!', 'Steam Tank technology remains an inexact science, meaning they explode on occasion, and among the enemy''s ranks if good fortune prevails!', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (124, 'd1000000-0000-0000-0000-00000000007c', 'wh2_dlc14_lord_abilities_beastslaver', 'Beastslaver', 'Beastmasters share their minions’ belligerence, cutting down foemen with lash, spear, and harpoon before claiming their twitching bodies as fodder.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (125, 'd1000000-0000-0000-0000-00000000007d', 'wh2_dlc14_lord_abilities_bloodstorm', 'Bloodstorm', 'Tz’arkan’s evil is a reflection of Malus’ hate; each gives them strength and always threatens to bubble over in devastating fashion.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (126, 'd1000000-0000-0000-0000-00000000007e', 'wh2_dlc14_lord_abilities_deathmasters_sigil', 'Deathmaster''s Sigil', 'Snikch leaves his distinctive symbol traced in blood beside his victims, so others will know the Deathmaster is abroad, and live in mortal dread.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (127, 'd1000000-0000-0000-0000-00000000007f', 'wh2_dlc14_lord_abilities_halo_of_maidenly_wrath', 'Halo of Maidenly Wrath', 'The power of the Lady shone from Repanse like a halo, her sword and armour glowing with the brilliant light of divine retribution.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (128, 'd1000000-0000-0000-0000-000000000080', 'wh2_dlc14_lord_abilities_looming_dread', 'Looming Dread', 'Rather paradoxically, afflicting an enemy with profound paranoia can cause them to drop their guard.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (129, 'd1000000-0000-0000-0000-000000000081', 'wh2_dlc14_lord_abilities_reaper_of_souls', 'Reaper of Souls', 'Tz’arkan’s limitless appetite for souls enables him to use his Daemonic power to extract the very lifeforce from surrounding enemies and channel it through himself.', 'wh_type_area_of_direct_damage', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (130, 'd1000000-0000-0000-0000-000000000082', 'wh2_dlc14_lord_abilities_the_blood_price', 'The Blood Price', 'Forever tormenting Malus’ soul, Tz’arkan’s Daemonic puissance always simmers just beneath Malus’ skin.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (131, 'd1000000-0000-0000-0000-000000000083', 'wh2_dlc14_lord_abilities_the_daemons_curse', 'The Daemon''s Curse', 'Those who go to war against Malus Darkblade feel his Daemonic aura. Those who come face to face with him are infected by it.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (132, 'd1000000-0000-0000-0000-000000000084', 'wh2_dlc14_lord_abilities_tzarkan', 'Tz''arkan', 'Tz’arkan’s dark influence waxes and wanes, but when Malus relinquishes control entirely the Daemon’s supernatural strength is unleashed upon the world.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (133, 'd1000000-0000-0000-0000-000000000085', 'wh2_dlc14_lord_abilities_tzarkan_mp', 'Tz''arkan', 'Tz’arkan’s dark influence waxes and wanes, but when Malus relinquishes control entirely, the Daemon’s supernatural strength is unleashed upon the world.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (134, 'd1000000-0000-0000-0000-000000000086', 'wh2_dlc14_lord_abilities_tzarkan_spite', 'Tz''arkan', 'Tz’arkan’s dark influence waxes and wanes, but when Malus relinquishes control entirely, the Daemon’s supernatural strength is unleashed upon the world.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (135, 'd1000000-0000-0000-0000-000000000087', 'wh2_dlc14_lord_abilities_tzarkan_spite_mp', 'Tz''arkan', 'Tz’arkan’s dark influence waxes and wanes, but when Malus relinquishes control entirely, the Daemon’s supernatural strength is unleashed upon the world.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (136, 'd1000000-0000-0000-0000-000000000088', 'wh2_dlc14_lord_abilities_whiplash', 'Whiplash!', 'The startling crack of the Beastmaster’s hefty and ever-so-slightly serrated whip of Dragon-sinew suitably infuriates the beasts for battle.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (137, 'd1000000-0000-0000-0000-000000000089', 'wh2_dlc14_lord_passive_fleur_de_lys_banner', 'Fleur de Lys Banner', 'A symbol of ancient, holy significance, the magical lily only grows where the Lady appears, and is carried to war as sign of Her warriors'' devotion.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (138, 'd1000000-0000-0000-0000-00000000008a', 'wh2_dlc14_lord_passive_tzarkan', 'Tz''arkan', 'The frightening manifestation of the Drinker of Worlds leaves none questioning the extremes one may go to for self-preservation.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (139, 'd1000000-0000-0000-0000-00000000008b', 'wh2_dlc14_unit_abilities_doppelgang', 'Doppelgang', 'Now you see them, now you don’t… and now you’re seeing double.', 'wh_type_hiding', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (140, 'd1000000-0000-0000-0000-00000000008c', 'wh2_dlc14_unit_abilities_seismic_snare', 'Seismic Snare', 'Like their huge, earth-boring equivalents, Warp-Grinders can turn solid rock into dust on a smaller scale, halting enemies’ movements by pulverising the ground beneath them.', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (141, 'd1000000-0000-0000-0000-00000000008d', 'wh2_dlc14_unit_abilities_wail_of_malice', 'Wail of Malice', 'The Siren’s voice is a fearsome weapon – should its sound reach an enemy’s ears, their lifeblood begins to violently rebel through every pore.', 'wh_type_area_of_direct_damage', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (142, 'd1000000-0000-0000-0000-00000000008e', 'wh2_dlc14_unit_abilities_warp_quake', 'Warp-Quake', 'Warp-energy channelled directly into the ground causes the earth to tremble at a frequency that causes brains to rattle within skulls and bones to splinter!', 'wh_type_area_of_direct_damage', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (143, 'd1000000-0000-0000-0000-00000000008f', 'wh2_dlc14_unit_passive_aura_of_agony', 'Aura of Agony', 'Enemies who fight near a Bloodwrack Shrine find their minds twisted by the echo of the Medusa’s endless despair.', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (144, 'd1000000-0000-0000-0000-000000000090', 'wh2_dlc14_unit_passive_aura_of_ardour', 'Aura of Ardour', 'The pain of a shrine-bound Medusa permeates the battlefield, exuding a scent of suffering that invigorates those fighting alongside her.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (145, 'd1000000-0000-0000-0000-000000000091', 'wh2_dlc14_unit_passive_barbed_net', 'Barbed Net', 'Typically used to ensnare, immobilise and truss wild beasts, the Ravagers utilise their steel-wire nets against their foes to the same debilitating effect.', 'wh_type_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (146, 'd1000000-0000-0000-0000-000000000092', 'wh2_dlc14_unit_passive_crowfeast', 'Crowfeast', 'Khaine’s bloodthirst drives the murderous flock into a frenzied crescendo, enlivening and rejuvenating his foul manifestations.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (147, 'd1000000-0000-0000-0000-000000000093', 'wh2_dlc14_unit_passive_duck_and_weave', 'Duck & Weave', 'The Death Squad’s unnatural head movements and bewildering upper-body agility mean their enemies often hit nothing but air.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (148, 'd1000000-0000-0000-0000-000000000094', 'wh2_dlc14_unit_passive_unbinding_eshin_triads_ror', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (149, 'd1000000-0000-0000-0000-000000000095', 'wh2_dlc15_character_abilities_they_needs_stabbin', 'They Needs Stabbin’', '"Get yer stabbers out, boys. We ain’t leavin’ ‘til they''s fulla gashes!"', 'wh_type_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (150, 'd1000000-0000-0000-0000-000000000096', 'wh2_dlc15_hero_abilities_mither', 'Mither', 'The Troll Hag bombards the target with a tirade of unintelligible Trollish invective, powerful and relentless enough to cow even the most stoic of hearts.', 'wh_type_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (151, 'd1000000-0000-0000-0000-000000000097', 'wh2_dlc15_hero_abilities_swamp_breath', 'Swamp Breath', 'Troll Hags eat anything that finds its way into their swamps, be it alive, dead, or horribly decomposed. Their putrid breath is certainly testament to that!', 'wh_type_magic_missile', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (152, 'd1000000-0000-0000-0000-000000000098', 'wh2_dlc15_lord_abilities_da_boss_loons', 'Da Boss'' Loons', 'Force-feeding madness-inducing fungus brew to your minions can be advantageous but risky, with wholly unpredictable results.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (153, 'd1000000-0000-0000-0000-000000000099', 'wh2_dlc15_lord_abilities_da_great_un_iz_ere', 'Da Great ''Un Iz ''Ere!', 'Grom is a veritable symbol of greatness, his prodigious size rivalling even the greatest Orcs, and his ambition to conquer outweighing them all.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (154, 'd1000000-0000-0000-0000-00000000009a', 'wh2_dlc15_lord_abilities_dont_even_try_it', 'Don''t Even Try It', 'Goblins, in general, are a little twitchy to say the least. If you’ve flinched too soon, you’re probably already dead.', 'wh_type_direct_damage', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (155, 'd1000000-0000-0000-0000-00000000009b', 'wh2_dlc15_lord_abilities_dragonhorn', 'Dragonhorn', 'A single blast on the ''Dragonhorn'', forged in the fire of Draugnir''s flaming breath, causes the foe to shrink in terror, for they know what surely follows…', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (156, 'd1000000-0000-0000-0000-00000000009c', 'wh2_dlc15_lord_abilities_fermented_fungi', 'Fermented Fungi', 'Rotten mushroom gas wafted towards the enemy can cause them to lose their mind at the worst possible moment in battle.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (157, 'd1000000-0000-0000-0000-00000000009d', 'wh2_dlc15_lord_abilities_lord_of_dragons', 'Lord of Dragons', 'Imrik’s affinity with Dragons gifts him their sharpness; with his concentration heightened, even the most skilful foes struggle to land blows.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (158, 'd1000000-0000-0000-0000-00000000009e', 'wh2_dlc15_lord_abilities_smash_em_faster', 'Smash ''Em Faster', 'By the bellow of an angry Warboss, there’s always that little bit more murderousness to be squeezed from the boys.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (159, 'd1000000-0000-0000-0000-00000000009f', 'wh2_dlc15_lord_abilities_youre_next', 'You''re Next!', 'Grimgor’s reputation is one that induces paralysing fear, especially in enemies who find out they have his unwanted attentions on the battlefield!', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (160, 'd1000000-0000-0000-0000-0000000000a0', 'wh2_dlc15_lord_passive_best_of_da_best', 'Best of Da Best', 'Grimgor fears no injury, but despite his war-ravaged appearance has an unmatched knack for avoiding it.', 'wh_type_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (161, 'd1000000-0000-0000-0000-0000000000a1', 'wh2_dlc15_lord_passive_language_of_da_boyz', 'Language of Da Boyz', 'When Grom joins the fightin'' with his competent, well trained boyz; it''s proof to all of the ladz around him that he knows da language of da boyz.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (162, 'd1000000-0000-0000-0000-0000000000a2', 'wh2_dlc15_lord_passive_mistwalkers_barrage', 'Mistwalkers'' Barrage', 'The mist provides unique protection to the Warden himself, magically manifesting a torrent of arrows that rains down upon those assailing him.', 'wh_type_bombardment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (163, 'd1000000-0000-0000-0000-0000000000a3', 'wh2_dlc15_unit_abilities_arachneruption', 'Arachneruption', '"Y''see that glowin'' spot there?" "Ye." "Poke it." PHTWOOSH!!!', 'wh_type_bombardment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (164, 'd1000000-0000-0000-0000-0000000000a4', 'wh2_dlc15_unit_abilities_emberstorm', 'Emberstorm', 'The Phoenix''s spiralling dive whips the Winds of Magic into a swirling vortex of magical flame.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (165, 'd1000000-0000-0000-0000-0000000000a5', 'wh2_dlc15_unit_abilities_exploding_unit', 'Exploding Unit', 'This is a hidden ability that enables some flashy persistent banner VFX to indicate that a unit explodes', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (166, 'd1000000-0000-0000-0000-0000000000a6', 'wh2_dlc15_unit_abilities_mighty_roar', 'Mighty Roar', 'A bestial roar causes both spirit and strength to weaken.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (167, 'd1000000-0000-0000-0000-0000000000a7', 'wh2_dlc15_unit_abilities_noxious_breath_imrik', 'Shackolot''s Noxious Breath', 'Some Dragons’ noxious fumes alone have long-lasting effects on their target''s coordination – if survived in the first place.', 'wh_type_magic_missiles', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (168, 'd1000000-0000-0000-0000-0000000000a8', 'wh2_dlc15_unit_abilities_rock_bottom', 'Rock Bottom', 'Throwing bits of yourself at the enemy is either a sign of great determination... or singular stupidity.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (169, 'd1000000-0000-0000-0000-0000000000a9', 'wh2_dlc15_unit_abilities_sun_dragon_breath_imrik', 'Gordinar''s Dragon Breath', 'Despite being an adolescent in Dragon terms, Gordinar’s breath blazes with the intense power of the sun itself.', 'wh_type_magic_missiles', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (170, 'd1000000-0000-0000-0000-0000000000aa', 'wh2_dlc15_unit_passive_fiery_rebirth', 'Fiery Rebirth', 'Upon death, the potent arcane energies of the Phoenix erupt into a magnificent pyre.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (171, 'd1000000-0000-0000-0000-0000000000ab', 'wh2_dlc15_unit_passive_giant_explodin_spores', 'Giant Explodin'' Spores', 'The lurid fungus strapped to the front of this Pump Wagon explodes with immense force on contact with the enemy – much to the amusement of its Snotling crew!', 'wh_type_explosion', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (172, 'd1000000-0000-0000-0000-0000000000ac', 'wh2_dlc15_unit_passive_grim_discipline', 'Grim Discipline', 'Over centuries, some Elves become so steeped in bloodshed that fear itself abandons them.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (173, 'd1000000-0000-0000-0000-0000000000ad', 'wh2_dlc15_unit_passive_omen_of_hope', 'Omen of Hope', 'The mere sight of a Phoenix lifts the spirits of the High Elves when darkness looms.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (174, 'd1000000-0000-0000-0000-0000000000ae', 'wh2_dlc15_unit_passive_overwhelming_odour', 'Overwhelming Odour', '"If you thought them Hags smelt bad from a distance, just wait until you get up close…"', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (175, 'd1000000-0000-0000-0000-0000000000af', 'wh2_dlc15_unit_passive_pump_harder_ladz', 'Pump Harder Ladz!', '"Green boss says move! Fasta! Fasta! Move, find, crush!"', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (176, 'd1000000-0000-0000-0000-0000000000b0', 'wh2_dlc15_unit_passive_rubble_and_ruin_tier_1', 'Rubble & Ruin I', 'Being a towering, walking cluster of rocks means that big bits sometimes fall off you, much to the detriment of anything smaller nearby!', 'wh_type_bombardment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (177, 'd1000000-0000-0000-0000-0000000000b1', 'wh2_dlc15_unit_passive_rubble_and_ruin_tier_1_bombardment', 'Rubble & Ruin I', 'Being a towering, walking cluster of rocks means that big bits sometimes fall off you, much to the detriment of anything smaller nearby!', 'wh_type_bombardment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (178, 'd1000000-0000-0000-0000-0000000000b2', 'wh2_dlc15_unit_passive_rubble_and_ruin_tier_2', 'Rubble & Ruin II', 'Being a towering, walking cluster of rocks means that big bits sometimes fall off you, much to the detriment of anything smaller nearby!', 'wh_type_bombardment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (179, 'd1000000-0000-0000-0000-0000000000b3', 'wh2_dlc15_unit_passive_rubble_and_ruin_tier_2_bombardment', 'Rubble & Ruin II', 'Being a towering, walking cluster of rocks means that big bits sometimes fall off you, much to the detriment of anything smaller nearby!', 'wh_type_bombardment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (180, 'd1000000-0000-0000-0000-0000000000b4', 'wh2_dlc15_unit_passive_rubble_and_ruin_tier_3', 'Rubble & Ruin III', 'Being a towering, walking cluster of rocks means that big bits sometimes fall off you, much to the detriment of anything smaller nearby!', 'wh_type_bombardment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (181, 'd1000000-0000-0000-0000-0000000000b5', 'wh2_dlc15_unit_passive_rubble_and_ruin_tier_3_bombardment', 'Rubble & Ruin III', 'Being a towering, walking cluster of rocks means that big bits sometimes fall off you, much to the detriment of anything smaller nearby!', 'wh_type_bombardment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (182, 'd1000000-0000-0000-0000-0000000000b6', 'wh2_dlc15_unit_passive_spirit_of_gork_or_mork', 'Spirit of Gork (or Mork)', 'Few things embolden da ladz like the presence of a Rogue Idol on the battlefield, striding implacably forwards to bring inevitable doom to the enemy.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (183, 'd1000000-0000-0000-0000-0000000000b7', 'wh2_dlc15_unit_passive_thermal_thorax', 'Thermal Thorax', 'The radiant heat of the Lava Arachnarok scorches flesh and softens steel. Coincidentally, it also provides the perfect sear on a hunk of Squig meat.', 'wh_type_area_of_direct_damage', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (184, 'd1000000-0000-0000-0000-0000000000b8', 'wh2_dlc16_character_abilities_muster_of_malevolents', 'Muster of Malevolents', 'Unleashed upon a foe, these aggressive manifestations of the forest are utilised for their needle-like arrows that inflict painful wounds from afar.', 'wh_type_direct_damage', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (185, 'd1000000-0000-0000-0000-0000000000b9', 'wh2_dlc16_character_passive_murder_of_spites', 'Murder of Spites', 'Hiding in their hosts'' hollows are fiendish forms, ready to strike out at any who draw near.', 'wh_type_area_of_direct_damage', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (186, 'd1000000-0000-0000-0000-0000000000ba', 'wh2_dlc16_hero_abilities_evisceration', 'Evisceration', 'Consumed by all the rage of the Dark Gods themselves, Ghoritch turns himself into a whirling juggernaut of death.', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (187, 'd1000000-0000-0000-0000-0000000000bb', 'wh2_dlc16_hero_abilities_shock_collar', 'Shock Collar', 'Even the most vicious and impetuous monstrosities can be ‘encouraged’ to do one’s bidding with a quick jolt of Warpstone-generated electricity.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (188, 'd1000000-0000-0000-0000-0000000000bc', 'wh2_dlc16_hero_abilities_warp_frenzy', 'Warp Frenzy', 'When Ghoritch fires up his Warpstone-powered piston-driven claws, everyone within his extensive reach witnesses the true meaning of violence!', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (189, 'd1000000-0000-0000-0000-0000000000bd', 'wh2_dlc16_hero_passive_blood_shield', 'Blood Shield', 'To his loyal followers, the Lord of Murder’s bellows of rage that echo throughout the multiverse strengthen them against cowardly sorceries.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (190, 'd1000000-0000-0000-0000-0000000000be', 'wh2_dlc16_hero_passive_dance_of_loec', 'Dance of Loec', 'This ritualistic war dance requires neither rhythm nor order, enabling evasion of the enemy’s clumsy attacks, and lethal counterattacks.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (191, 'd1000000-0000-0000-0000-0000000000bf', 'wh2_dlc16_hero_passive_power_grab', 'Power Grab', '"I be leader now, yes-yes! ‘Til I die-die, or you find someone better!"', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (192, 'd1000000-0000-0000-0000-0000000000c0', 'wh2_dlc16_hero_passive_running_with_the_pack', 'Running with the Pack', 'Staying close to his mutated beasts allows the Packmaster to keep them in check and within reach of his rudimentary field surgery skills.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (193, 'd1000000-0000-0000-0000-0000000000c1', 'wh2_dlc16_lord_abilities_beast_pack', 'Beast Pack', '"Say hello-hello to my little friends, yes-yes!"', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (194, 'd1000000-0000-0000-0000-0000000000c2', 'wh2_dlc16_lord_abilities_loecs_blessing', 'Loec''s Blessing', 'Using rhythmic incantations endowed and employed by Loec himself to avoid Slaanesh’s gaze, one can stay unseen and uncaught.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (195, 'd1000000-0000-0000-0000-0000000000c3', 'wh2_dlc16_lord_abilities_remouldered', 'Remouldered', 'Masterful field surgery techniques and hastily administered steroid shots keep wounded monsters alive and keen to maximise the slaughtering.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (196, 'd1000000-0000-0000-0000-0000000000c4', 'wh2_dlc16_lord_abilities_roused_to_wrath', 'Roused to Wrath', 'A sudden sprouting of savage Dryads is often the first tangible warning that the forest’s savagery has truly been unleashed.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (197, 'd1000000-0000-0000-0000-0000000000c5', 'wh2_dlc16_lord_passive_ceithin_hars_tenacity', 'Ceithin-Har''s Tenacity', 'A true predator like Ceithin-Har shows no weakness when wounded, simply becoming even more of an impulsively deadly foe.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (198, 'd1000000-0000-0000-0000-0000000000c6', 'wh2_dlc16_lord_passive_conjoined_destiny', 'Conjoined Destiny', 'Should either sister come close to death, the spirit of one flows into the other, thus healing her.', 'wh_type_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (199, 'd1000000-0000-0000-0000-0000000000c7', 'wh2_dlc16_lord_passive_fanatical_resolve_1', 'Fanatical Resolve', 'Drycha’s soul eternally seethes, her external wounds only further fuelling her vindictive, murderous intent.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (200, 'd1000000-0000-0000-0000-0000000000c8', 'wh2_dlc16_lord_passive_gwindalors_vantage', 'Gwindalor''s Vantage', 'Gwindalor is as valuable for reconnaissance as he is for combat, sensing the most advantageous positions from which the Sisters can inflict the most harm.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (201, 'd1000000-0000-0000-0000-0000000000c9', 'wh2_dlc16_lord_passive_master_controller', 'Master Controller', 'From his most brutish creations down to his diminutive Throtlings, Throt’s knack for subjugating troops has them always fearing the possibility of failure.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (202, 'd1000000-0000-0000-0000-0000000000ca', 'wh2_dlc16_spell_bound_earth_blood', 'Earth Blood', 'The Wizard draws wholesome energies from the soil, imbuing companions with the natural resilience of the earth.', 'wh_type_area_of_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (203, 'd1000000-0000-0000-0000-0000000000cb', 'wh2_dlc16_spell_bound_flesh_to_stone', 'Flesh to Stone', 'This spell temporarily transforms allies'' mortal flesh into unbreakable rock, increasing tenfold their resistance to attack.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (204, 'd1000000-0000-0000-0000-0000000000cc', 'wh2_dlc16_spell_bound_regrowth', 'Regrowth', 'By speaking Druthandor''s name the Wizard is able to heal allies'' injuries much faster than by natural means.', 'wh_type_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (205, 'd1000000-0000-0000-0000-0000000000cd', 'wh2_dlc16_spell_bound_vampires_lesser_raise_dead', 'Lesser Raise Dead', 'Necromancers can awaken mortal remains to reinforce their Undead legions.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (206, 'd1000000-0000-0000-0000-0000000000ce', 'wh2_dlc16_unit_abilities_fluid_injection', 'Fluid Injection!', 'The mutated, stitched nightmare roars in pain as a surge of specially concocted Growth Juice courses through its foul body.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (207, 'd1000000-0000-0000-0000-0000000000cf', 'wh2_dlc16_unit_abilities_whirling_death', 'Whirling Death', 'A Bladesinger’s dance may start as a mesmerising, graceful pirouette, but always ends as a violent maelstrom of slicing, gashing slaughter!', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (208, 'd1000000-0000-0000-0000-0000000000d0', 'wh2_dlc16_unit_passive_warp_discharge', 'Warp Discharge', 'One too many Warp-fuel infusions have made the Hellion a volatile mutant indeed, allowing it to spontaneously discharge destructive magical vortices at will.', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (209, 'd1000000-0000-0000-0000-0000000000d1', 'wh2_dlc17_hero_abilities_more_powder_generic', 'Restock!', 'Arrows, cannonballs and more esoteric munitions are needed in endless supply on the battlefield.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (210, 'd1000000-0000-0000-0000-0000000000d2', 'wh2_dlc17_hero_passive_will_of_the_dark_gods', 'Will of the Dark Gods', 'Possessed by a singular, apocalyptic vision and utter hatred, this champion proliferates the Dark Gods'' will.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (211, 'd1000000-0000-0000-0000-0000000000d3', 'wh2_dlc17_lord_abilities_barbed_knuckle_boxing', 'Barbed-Knuckle Boxing', 'A brutally simple weapon makes the Doombull’s incredible punching power more than enough to puncture armour and cause dreadful injury.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (212, 'd1000000-0000-0000-0000-0000000000d4', 'wh2_dlc17_lord_abilities_bloodbeast', 'Bloodbeast', 'Seized by hyperviolent visions, the Bloodbeast spasms and shakes in a violent thrashing of fiery convulsions.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (213, 'd1000000-0000-0000-0000-0000000000d5', 'wh2_dlc17_lord_abilities_brass_body', 'Brass Body', 'Invoking the Dark Masters who endowed his gift, Taurox’s brazen skin temporarily hardens even further to an impossible rigidity.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (214, 'd1000000-0000-0000-0000-0000000000d6', 'wh2_dlc17_lord_abilities_master_predator', 'Master Predator', 'With stealth capabilities honed in the Realm of Chaos, Oxyotl’s skill at tracking and stalking his targets is unparalleled.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (215, 'd1000000-0000-0000-0000-0000000000d7', 'wh2_dlc17_lord_abilities_rune_of_doom', 'Rune of Doom', 'Etched upon the Anvil of Doom is a rune that can resonate with deep vibrations felt by both friend and foe.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (216, 'd1000000-0000-0000-0000-0000000000d8', 'wh2_dlc17_lord_passive_distorted_reality', 'Distorted Reality', 'A palpable miasma of fell sorcery surrounds the Bray-Shaman, distorting and maiming reality.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (217, 'd1000000-0000-0000-0000-0000000000d9', 'wh2_dlc17_lord_passive_master_of_the_ancient_lore', 'Master of the Ancient Lore', 'The self-crafted, rune-covered armaments of the most learned Runelords can harness the Winds’ potency each time they are brought to blows.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (218, 'd1000000-0000-0000-0000-0000000000da', 'wh2_dlc17_spell_bound_lesser_chain_lightning', 'Lesser Chain Lightning', 'Lightning arcs across the battlefield, leaping from foe-to-foe with crackling fury until there are none left within the storm.', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (219, 'd1000000-0000-0000-0000-0000000000db', 'wh2_dlc17_spell_bound_urannons_thunderbolt', 'Urannon''s Thunderbolt', 'The caster calls down a mighty ball of lightning and hurls it - should the foe be struck they will surely be shattered!', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (220, 'd1000000-0000-0000-0000-0000000000dc', 'wh2_dlc17_unit_abilities_primeval_roar', 'Primeval Roar', 'All Lizardmen are roused at the wailing cry of the Troglodon, its eerie call stirring their savagery.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (221, 'd1000000-0000-0000-0000-0000000000dd', 'wh2_dlc17_unit_passive_aura_of_madness', 'Aura of Madness', 'Those that look upon the Jabberslythe for too long will suffer insanity, even causing injury to themselves in desperation of escape.', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (222, 'd1000000-0000-0000-0000-0000000000de', 'wh2_dlc17_unit_passive_bloodgreed_upgraded', 'Goregreed', 'Becoming more savage and frenzied the greater the scent and sight of blood.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (223, 'd1000000-0000-0000-0000-0000000000df', 'wh2_dlc17_unit_passive_drunken_bravado', 'Drunken Bravado', 'Fuelled by looted wine, the Centigors strut and swagger with vulgar bravado to boost their own vigour.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (224, 'd1000000-0000-0000-0000-0000000000e0', 'wh2_dlc17_unit_passive_master_of_the_sacred_places', 'Master of the Sacred Places', 'These guardians of the most secret and sacred places can manipulate their environment to obscure themselves from foes.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (225, 'd1000000-0000-0000-0000-0000000000e1', 'wh2_dlc17_unit_passive_searing_bile_blood', 'Searing Bile-Blood', 'So concentrated is the spurting vitriolic bile of this Jabberslythe’s wounds that it eats through solid armour to dissolve the flesh below.', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (226, 'd1000000-0000-0000-0000-0000000000e2', 'wh2_dlc17_unit_passive_spurting_bile_blood', 'Spurting Bile-Blood', 'This horrid creature bleeds stinking, vitriolic bile that spurts out from the slightest wound in great gouts of hissing back fluid.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (227, 'd1000000-0000-0000-0000-0000000000e3', 'wh2_dlc17_unit_passive_strength_from_flesh', 'Strength from Flesh', 'A frequent gorging on the enemy’s battle lines leads to this one’s flesh flushing red as its wounds reknit themselves.', 'wh_type_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (228, 'd1000000-0000-0000-0000-0000000000e4', 'wh2_dlc25_hero_passive_grim_resolve', 'Grim Resolve', 'The Empire''s dark guardians do not retreat. Neither do they surrender, even when faced with seemingly insurmountable odds.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (229, 'd1000000-0000-0000-0000-0000000000e5', 'wh2_dlc25_hero_passive_tools_of_judgement', 'Tools of Judgement', 'When serving as judge, jury and executioner, one must have the correct tools if the wicked are to be weeded out for punishment.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (230, 'd1000000-0000-0000-0000-0000000000e6', 'wh2_main_character_abilities_assassins_trophy', 'Assassin''s Trophy', 'It should be no great surprise that those already adept in the art of silent death continue to improve with time and practice.', 'wh_type_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (231, 'd1000000-0000-0000-0000-0000000000e7', 'wh2_main_character_abilities_black_lotus', 'Black Lotus', 'This poison contains a powerful narcotic and drives its victims to delusional insanity.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (232, 'd1000000-0000-0000-0000-0000000000e8', 'wh2_main_character_abilities_cold_blooded', 'Cold-Blooded', 'While Lizardmen may be slow to react due to their cold-blooded nature, this also makes them stoic in battle.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (233, 'd1000000-0000-0000-0000-0000000000e9', 'wh2_main_character_abilities_concealment_bombs', 'Concealment Bombs', 'When a bomb is smashed, a dark smoke curls out, concealing those who wish to hide and choking everyone else.', 'wh_type_hiding', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (234, 'd1000000-0000-0000-0000-0000000000ea', 'wh2_main_character_abilities_dark_venom', 'Dark Venom', 'A victim of Dark Venom knows only a drawn-out and agonising death.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (235, 'd1000000-0000-0000-0000-0000000000eb', 'wh2_main_character_abilities_shield_of_the_old_ones', 'Shield of the Old Ones', 'The resilience of the Old Ones is channelled into an energy barrier that protects its users from the full brunt of magical attacks against them.', 'wh_type_area_of_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (236, 'd1000000-0000-0000-0000-0000000000ec', 'wh2_main_character_abilities_swiftness_of_itzl', 'Swiftness of Itzl', 'The speed and agility of the great three-horned ruler is sometimes bestowed upon his subjects.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (237, 'd1000000-0000-0000-0000-0000000000ed', 'wh2_main_character_abilities_verminous_valour', 'Verminous Valour', 'There is a sense in which the Skaven''s natural cowardice can appear to be the very pinnacle of honourable conduct.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (238, 'd1000000-0000-0000-0000-0000000000ee', 'wh2_main_character_abilities_volley_of_dark_arrows', 'Volley of Dark Arrows', 'By which an unexpected shower of pointy death rains down upon the unfortunate targets. Ouch!', 'wh_type_magic_missiles', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (239, 'd1000000-0000-0000-0000-0000000000ef', 'wh2_main_character_abilities_volley_of_high_arrows', 'Volley of High Arrows', 'By which an unexpected shower of pointy death rains down upon the unfortunate targets. Ouch!', 'wh_type_magic_missiles', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (240, 'd1000000-0000-0000-0000-0000000000f0', 'wh2_main_character_abilities_witchbrew', 'Witchbrew', 'Distilled from the blood of Hag Queens, this evil brew drives imbibers into an ecstasy of destruction.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (241, 'd1000000-0000-0000-0000-0000000000f1', 'wh2_main_character_passive_aura_of_pestilence', 'Aura of Pestilence', 'All around are caught in a deadly miasma of virulent disease that rips through their bodies with vile momentum.', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (242, 'd1000000-0000-0000-0000-0000000000f2', 'wh2_main_character_passive_darken_the_skies', 'Darken the Skies', 'Above the battlefield, the air is filled with arrows; a shroud of pure death blotting out the sun.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (243, 'd1000000-0000-0000-0000-0000000000f3', 'wh2_main_character_passive_grand_arcane_conduit', 'Greater Arcane Conduit', 'A strong mind is needed to channel the Winds of Magic. Those that have such a gift become arcane conduits – funnelling the magical tempests to their cause.', 'wh_type_augment_of_the_winds', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (244, 'd1000000-0000-0000-0000-0000000000f4', 'wh2_main_character_passive_loose', 'Loose!', 'The authorisation to loose arrows without adherence to drill makes for an irregular - and therefore far deadlier - hail of pointed death.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (245, 'd1000000-0000-0000-0000-0000000000f5', 'wh2_main_faction_abilities_murderous_mastery', 'Murderous Mastery', 'It is through killing that Dark Elves rise above other beings. Once engulfed in enough bloodshed, they will often feel their murderous prowess increase, as if Khaine himself was guiding the blades of his disciples.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (246, 'd1000000-0000-0000-0000-0000000000f6', 'wh2_main_faction_abilities_murderous_prowess', 'Murderous Prowess', 'Slaughter! There is no greater glorification of Khaine, the God of Murder, and no more popular form of worship – or indeed daily exercise – amongst the Dark Elves.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (247, 'd1000000-0000-0000-0000-0000000000f7', 'wh2_main_faction_abilities_murderous_prowess_indicator', 'Murderous Prowess Indicator', 'Once enough blood has been shed, the Dark Elves’ murderous prowess increases, as if Khaine himself was guiding his disciples'' blades!', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (248, 'd1000000-0000-0000-0000-0000000000f8', 'wh2_main_hero_abilities_doomrocket', 'Doomrocket', 'Built with secrets stolen from the mysterious east, Warlock Engineers seek to improve the propulsion and payload of these devastating weapons.', 'wh_type_magic_missile', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (249, 'd1000000-0000-0000-0000-0000000000f9', 'wh2_main_lord_abilities_feint_and_reposte', 'Feint & Riposte', 'Quite literally the cut-and-thrust of the Elven way of battle; every stroke is precisely made and finds its mark perfectly.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (250, 'd1000000-0000-0000-0000-0000000000fa', 'wh2_main_lord_abilities_gaze_of_malice', 'Gaze of Malice', 'If looks could kill… Oh wait, it turns out that they can…', 'wh_type_breath', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (251, 'd1000000-0000-0000-0000-0000000000fb', 'wh2_main_lord_abilities_potion_of_charoi', 'Potion of Charoi', 'Like Teclis before them, the deepest blue of night imbues the drinker with the stamina and strength they need to face down the foe.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (252, 'd1000000-0000-0000-0000-0000000000fc', 'wh2_main_lord_abilities_sacred_spawning_of_xhotl', 'Sacred Spawning of Xhotl', 'Kroq-Gar arises once more, born anew to take revenge upon those who stand against him.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (253, 'd1000000-0000-0000-0000-0000000000fd', 'wh2_main_lord_abilities_the_ruination_of_cities', 'The Ruination of Cities', 'The Lord unleashes a force of seismic power like no other, causing the tectonic plates themselves to shift and buckle at his behest.', 'wh_type_wind', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (254, 'd1000000-0000-0000-0000-0000000000fe', 'wh2_main_lord_abilities_trophy_heads', 'Trophy Heads', 'Oft-times, killers retain the heads of their victims as prizes or reminders of dark deeds done.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (255, 'd1000000-0000-0000-0000-0000000000ff', 'wh2_main_lord_passive_enchanting_beauty', 'Enchanting Beauty', 'Morathi''s strange, magical allure enchants opponents, making them question their loyalties and allegiances.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (256, 'd1000000-0000-0000-0000-000000000100', 'wh2_main_lord_passive_strength_through_spite', 'Strength Through Spite', 'Hatred is an energy source just like any other, to be harnessed and directed at will.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (257, 'd1000000-0000-0000-0000-000000000101', 'wh2_main_mount_abilities_unholy_clamour', 'Unholy Clamour', 'As the clanging of the Bell rises alarmingly, the Skaven''s squeaking escalates in unison; they know for whom it tolls.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (258, 'd1000000-0000-0000-0000-000000000102', 'wh2_main_mount_bound_pestilent_breath', 'Pestilent Breath', 'The swinging of the Great Censer sends a fuming fog of corruption billowing over nearby foes.', 'wh_type_breath', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (259, 'd1000000-0000-0000-0000-000000000103', 'wh2_main_mount_bound_scorch', 'Scorch', 'The tolling sound of the Screaming Bell opens fissures in the ground, allowing white-hot flame to erupt.', 'wh_type_breath', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (260, 'd1000000-0000-0000-0000-000000000104', 'wh2_main_mount_passive_billowing_death', 'Billowing Death', 'Clouds of green-tinged Warpstone fumes fill the air around the furnace, spreading pestilence in their wake.', 'wh_type_area_of_direct_damage', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (261, 'd1000000-0000-0000-0000-000000000105', 'wh2_main_mount_passive_wall_of_unholy_sound', 'Wall of Unholy Sound', 'The deafening peals toll throughout the land, driving the verminous Skaven to ever-greater heights of ferocity.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (262, 'd1000000-0000-0000-0000-000000000106', 'wh2_main_spell_bound_khaines_ring_of_fury', 'Bound Fiery Convocation', 'The caster utters words of power and a phoenix of pure fire manifests to swoop upon the enemy, bathing them in cleansing flame.', 'wh_type_wind', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (263, 'd1000000-0000-0000-0000-000000000107', 'wh2_main_unit_abilities_concealment_bombs', 'Concealment Bombs', 'When a bomb is smashed, a dark smoke curls out, concealing those who wish to hide and choking everyone else.', 'wh_type_hiding', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (264, 'd1000000-0000-0000-0000-000000000108', 'wh2_main_unit_abilities_dark_fire_of_chaos', 'Dark Fire of Chaos', 'The dark flames of Chaos burn flesh, armour and souls alike; the Ruinous Powers do not discriminate.', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (265, 'd1000000-0000-0000-0000-000000000109', 'wh2_main_unit_abilities_death_shriek', 'Death Shriek', 'Unimpeded by armour and flesh, a Terrorgheist’s horrible shriek travels through its victims, splintering bones and souls, and erasing all memory of courage.', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (266, 'd1000000-0000-0000-0000-00000000010a', 'wh2_main_unit_abilities_drop_rocks', 'Drop Rocks', 'Crude though it may be, swiftly swooping in low to pepper the foe with rocks remains a most effective tactic.', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (267, 'd1000000-0000-0000-0000-00000000010b', 'wh2_main_unit_abilities_fiery_breath', 'Fiery Breath', 'Just give the order and the Hydra''s heads will spew forth their fiery breath, each competing for the brightest flame.', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (268, 'd1000000-0000-0000-0000-00000000010c', 'wh2_main_unit_abilities_fury_of_khaine', 'Fury of Khaine', 'As the blood in the cauldron boils and bubbles, Khaine drives bloodlust to a fever pitch and stokes hearts with a violent fire.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (269, 'd1000000-0000-0000-0000-00000000010d', 'wh2_main_unit_abilities_moon_dragons_breath', 'Moon Dragon''s Breath', 'No one wants to be on the receiving end of these Dragons'' fiery breath attack, which surpasses that of their younger kin in both might and enlightenment.', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (270, 'd1000000-0000-0000-0000-00000000010e', 'wh2_main_unit_abilities_noxious_breath', 'Noxious Breath', 'Some Dragons breathe noxious fumes that have a long-lasting effect on their target''s coordination - if it survived the attack in the first place.', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (271, 'd1000000-0000-0000-0000-00000000010f', 'wh2_main_unit_abilities_pestilential_breath', 'Pestilential Breath', 'Some Dragons breathe noxious fumes that have a long-lasting effect on their target''s coordination - if it survived the attack in the first place.', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (272, 'd1000000-0000-0000-0000-000000000110', 'wh2_main_unit_abilities_revivification_crystal', 'Revivification Crystal', 'The crystal protects those who worship the Serpent God, healing wounds and bringing supplicants back from the point of death.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (273, 'd1000000-0000-0000-0000-000000000111', 'wh2_main_unit_abilities_soporific_breath', 'Soporific Breath', 'Some Dragons breathe noxious fumes that have a long-lasting effect on their target''s coordination - if it survived the attack in the first place.', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (274, 'd1000000-0000-0000-0000-000000000112', 'wh2_main_unit_abilities_star_dragons_breath', 'Star Dragon''s Breath', 'The eldest, most powerful Dragons can destroy entire units with a molten blast of their white-hot breath.', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (275, 'd1000000-0000-0000-0000-000000000113', 'wh2_main_unit_abilities_sun_dragons_breath', 'Sun Dragon''s Breath', 'The youngest Dragons have a warm hue to their scales and a fiery temper, with scorching breath to match.', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (276, 'd1000000-0000-0000-0000-000000000114', 'wh2_main_unit_abilities_wake_of_fire', 'Wake of Fire', 'As the Flamespyre swoops, wreathes of fire squall off its wings in the bird’s wake.', 'wh_type_bombardment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (277, 'd1000000-0000-0000-0000-000000000115', 'wh2_main_unit_passive_another_takes_its_place', 'Another Takes its Place', 'The titanic, deadly Hydras are notoriously difficult to kill; their broken bodies regenerate, rising up again to devour anew.', 'wh_type_regeneration', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (278, 'd1000000-0000-0000-0000-000000000116', 'wh2_main_unit_passive_attuned_to_magic', 'Attuned to Magic', 'Some creatures, such as the Phoenix, are infused with magic and use the arcane Winds to fly upon and immerse themselves in.', 'wh_type_ward_save', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (279, 'd1000000-0000-0000-0000-000000000117', 'wh2_main_unit_passive_blizzard_aura', 'Blizzard Aura', 'The Frostheart is surrounded by icy shards and biting winds with every great flap of its mighty wings.', 'wh_type_area_of_hexes', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (280, 'd1000000-0000-0000-0000-000000000118', 'wh2_main_unit_passive_bloodshield_of_khaine', 'Bloodshield of Khaine', 'Dark enchantments ensure that those who stand close to a Cauldron of Blood enjoy a degree of protection from the Bloody-handed God.', 'wh_type_area_of_ward_save', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (281, 'd1000000-0000-0000-0000-000000000119', 'wh2_main_unit_passive_martial_mastery', 'Martial Mastery', 'While all High Elves have excellent martial prowess, those that continue upon the path of the warrior will further excel in armed combat.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (282, 'd1000000-0000-0000-0000-00000000011a', 'wh2_main_unit_passive_martial_prowess', 'Martial Prowess', 'High Elves excel as warriors, having trained in martial disciplines for the equivalent of many men''s lifetimes.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (283, 'd1000000-0000-0000-0000-00000000011b', 'wh2_main_unit_passive_primal_instincts', 'Primal Instincts', 'When under pressure, the primal instincts of these natural predators take over, improving their potential in combat.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (284, 'd1000000-0000-0000-0000-00000000011c', 'wh2_main_unit_passive_rebirth', 'Rebirth', 'With strange aeons even death may die...', 'wh_type_regeneration', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (285, 'd1000000-0000-0000-0000-00000000011d', 'wh2_main_unit_passive_scurry_away', 'Scurry Away!', '"He who runs away lives to fight another day!" - so the foul, craven adage goes.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (286, 'd1000000-0000-0000-0000-00000000011e', 'wh2_main_unit_passive_snare_net', 'Snare-Net', 'Snare-nets are lightweight but strong and covered in hooks. They are used by Gutter Runners to capture live prisoners.', 'wh_type_hex', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (287, 'd1000000-0000-0000-0000-00000000011f', 'wh2_main_unit_passive_strength_in_numbers', 'Strength in Numbers', 'Skaven are craven by nature but take courage when in packs of their own kind, where they move slower but enjoy the safety of numbers.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (288, 'd1000000-0000-0000-0000-000000000120', 'wh2_main_unit_passive_the_rats_emerge', 'The Rats Emerge', 'Killing a Hell-Pit Abomination is never a simple matter; when it dies many fresh Skaven spawn to take its place.', 'wh_type_summon_unit', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (289, 'd1000000-0000-0000-0000-000000000121', 'wh2_main_unit_passive_too_horrible_to_die', 'Too Horrible to Die', 'With its last, shuddering death throes there is a chance that one or more of the foul beast''s many hearts will restart.', 'wh_type_regeneration', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (290, 'd1000000-0000-0000-0000-000000000122', 'wh2_main_unit_passive_unbinding_clanrats_small', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (291, 'd1000000-0000-0000-0000-000000000123', 'wh2_pro08_character_abilities_gotrek_doom', 'Gotrek''s Doom', 'By which the Dwarf Slayer and his mannish chronicler are protected from magical harm, forcing the foe into single combat they have little chance of surviving.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (292, 'd1000000-0000-0000-0000-000000000124', 'wh2_pro08_character_abilities_helping_hand', 'Helping Hand', 'Two blades are infinitely better than one - twice the attack, double the number of fell lives unceremoniously ended.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (293, 'd1000000-0000-0000-0000-000000000125', 'wh2_pro08_character_passive_blood_oath', 'Blood Oath', 'Gotrek''s "rememberer" has pledged with his blood to record his friend the Dwarf Slayer''s deeds until the day he finally joins his venerable Ancestors.', 'wh_type_area_of_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (294, 'd1000000-0000-0000-0000-000000000126', 'wh2_pro08_character_passive_heroic_fortitude', 'Heroic Fortitude', 'Despite involving himself in the most dangerous situations imaginable, and against the Slayer''s suicidally-brave will, Gotrek is made of sterner stuff even than others of his kind and can survive any hand-to-hand encounter.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (295, 'd1000000-0000-0000-0000-000000000127', 'wh2_twa03_lord_abilities_beastlords_gaze', 'Beastlord''s Gaze', 'With a piercing stare, Rakarth makes known his innate cruelty and bloodlust to his beastly kindred spirits, thus subduing them.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (296, 'd1000000-0000-0000-0000-000000000128', 'wh3_dlc20_character_passive_acid_ichor', 'Acid Ichor', 'The blood is transformed into a corrosive fluid. Deadly acid spurts from every wound.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (297, 'd1000000-0000-0000-0000-000000000129', 'wh3_dlc20_character_passive_soul_feeder', 'Soul Feeder', 'Some hungers can only be sated by feeding on the souls of the slain.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (298, 'd1000000-0000-0000-0000-00000000012a', 'wh3_dlc20_lord_abilities_harbinger_of_pestilence', 'Harbinger of Pestilence', 'The Leechlord exudes waves of putrid infection, sickening his enemies as disease overcomes them.', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (299, 'd1000000-0000-0000-0000-00000000012b', 'wh3_dlc20_lord_abilities_healing_elixirs', 'Healing Elixirs', 'Doktor Festus can heal as well as harm, he simply finds it far less enjoyable.', 'wh_type_area_of_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (300, 'd1000000-0000-0000-0000-00000000012c', 'wh3_dlc20_lord_abilities_tempest_rage', 'Tempest Rage', 'Shining rays of light fall upon the worthy, riling the recipient into a violent frenzy.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (301, 'd1000000-0000-0000-0000-00000000012d', 'wh3_dlc20_lord_abilities_temptator', 'Temptator', 'To face Azazel is to gamble with one’s very soul, lose free will, and be used as his plaything.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (302, 'd1000000-0000-0000-0000-00000000012e', 'wh3_dlc20_lord_passive_domineering_aura', 'Domineering Aura', 'The mere presence of one so mighty has the enemy gripped by fear, weakened by their own self-doubt.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (303, 'd1000000-0000-0000-0000-00000000012f', 'wh3_dlc20_lord_passive_paragon_of_carnage', 'Paragon of Carnage', 'Those who behold such rage incarnate would surely stare in awe, were their heads not promptly removed from their bodies.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (304, 'd1000000-0000-0000-0000-000000000130', 'wh3_dlc20_lord_passive_paragon_of_change', 'Paragon of Change', 'The magic of Tzeentch forms a protective barrier, continually strengthened according to the Wind-Lord''s whims.', 'wh_type_area_of_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (305, 'd1000000-0000-0000-0000-000000000131', 'wh3_dlc20_lord_passive_paragon_of_decay', 'Paragon of Decay', 'All who wade through such a deadly aura of decay are visibly weakened by Nurgle''s vile afflictions.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (306, 'd1000000-0000-0000-0000-000000000132', 'wh3_dlc20_lord_passive_paragon_of_excess', 'Paragon of Excess', 'Who could strike at such a tempting figure? After all, it would be a shame to mar such beguiling beauty.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (307, 'd1000000-0000-0000-0000-000000000133', 'wh3_dlc20_lord_passive_paragon_of_ruin', 'Paragon of Ruin', 'The Warriors of Chaos gather behind a force of almighty carnage, empowered by the very presence of their barbarous Lord.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (308, 'd1000000-0000-0000-0000-000000000134', 'wh3_dlc20_lord_passive_the_gaze_of_khorne', 'The Gaze of Khorne', 'Khorne''s warriors follow Valkia without question, for her strength has been proven time and again at the point of her spear.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (309, 'd1000000-0000-0000-0000-000000000135', 'wh3_dlc20_lord_passive_the_twisted_twin', 'The Twisted Twin', 'Vilitch thrives in the midst of battle, revelling in the use of his strength and sorcery combined.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (310, 'd1000000-0000-0000-0000-000000000136', 'wh3_dlc20_spell_bound_gehennas_golden_hounds', 'Gehenna''s Golden Hounds', 'Blowing on a glimmering golden whistle, the Wizard summons the spirit of Gehenna’s metal hounds to hunt down his prey.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (311, 'd1000000-0000-0000-0000-000000000137', 'wh3_dlc20_spell_bound_stream_of_corruption', 'Stream of Corruption', 'A poisonous spurt of diseased gas and bile spews forth from the spellcaster''s diseased lungs, drenching the enemy in vile, choking pus.', 'wh_type_breath', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (312, 'd1000000-0000-0000-0000-000000000138', 'wh3_dlc20_spell_bound_the_penumbral_pendulum', 'The Penumbral Pendulum', 'A spectral pendulum is summoned by the Wizard. On command, it swings, razor sharp and with lethal speed, through the foe.', 'wh_type_wind', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (313, 'd1000000-0000-0000-0000-000000000139', 'wh3_dlc20_unit_abilities_violent_wind', 'Violent Wind', '''Better out than in'' is a questionable maxim—particularly for the unfortunates caught in this deadly, reeking draught.', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (314, 'd1000000-0000-0000-0000-00000000013a', 'wh3_dlc20_unit_passive_giver_of_abundant_glory', 'Giver of Abundant Glory', 'Where bodies fall, life springs once more, healing the wounded among the warriors of Nurgle.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (315, 'd1000000-0000-0000-0000-00000000013b', 'wh3_dlc20_unit_passive_giver_of_arcane_glory', 'Giver of Arcane Glory', 'Death is but a source of power, where the lifeblood of one may fuel the arcane wizardry of another.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (316, 'd1000000-0000-0000-0000-00000000013c', 'wh3_dlc20_unit_passive_giver_of_furious_glory', 'Giver of Furious Glory', 'Khorne blesses his warriors for every enemy slain, feasting on their suffering and screams.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (317, 'd1000000-0000-0000-0000-00000000013d', 'wh3_dlc20_unit_passive_giver_of_glory', 'Giver of Glory', 'The shrinemaster implores the fickle Chaos Gods for their aid, bestowing their dark blessings upon nearby champions.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (318, 'd1000000-0000-0000-0000-00000000013e', 'wh3_dlc20_unit_passive_giver_of_torturous_glory', 'Giver of Torturous Glory', 'Agonising pain is but a thrilling delight for Slaanesh, who revels in inflicting such torture on his foes.', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (319, 'd1000000-0000-0000-0000-00000000013f', 'wh3_dlc20_unit_passive_murderous_charge', 'Murderous Charge', 'All in the path of this murderous rampage will have little chance to react before being trampled into a fine red mist.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (320, 'd1000000-0000-0000-0000-000000000140', 'wh3_dlc20_unit_passive_supreme_vanity', 'Supreme Vanity', 'What could spur one to greater heights of glory than the sight of one''s own exquisite visage, reflected in mirrored shields.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (321, 'd1000000-0000-0000-0000-000000000141', 'wh3_dlc23_character_abilities_reforge', 'Reforge', 'By which even those born of fire and flame, deep within the forge, can be healed.', 'wh_type_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (322, 'd1000000-0000-0000-0000-000000000142', 'wh3_dlc23_character_abilities_skjalandirs_fall', 'Skjalandir''s Fall', 'An aim so sharp – and a shot so precise – that it took the eye of a Dragon and saved Gotrek''s life; woe betide any on the receiving end of Ulrika''s bow and arrow!', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (323, 'd1000000-0000-0000-0000-000000000143', 'wh3_dlc23_character_abilities_sword_dance', 'The Dancing Blade', 'So graceful are her movements, and so precise her attacks, that to see Ulrika in the midst of battle is almost like witnessing a dance, rather than a slaughter.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (324, 'd1000000-0000-0000-0000-000000000144', 'wh3_dlc23_character_passive_infernal_engineer', 'Infernal Engineer', 'There are always improvements that can be made to any process; this one ensures the Chaos Dwarfs'' war machines and artillery are calibrated to perfection.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (325, 'd1000000-0000-0000-0000-000000000145', 'wh3_dlc23_hero_abilities_crooked_dice', 'Crooked Dice', 'Anything that prevents you from killing your opponents in a fit of bad-loser''s pique on more than one occasion, and then having to clear up the mess yourself afterwards, is a good thing. Now, the odds *always* swing in your favour.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (326, 'd1000000-0000-0000-0000-000000000146', 'wh3_dlc23_hero_passive_lucky_git', 'Lucky Git', '"You lucky git. You lucky, lucky git. You lucky, lucky, lucky git. You lu--"', 'wh_type_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (327, 'd1000000-0000-0000-0000-000000000147', 'wh3_dlc23_hero_passive_the_hunger', 'The Hunger', 'As the Vampires rip apart their victims they feast on the blood that spills forth – gaining in strength and lost stamina.', 'wh_type_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (328, 'd1000000-0000-0000-0000-000000000148', 'wh3_dlc23_lord_abilities_sadistic_snare', 'Sadistic Snare', 'The beauty in totally immobilising an enemy is that you can decide precisely how they will die.', 'wh_type_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (329, 'd1000000-0000-0000-0000-000000000149', 'wh3_dlc23_lord_passive_boundless_cruelty', 'Boundless Cruelty', 'The Black''s crimes are without number and his villainy without end, for Zhatan is savagery personified.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (330, 'd1000000-0000-0000-0000-00000000014a', 'wh3_dlc23_lord_passive_dark_renown', 'Dark Renown', 'Grown and built upon across the centuries of his banishment, Drazhoath''s endless contempt for all life is a tangible thing, and a power in its own right.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (331, 'd1000000-0000-0000-0000-00000000014b', 'wh3_dlc23_lord_passive_mechanical_overdrive', 'Mechanical Overdrive', 'Murder itself drives the machine, so the more it kills, the more it *can* kill. Diabolical ingenuity!', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (332, 'd1000000-0000-0000-0000-00000000014c', 'wh3_dlc23_mount_passive_horseback_prodigy', 'Horseback Prodigy', 'Some people just seem to have been born in the saddle, such is the quality of their natural horsemanship. Ulrika is one such person.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (333, 'd1000000-0000-0000-0000-00000000014d', 'wh3_dlc23_spell_bound_enfeebling_foe', 'The Enfeebling Foe', 'By means of the Lore of Shadows, the Wizard causes the enemy to be worn down by their own burdens, until they are enervated to a sorry standstill.', 'wh_type_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (334, 'd1000000-0000-0000-0000-00000000014e', 'wh3_dlc23_spell_bound_the_withering', 'The Withering', 'The Wizard destroys the foe from within, corroding their minds with doubt and crisis.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (335, 'd1000000-0000-0000-0000-00000000014f', 'wh3_dlc23_unit_abilities_flaming_breath', 'Flaming Breath', 'Use wisely, because just one careless puff will turn the Chaos Dwarfs'' own ranks to cinders!', 'wh_type_magic_missile', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (336, 'd1000000-0000-0000-0000-000000000150', 'wh3_dlc23_unit_abilities_more_power', 'More Power!', '""Wait and see," he said. "We''ll have a roaring fire, just when we want it!" He was right…"', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (337, 'd1000000-0000-0000-0000-000000000151', 'wh3_dlc23_unit_passive_backstabbers', 'Backstabbers', 'Hobgoblins are just horrid: devious, ultra-tricksy, untrustworthy killers. They''re also cowards, unsurprisingly – so don''t turn your back on one for an instant. Gottit?', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (338, 'd1000000-0000-0000-0000-000000000152', 'wh3_dlc23_unit_passive_blazing_body', 'Blazing Body', 'Birthed in the boiling blood of Hashut''s burning sacrifices, this one radiates molten heat that weakens any foe close enough to attack.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (339, 'd1000000-0000-0000-0000-000000000153', 'wh3_dlc23_unit_passive_burning_bright', 'Burning Bright', 'Once unleashed, the power of the K’daai’s sorcerous fire is so great that it consumes everything – even itself – eventually destroying the bindings holding it in shape.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (340, 'd1000000-0000-0000-0000-000000000154', 'wh3_dlc23_unit_passive_by_our_blood', 'By Our Blood', 'Kislevite warriors are inherently stronger than weak-hearted Empire-men, who know nothing of the hardship and strife of lives lived on the unforgiving steppes.', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (341, 'd1000000-0000-0000-0000-000000000155', 'wh3_dlc23_unit_passive_cowardly_despoilers', 'Cowardly Despoilers', 'Stick a Hobgoblin on a wolf and point them at the enemy, having first pointed out that if they retreat, *you''ll* kill them, and they can be most effective when massed for a charge.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (342, 'd1000000-0000-0000-0000-000000000156', 'wh3_dlc23_unit_passive_dig_in', 'Dig in!', 'When you''ve scouted an advantageous position from which to pepper the enemy with missile fire, dig in, rain death, and repeat until done.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (343, 'd1000000-0000-0000-0000-000000000157', 'wh3_dlc23_unit_passive_extra_reload', 'Extra Reload', 'Imagine if your extra ammo clip had an extra ammo clip! I know -- wild, huh?!', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (344, 'd1000000-0000-0000-0000-000000000158', 'wh3_dlc23_unit_passive_hellbound', 'Hellbound', 'Some war machines have Daemons of fury and destruction bound to their very frame and bolt, creating something even more bloodthirsty than their creators, and much more difficult to destroy.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (345, 'd1000000-0000-0000-0000-000000000159', 'wh3_dlc23_unit_passive_hellish_frenzy', 'Hellish Frenzy', 'By which this trapped Daemon spirit channels all their pent-up fury into a delirium of the worst violence possible.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (346, 'd1000000-0000-0000-0000-00000000015a', 'wh3_dlc23_unit_passive_malign_authority', 'Malign Authority', '"Best not step out of line. Heard a Labourer ask for more gruel the other day, and they put him in the pot!"', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (347, 'd1000000-0000-0000-0000-00000000015b', 'wh3_dlc23_unit_passive_pelt_of_wulfag', 'Pelt of Wulfag', 'The pelt of the legendary giant wolf steed of the Hobgoblin Lord Khengai Khan carries an ancient blessing from shamans past; no foe may turn their back on its wearer and leave the field alive.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (348, 'd1000000-0000-0000-0000-00000000015c', 'wh3_dlc23_unit_passive_revel_in_fear', 'Revel in Fear', 'By which fear of death is exploited by the attacking force, enabling them to press their advantage and wipe the foe from the battlefield.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (349, 'd1000000-0000-0000-0000-00000000015d', 'wh3_dlc23_unit_passive_sorcerous_miasma', 'Sorcerous Miasma', 'Those within sniffing distance of this enchanted pong find their own magical weapons practically useless while they remain there.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (350, 'd1000000-0000-0000-0000-00000000015e', 'wh3_dlc23_unit_passive_undying_will', 'Undying Will', 'Unshakeable, unassailable strength of will can hold back anything, even death itself.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (351, 'd1000000-0000-0000-0000-00000000015f', 'wh3_dlc24_character_abilities_bastions_defenders', 'Bastion''s Defenders', 'Sometimes, you must make a stand against a tide of Ruin. That time is now; the place is here.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (352, 'd1000000-0000-0000-0000-000000000160', 'wh3_dlc24_character_abilities_change_or_die', 'Change or Die!', 'Tzeentchian tyrants and Lords, whose word is law, ensure their troops will not run by issuing this dread order.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (353, 'd1000000-0000-0000-0000-000000000161', 'wh3_dlc24_character_abilities_colossal_strike', 'Colossal Strike', 'The bigger they are, the harder they fall.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (354, 'd1000000-0000-0000-0000-000000000162', 'wh3_dlc24_character_abilities_colossal_strike_summoned', '{{tr:unit_abilities_onscreen_name_wh3_dlc24_character_abilities_colossal_strike}}', 'The bigger they are, the harder they fall.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (355, 'd1000000-0000-0000-0000-000000000163', 'wh3_dlc24_character_abilities_fury_of_the_land', 'Fury of the Land', '"Through blood runs the power of the land. Kislev is the land. The Land is Kislev. We are Kislev!”', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (356, 'd1000000-0000-0000-0000-000000000164', 'wh3_dlc24_character_abilities_giant_leap', 'Giant Leap', 'When Saytang leaps, the ground trembles …and his foes stumble and fall.', 'wh_type_explosion', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (357, 'd1000000-0000-0000-0000-000000000165', 'wh3_dlc24_character_abilities_watched_by_the_watcher', 'Watched by the Watcher', 'Near… far… In fact, wherever it is that you are, Saytang''s belittling gaze will find you.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (358, 'd1000000-0000-0000-0000-000000000166', 'wh3_dlc24_character_passive_bulwark_of_the_gate', 'Bulwark of the Gate', 'Be the gate itself, through which none shall pass if you will it so.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (359, 'd1000000-0000-0000-0000-000000000167', 'wh3_dlc24_character_passive_master_of_the_stone_legions', 'Master of the Stone Legions', 'This paragon of Cathayan Constructs imbues others of his kind with greater resilience, be they jade, jet or stone.', 'wh_type_area_of_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (360, 'd1000000-0000-0000-0000-000000000168', 'wh3_dlc24_hero_abilities_koldunjas_spirit', 'Koldunja''s Spirit', 'When nightmarish predators are nowhere to be found, magic can assist.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (361, 'd1000000-0000-0000-0000-000000000169', 'wh3_dlc24_hero_abilities_thorns_aura', 'Thorn''s Aura', 'Once caught in a vice-like grip of vines, each thorn is a sharpened blade, piercing the skin and tearing at fragile flesh.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (362, 'd1000000-0000-0000-0000-00000000016a', 'wh3_dlc24_hero_abilities_vorozhejas_foresight', 'Vorozheja''s Foresight', 'No enemy can fight the cursed lashings of fate, binding them to their inevitable doom.', 'wh_type_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (363, 'd1000000-0000-0000-0000-00000000016b', 'wh3_dlc24_hero_abilities_znarkharjas_ward', 'Znarkharja''s Ward', 'A folk witch''s ward is a powerful protection, meant to tend all manner of wound and ailment.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (364, 'd1000000-0000-0000-0000-00000000016c', 'wh3_dlc24_hero_passive_assume_command', 'Assume Command', '"It’s time for action, not words! In defence of the future!"', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (365, 'd1000000-0000-0000-0000-00000000016d', 'wh3_dlc24_hero_passive_breath_of_life', 'The Breath of Life', 'One of Tzeentch’s most mysterious and bizarre gifts, Aekold''s body springs new and vigorous growth, constantly restoring his own lifeforce.', 'wh_type_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (366, 'd1000000-0000-0000-0000-00000000016e', 'wh3_dlc24_hero_passive_meeting_of_the_minds', 'Meeting of the Minds', 'You know what they say: "Three heads are better than one!" Well, that might not be strictly true, but they definitely should.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (367, 'd1000000-0000-0000-0000-00000000016f', 'wh3_dlc24_hero_passive_spell_syphon', 'Spell Syphon', 'Any small morsel of magic is a feast for the mind, for Tzeentch leeches power from nearby spells to gift upon his Sorcerers.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (368, 'd1000000-0000-0000-0000-000000000170', 'wh3_dlc24_lord_abilities_celestial_sweep', 'Celestial Sweep', 'Such a sweeping maelstrom of energy can cut through a crowd of bodies, leaving blood and devastation in its wake.', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (369, 'd1000000-0000-0000-0000-000000000171', 'wh3_dlc24_lord_abilities_formless_horror', 'Formless Horror', 'Features shift and morph, skin and cloth ripples, until the facsimile form is flawless.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (370, 'd1000000-0000-0000-0000-000000000172', 'wh3_dlc24_lord_abilities_formless_horror_quest_battle', 'Formless Horror', 'Features shift and morph, skin and cloth ripples, until the facsimile form is flawless.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (371, 'd1000000-0000-0000-0000-000000000173', 'wh3_dlc24_lord_abilities_formless_horror_quest_battle_changeling_form', 'Formless Horror', 'The disguise is discarded, the ethereal mists recede, and only the Trickster remains.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (372, 'd1000000-0000-0000-0000-000000000174', 'wh3_dlc24_lord_abilities_gulyas', 'Gulyas', 'Never doubt the healing power of a tasty mushroom goulash; the fungal spores alone work wonders for the soul.', 'wh_type_area_of_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (373, 'd1000000-0000-0000-0000-000000000175', 'wh3_dlc24_lord_abilities_jade_dragon_dragon_form', 'Transformation of the Dragon', 'Yuan Bo has the innate power to transmogrify from human form to Dragon and back again at will, and often at the most opportune moments.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (374, 'd1000000-0000-0000-0000-000000000176', 'wh3_dlc24_lord_abilities_jade_dragon_human_form', 'Transformation of the Dragon', 'Yuan Bo has the innate power to transmogrify from human form to Dragon and back again at will, and often at the most opportune moments.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (375, 'd1000000-0000-0000-0000-000000000177', 'wh3_dlc24_lord_abilities_lord_of_grand_cathay', 'Lord of Grand Cathay', 'When their noble Lord speaks, the men of Cathay listen, burning every inspiring word into their hearts to carry it with them into battle.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (376, 'd1000000-0000-0000-0000-000000000178', 'wh3_dlc24_lord_abilities_spirit_bear', 'Spirit Bear', 'When one looks to the sky, the last thing they expect to see is a descending flurry of teeth, claws and ethereal ursine might.', 'wh_type_magic_missile', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (377, 'd1000000-0000-0000-0000-000000000179', 'wh3_dlc24_lord_abilities_taals_judgement', 'Taal''s Judgement', 'When the God of Nature makes a ruling, the whole of the natural world stands behind him. All verdicts are final.', 'wh_type_magic_missiles', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (378, 'd1000000-0000-0000-0000-00000000017a', 'wh3_dlc24_lord_abilities_the_emperors_executioner', 'The Emperor''s Executioner', 'The Jade Dragon bears a heavy duty, cutting down the Emperor''s enemies without mercy, in a single strike of his blade.', 'wh_type_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (379, 'd1000000-0000-0000-0000-00000000017b', 'wh3_dlc24_lord_passive_cowled_and_cloaked', 'Cowled & Cloaked', 'None, save perhaps Tzeentch himself, know the Changeling’s true form, for his figure is indiscernible and indistinguishable to the naked eye.', 'wh_type_hiding', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (380, 'd1000000-0000-0000-0000-00000000017c', 'wh3_dlc24_lord_passive_cursed_frontier', 'Cursed Frontier', 'Don''t go into the woods today. No, seriously, don''t.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (381, 'd1000000-0000-0000-0000-00000000017d', 'wh3_dlc24_lord_passive_kislev_unite', 'Kislev Unite!', '"For the sake of the Motherland, the Tzarina and for Ursun himself, we must face down this scourge that threatens our very being."', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (382, 'd1000000-0000-0000-0000-00000000017e', 'wh3_dlc24_lord_passive_tzarinas_guardian', 'Tzarina''s Guardian', 'For her life, she will give her own ten thousand times over.', 'wh_type_area_of_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (383, 'd1000000-0000-0000-0000-00000000017f', 'wh3_dlc24_mount_passive_wounded_pride', 'Wounded Pride', 'Down but not out… and never more dangerous. You''d be right to fear the wounded lion…', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (384, 'd1000000-0000-0000-0000-000000000180', 'wh3_dlc24_passive_shield_of_thorns', 'Wreathed in Thorns', 'From every gap in the armour, bristling thorns burst forth to skewer unwary opponents.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (385, 'd1000000-0000-0000-0000-000000000181', 'wh3_dlc24_unit_abilities_bastion_of_the_great_cities', 'Bastion of the Great Cities', 'A steady beat symbolises the staunch defences of the Bastion, a bulwark through which no enemy shall break.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (386, 'd1000000-0000-0000-0000-000000000182', 'wh3_dlc24_unit_abilities_disdain_of_the_dragon_emperor', 'Disdain of the Dragon Emperor', 'Urged on by the pounding of drums, the Cathayan warriors fight untouched by fear, unleashing the fury of the Dragon on their foes.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (387, 'd1000000-0000-0000-0000-000000000183', 'wh3_dlc24_unit_abilities_fearsome_roar', 'Fearsome Roar', 'This one''s bark is at least as bad as their bite…', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (388, 'd1000000-0000-0000-0000-000000000184', 'wh3_dlc24_unit_abilities_fury_of_the_falling_blade', 'Fury of the Falling Blade', 'As the rising tempo reaches a crescendo, every man gives way to the rage of war, carrying their fury into every charge.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (389, 'd1000000-0000-0000-0000-000000000185', 'wh3_dlc24_unit_abilities_howl_of_the_great_beast', 'Howl of the Great Beast', 'The piercing howl of the Incarnate Elemental of Beasts freezes the blood and fills all who hear it with mortal fear.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (390, 'd1000000-0000-0000-0000-000000000186', 'wh3_dlc24_unit_abilities_jade_dragons_breath', 'Jade Lion''s Breath', 'Before the enemy has seen the Lion in a single glance, its jade breath has burnt them to cinders.', 'wh_type_breath', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (391, 'd1000000-0000-0000-0000-000000000187', 'wh3_dlc24_unit_abilities_lampreys_bite', 'Lamprey''s Bite', 'The force of such a clash of fangs echoes out across the battlefield, forcing whole waves of men to their knees.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (392, 'd1000000-0000-0000-0000-000000000188', 'wh3_dlc24_unit_abilities_maelstrom_of_change', 'Maelstrom of Change', 'Those who cannot find shelter from this raging tempest of arcane power are sure to wither and break beneath its every wave.', 'wh_type_chain_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (393, 'd1000000-0000-0000-0000-000000000189', 'wh3_dlc24_unit_abilities_mark_of_yin', 'Mark of Yin', 'Woe to the man or beast bearing this cursed mark, for the Lore of Yin has found an unwilling target and doom trails their every step.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (394, 'd1000000-0000-0000-0000-00000000018a', 'wh3_dlc24_unit_abilities_moon_flare', 'Moon Flare', 'Don''t get anywhere near this silvery-blue flame as it gushes forth. Best not even look at it, in fact. Certainly do not touch it if you value your continued existence.', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (395, 'd1000000-0000-0000-0000-00000000018b', 'wh3_dlc24_unit_abilities_nan_gau_grenades', 'Nan-Gau Grenades', 'Who would have thought such a small, unassuming object could cause such overwhelming damage?', 'wh_type_bombardment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (396, 'd1000000-0000-0000-0000-00000000018c', 'wh3_dlc24_unit_abilities_pack_trap', 'Pack Trap', 'Every woven strand of net bears a powerful hex, draining every ounce of pace from the prey caught in its binds.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (397, 'd1000000-0000-0000-0000-00000000018d', 'wh3_dlc24_unit_abilities_witchbrew', 'Witchbrew', 'Distilled from the blood of Hag Queens, this evil brew drives imbibers into an ecstasy of destruction.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (398, 'd1000000-0000-0000-0000-00000000018e', 'wh3_dlc24_unit_bound_missile_mirror', 'Missile Mirror', 'A magical of shifting darkness and howling wind snatches the enemy’s missiles from the air, even as they are fired, and hurls them back at their owners.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (399, 'd1000000-0000-0000-0000-00000000018f', 'wh3_dlc24_unit_passive_arcane_charge', 'Arcane Charge', 'Attuned to the Winds of Magic, those with this ability can sniff out every spell, seeking to ravage its unfortunate caster.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (400, 'd1000000-0000-0000-0000-000000000190', 'wh3_dlc24_unit_passive_construct_instability', 'Crumbling', 'Constructs are inanimate objects given form and purpose through magical means. When that magic wavers and ebbs, as it inevitably will, it''s immensely difficult to keep one ''alive'' and in one piece.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (401, 'd1000000-0000-0000-0000-000000000191', 'wh3_dlc24_unit_passive_construct_instability_ii', 'Disintegrating', 'Now that the sorcery that holds this Construct together has failed, the Winds of Magic flow out of it, leaving naught but an empty, static husk behind.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (402, 'd1000000-0000-0000-0000-000000000192', 'wh3_dlc24_unit_passive_elemental_instability', 'Elemental Instability', 'The Winds of Magic ebb and flow with the tide of battle. The more heavily-beset an Elemental is, the more likely the sorcery that binds them will fade away.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (403, 'd1000000-0000-0000-0000-000000000193', 'wh3_dlc24_unit_passive_elemental_instability_ii', 'Fade Away!', 'Its magic binding failed, the corporeal form of this Elemental gradually fades from this reality.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (404, 'd1000000-0000-0000-0000-000000000194', 'wh3_dlc24_unit_passive_eternal_duty', 'Eternal Duty', 'Heedless of their own casualties, the Temple Guard execute their sacred duty until the enemy is annihilated or they themselves are slain.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (405, 'd1000000-0000-0000-0000-000000000195', 'wh3_dlc24_unit_passive_eyes_of_the_empress', 'Eyes of the Empress', 'A horrifying cluster of ink black eyes stare out across the land, taking in each detail and following every movement.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (406, 'd1000000-0000-0000-0000-000000000196', 'wh3_dlc24_unit_passive_feral_rage_i', 'Feral Rage I', 'The smell and taste of blood intensifies the rage of most wild creatures, reverting them to their feral instincts.', 'wh_type_hex', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (407, 'd1000000-0000-0000-0000-000000000197', 'wh3_dlc24_unit_passive_feral_rage_ii', 'Feral Rage II', 'The smell and taste of blood intensifies the rage of most wild creatures, reverting them to their feral instincts.', 'wh_type_hex', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (408, 'd1000000-0000-0000-0000-000000000198', 'wh3_dlc24_unit_passive_gift_of_mutation', 'Gift of Mutation', 'Tzeentch''s mutations are a boon to be savoured, transforming even the tragically mundane into a mighty force of nature.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (409, 'd1000000-0000-0000-0000-000000000199', 'wh3_dlc24_unit_passive_guardian_shield', 'Guardian Shield', 'Such a shield does not render its bearer untouchable, but as close as one can get to it in the throes of battle.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (410, 'd1000000-0000-0000-0000-00000000019a', 'wh3_dlc24_unit_passive_icon_of_the_great_cities', 'Icon of the Great Cities', 'The warriors of Cathay know their roles well, guided through battle by the rhythmic pounding of their war drums.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (411, 'd1000000-0000-0000-0000-00000000019b', 'wh3_dlc24_unit_passive_incarnate_flock_of_doom', 'Incarnate Flock of Doom', 'A flock of shadows haunts every step, swarming any fool that dares step foot into the dark.', 'wh_type_area_of_direct_damage', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (412, 'd1000000-0000-0000-0000-00000000019c', 'wh3_dlc24_unit_passive_jade_conduit', 'Jade Conduit', 'The greatest of powers are those without limit, drawing from seemingly endless reserves.', 'wh_type_augment_of_the_winds', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (413, 'd1000000-0000-0000-0000-00000000019d', 'wh3_dlc24_unit_passive_petrifying_gaze', 'Petrifying Gaze', 'A single glance is enough to have any heart engulfed in abject terror, leaving mere mortals frozen in fear, unable to escape.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (414, 'd1000000-0000-0000-0000-00000000019e', 'wh3_dlc24_unit_passive_predatory_fighter', 'Predatory Fighter', 'Ferocious predator-warriors are so single-minded in their duties and their heightened senses drive them to pursue their quarry.', 'wh_type_hex', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (415, 'd1000000-0000-0000-0000-00000000019f', 'wh3_dlc24_unit_passive_sacred_duty', 'Sacred Duty', 'The Temple Guard safeguard their charges whilst displaying a single-minded determination - clearly the role for which they were designed.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (416, 'd1000000-0000-0000-0000-0000000001a0', 'wh3_dlc24_unit_passive_solar_engine', 'Solar Engine', 'When activated, the Solar Engine radiates invigorating rays that stir nearby reptilians to energetic new heights of violence.', 'wh_type_area_of_augments', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (417, 'd1000000-0000-0000-0000-0000000001a1', 'wh3_dlc24_unit_passive_sour_discharge', 'Sour Discharge', 'Death is not the end – it is only the beginning of the explosive devastation such a creature can cause.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (418, 'd1000000-0000-0000-0000-0000000001a2', 'wh3_dlc24_unit_passive_spawn_kin_kroxigors', 'Spawn-Kin', 'Skinks tend to swarm around Kroxigor, encouraged by their awesome power. Kroxigor are likewise attracted to masses of Skinks, whose energetic movement and high-pitched sounds fuel their own battle-rage.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (419, 'd1000000-0000-0000-0000-0000000001a3', 'wh3_dlc24_unit_passive_spawn_kin_skinks', 'Spawn-Kin', '{{tr:unit_abilities_tooltip_text_wh3_dlc24_unit_passive_spawn_kin_kroxigors}}', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (420, 'd1000000-0000-0000-0000-0000000001a4', 'wh3_dlc24_unit_passive_tides_of_transformation', 'Tides of Transformation', 'A roaring wave of magical energy explodes in all directions, scrambling the minds of all it does not decimate outright.', 'wh_type_direct_damage', 250, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (421, 'd1000000-0000-0000-0000-0000000001a5', 'wh3_dlc24_unit_passive_unbinding_changeling', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (422, 'd1000000-0000-0000-0000-0000000001a6', 'wh3_dlc25_character_abilities_hurricane_of_death', 'Hurricane of Death', 'Garagrim spins his weapon in a practiced arc, creating a whirlwind of blood, death and destruction.', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (423, 'd1000000-0000-0000-0000-0000000001a7', 'wh3_dlc25_character_abilities_mercurial_shot', 'Mercurial Shot', 'A magical missile hones in on its target, triggering a violent explosion along enemy battle lines.', 'wh_type_magic_missile', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (424, 'd1000000-0000-0000-0000-0000000001a8', 'wh3_dlc25_character_abilities_pigeon_bomb', 'Pigeon Bomb', 'Devastation rains down from above, leaving no room for respite, but all managed from a reasonably safe distance.', 'wh_type_bombardment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (425, 'd1000000-0000-0000-0000-0000000001a9', 'wh3_dlc25_character_abilities_tallymans_blades', 'The Tallyman''s Blades', 'The greatest of Plaguebearers are chosen by the Tallyman and summoned to the battlefield to assist his putrid cause.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (426, 'd1000000-0000-0000-0000-0000000001aa', 'wh3_dlc25_character_abilties_epidemic_outbreak', 'Epidemic Outburst', 'Layers of rotten skin explode in a toxic cloud of decay, forcing the foe to stagger back in agony and disgust.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (427, 'd1000000-0000-0000-0000-0000000001ab', 'wh3_dlc25_character_passive_artillery_master', 'Artillery Master', 'Every piece of machinery has been fine-tuned to perfection, for when the artillery fires, there can be no margin for error.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (428, 'd1000000-0000-0000-0000-0000000001ac', 'wh3_dlc25_character_passive_befouled_charge', 'Befouled Charge', 'The befouled charge of Kayzk can be smelled as soon as it is seen. Only a will stronger than the Gods themselves could withstand the coming doom!', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (429, 'd1000000-0000-0000-0000-0000000001ad', 'wh3_dlc25_character_passive_corrupted_flesh', 'Corrupted Flesh', 'Kayzk''s ravaged flesh is a rotting mockery, little more than a roughly human-shaped bag of putrescence and corruption that feels neither pain nor hurt.', 'wh_type_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (430, 'd1000000-0000-0000-0000-0000000001ae', 'wh3_dlc25_character_passive_master_of_ballistics', 'Master of Ballistics', 'Calculating angles and trajectories is difficult work best left in the hands of an expert.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (431, 'd1000000-0000-0000-0000-0000000001af', 'wh3_dlc25_character_passive_slayer_of_legend', 'Slayer of Legend', 'A Slayer is the personification of death, thriving in battle with every ounce of blood spilled.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (432, 'd1000000-0000-0000-0000-0000000001b0', 'wh3_dlc25_character_passive_tally_of_pestilence', 'Tally of Pestilence', 'A lifetime spent cataloguing the most vile of diseases has left its mark on the Tallyman, for a miasma of rot and pestilence surrounds him wherever he goes.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (433, 'd1000000-0000-0000-0000-0000000001b1', 'wh3_dlc25_character_passive_the_war_mourner', 'The War-Mourner', 'The title of War-Mourner is a grave honour indeed, bestowed upon one with the strength not to be burdened by their duties.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (434, 'd1000000-0000-0000-0000-0000000001b2', 'wh3_dlc25_character_passive_worthy_foe', 'Worthy Foe', 'Inevitably, adversaries come in all shapes, sizes and strengths; if you''re trying to die, it''s desirable to go down fighting a formidable enemy.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (435, 'd1000000-0000-0000-0000-0000000001b3', 'wh3_dlc25_hero_abilities_titan_headsman', 'Titan Headsman', 'When an enemy stands broken and bruised, finishing them off is but a matter of one solid strike.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (436, 'd1000000-0000-0000-0000-0000000001b4', 'wh3_dlc25_hero_passive_fearsome_combatant', 'Fearsome Combatant', 'The warrior cleaves down foes like butter, for every enemy they fell, another flees at the sight of them.', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (437, 'd1000000-0000-0000-0000-0000000001b5', 'wh3_dlc25_lord_abilities_cinderblast_cluster_bomb', 'Cinderblast Cluster Bomb', 'A cluster of small explosions trigger in quick sequence, combining into a fiery blaze of destruction.', 'wh_type_magic_missile', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (438, 'd1000000-0000-0000-0000-0000000001b6', 'wh3_dlc25_lord_abilities_darkwalker', 'Darkwalker', 'It is hard to hit one that walks between worlds, straddling the line between life and death.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (439, 'd1000000-0000-0000-0000-0000000001b7', 'wh3_dlc25_lord_abilities_deranged_munitions', 'Deranged Munitions', 'The experiments might look like madness, but the results unleash devastating firepower.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (440, 'd1000000-0000-0000-0000-0000000001b8', 'wh3_dlc25_lord_abilities_glorious_death', 'Glorious Death', 'When a Daemon Slayer is at work, those around him get a taste of the glory as he courts renown, legend and, well, death on the battlefield.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (441, 'd1000000-0000-0000-0000-0000000001b9', 'wh3_dlc25_lord_abilities_nurgles_favoured_son', 'Nurgle''s Favoured Son', 'Nurgle loves all his children, but those however fated to be his favourites are afforded even more grotesque gifts with which to better carry out His will.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (442, 'd1000000-0000-0000-0000-0000000001ba', 'wh3_dlc25_lord_abilities_rot_or_die', 'Rot or Die!', 'Some people are not sufficiently blessed to be given a choice in the matter.', 'wh_type_chain_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (443, 'd1000000-0000-0000-0000-0000000001bb', 'wh3_dlc25_lord_passive_feast_of_the_maggot_lord', 'Feast of the Maggot Lord', 'Each mortal body is but a vessel from which the Maggot Lord might slight, seeking to corrupt the fragile body of another.', 'wh_type_direct_damage', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (444, 'd1000000-0000-0000-0000-0000000001bc', 'wh3_dlc25_lord_passive_living_darkness', 'Living Darkness', 'As it swirls about you, this ethereal aura dampens even the most potent of magical artefacts.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (445, 'd1000000-0000-0000-0000-0000000001bd', 'wh3_dlc25_lord_passive_rotting_host', 'Rotting Host', 'Exposed flesh, oozing innards, sulfur smells... all wonderful gifts courtesy of the ever-loving Urfather!', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (446, 'd1000000-0000-0000-0000-0000000001be', 'wh3_dlc25_unit_abilities_coruscating_blast', 'Coruscating Blast', 'The Carmine Dragon soaks up the energies of Shyish before breathing it back out again in a torrent of death and flame.', 'wh_type_magic_missiles', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (447, 'd1000000-0000-0000-0000-0000000001bf', 'wh3_dlc25_unit_abilities_full_power', 'Full Power!', '"All power to the engines – time is of the essence!"', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (448, 'd1000000-0000-0000-0000-0000000001c0', 'wh3_dlc25_unit_abilities_gyrocopter_bomb_anti_large', 'Gyrocopter Bomb (Trollhammer)', '{{tr:unit_abilities_tooltip_text_wh_main_unit_abilities_gyrocopter_bomb}}', 'wh_type_bombardment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (449, 'd1000000-0000-0000-0000-0000000001c1', 'wh3_dlc25_unit_abilities_spear_of_grungni', 'Spear of Grungni', 'A vicious spear of steel explodes from the Airship with force, brutally impaling anyone and anything in its path.', 'wh_type_magic_missile', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (450, 'd1000000-0000-0000-0000-0000000001c2', 'wh3_dlc25_unit_abilities_thunderburner', 'Thunderburner', 'With a sudden rush of piping hot steam, the Thunderbarge soars forward at speed, taking the battlefield by storm.', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (451, 'd1000000-0000-0000-0000-0000000001c3', 'wh3_dlc25_unit_abilities_unspeakable_foulness', 'Unspeakable Foulness', 'Being crushed or eaten may be a blessing when the alternative is choking on blood and puss as it slowly fills the lungs!', 'wh_type_magic_missiles', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (452, 'd1000000-0000-0000-0000-0000000001c4', 'wh3_dlc25_unit_abilities_whirlwind_of_death', 'Whirlwind of Death', 'Dual axe-edges carve through foes, lashing out in a spiral of slaughter, and leaving nought but a bloody mess in their wake.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (453, 'd1000000-0000-0000-0000-0000000001c5', 'wh3_dlc25_unit_abilities_whirlwind_of_death_ror', 'Endless Whirlwind of Death', '{{tr:unit_abilities_tooltip_text_wh3_dlc25_unit_abilities_whirlwind_of_death}}', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (454, 'd1000000-0000-0000-0000-0000000001c6', 'wh3_dlc25_unit_passive_abandon_ship', 'Abandon Ship!', 'While the Land Ship''s engines are undoubtedly marvels of technology, they''re also known to be highly combustible…', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (455, 'd1000000-0000-0000-0000-0000000001c7', 'wh3_dlc25_unit_passive_blackpowder_discipline', 'Blackpowder Discipline', 'Distance provides no safety; no matter how far the enemy runs, a sharpshooter''s bullet will always find them.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (456, 'd1000000-0000-0000-0000-0000000001c8', 'wh3_dlc25_unit_passive_corrosive_bile', 'Corrosive Bile', 'Don''t get any on your hands if you wish to keep them!', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (457, 'd1000000-0000-0000-0000-0000000001c9', 'wh3_dlc25_unit_passive_dwarf_rum', 'Dwarf Rum', 'Imagine a rum so harsh and strong that only superior Dawi constitutions can bear it!', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (458, 'd1000000-0000-0000-0000-0000000001ca', 'wh3_dlc25_unit_passive_nurgling_emergence', 'Nurgling Emergence', 'What was muffled, joyful frolicking becomes clearer as the bulges burst from their bloated host to find a new plaything.', 'wh_type_summon_unit', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (459, 'd1000000-0000-0000-0000-0000000001cb', 'wh3_dlc25_unit_passive_rear_guardian', 'Rear-Guardian', 'Even the sturdy structures of artillery weapons are not half so hardy as the men who defend them.', 'wh_type_area_of_ward_save', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (460, 'd1000000-0000-0000-0000-0000000001cc', 'wh3_dlc25_unit_passive_tears_of_nurgle', 'Tears of Nurgle', 'When the normally-ebullient Nurgle cries, it is for His many children across this reality and all others.', 'wh_type_chain_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (461, 'd1000000-0000-0000-0000-0000000001cd', 'wh3_dlc25_unit_passive_the_blessing_of_the_father', 'The Blessings of the Fly Lord', 'Nurgle be praised! A revolting pus flower is a token of the Plague Lord''s esteem; a gift of grandfatherly love, you might say, that his children might spread decay.', 'wh_type_ward_save', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (462, 'd1000000-0000-0000-0000-0000000001ce', 'wh3_dlc25_unit_passive_unbinding_gyrocopters', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (463, 'd1000000-0000-0000-0000-0000000001cf', 'wh3_dlc25_unit_passive_unbinding_spirit_of_grungni', 'Disengage!', 'After providing close air support, the Spirit of Grungni leaves the battlefield to resupply, ready for when it is requested once again.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (464, 'd1000000-0000-0000-0000-0000000001d0', 'wh3_dlc25_unit_passive_wards_of_grimnir', 'Wards of Grimnir', '"Shrug off the petty blows of weaklings! Relish in mighty Grimnir''s holy protection!"', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (465, 'd1000000-0000-0000-0000-0000000001d1', 'wh3_dlc26_character_abilities_bloody_onslaught', 'Bloody Onslaught', 'Skulltaker''s single-minded murder-spree drives him towards the heart of every army: its leader.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (466, 'd1000000-0000-0000-0000-0000000001d2', 'wh3_dlc26_character_abilities_cash_cascade', 'Cash Cascade', '"Right, there''s a bonus in it for tha one that does the most creative killin''…"', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (467, 'd1000000-0000-0000-0000-0000000001d3', 'wh3_dlc26_character_abilities_crimson_juggernaut', 'Crimson Juggernaut', '"Nothing hits harder than a cannonball, I tell you!" –– Imperial artillery crewman, part of a military company lost on the northern borders', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (468, 'd1000000-0000-0000-0000-0000000001d4', 'wh3_dlc26_character_abilities_da_boss_as_a_plan', 'Da Boss ''as a Plan!', 'Although Gorbad''s soldiers occasionally wonder what kind of weapon this "Plan" of his is and when he''s going to use it, knowing he has it bolsters their spirits nonetheless.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (469, 'd1000000-0000-0000-0000-0000000001d5', 'wh3_dlc26_character_abilities_dead_eye', 'Dead Eye', 'By simply standing still and waiting, pistol in hand, Golgfag has stolen countless kills from other Ogres with their bellies mid-stampede.', 'wh_type_magic_missile', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (470, 'd1000000-0000-0000-0000-0000000001d6', 'wh3_dlc26_character_abilities_empowering_shrooms', 'Empowering Shrooms', 'The fact that Squigs and gobbos love them should serve as a warning to the more inherently sensible races.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (471, 'd1000000-0000-0000-0000-0000000001d7', 'wh3_dlc26_character_abilities_headhunt', 'Headhunt', 'Promising a bonus for each and every skull detached, whether or not its owner objects, has proved to be something of a motivator among Ogre mercenaries.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (472, 'd1000000-0000-0000-0000-0000000001d8', 'wh3_dlc26_character_abilities_inevitable_horror', 'Inevitable Horror', 'Skarr''s approach grants a horrible realisation. Doom is upon you. There is no escape. Only the inevitable end.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (473, 'd1000000-0000-0000-0000-0000000001d9', 'wh3_dlc26_character_abilities_inventory_of_hatchlings', 'Inventory of Hatchlings', 'Snagla''s imaginative profusion and prodigious memory when it comes to Spider Hatchling names is the closest he comes to having magical talent.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (474, 'd1000000-0000-0000-0000-0000000001da', 'wh3_dlc26_character_abilities_kill_for_khorne', 'Kill for Khorne!', '"For Khorne, my dear microcephalic abomination? Oh, well then, verily, you must kill!" – The last words of a nameless, intestineless Arabyan Plenipotentiary', 'wh_type_explosion', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (475, 'd1000000-0000-0000-0000-0000000001db', 'wh3_dlc26_character_abilities_mumbo_jumbo_chant', 'Mumbo-Jumbo Chant', 'The words of this magical chant are different each time, though identically meaningless. It''s the conviction that matters, as well as the manic eye-rolling.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (476, 'd1000000-0000-0000-0000-0000000001dc', 'wh3_dlc26_character_abilities_orcs_are_da_best', 'Orcs are da Best!', '"...and if sumbody sez else, smash ''em to prove dat!"', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (477, 'd1000000-0000-0000-0000-0000000001dd', 'wh3_dlc26_character_abilities_puncture', 'Puncture', 'For all that he is as ungainly a brute as they come, the Bruiser manoeuvres his wrist blades with the precision of a painter''s brush.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (478, 'd1000000-0000-0000-0000-0000000001de', 'wh3_dlc26_character_abilities_spider_web_attack', 'Spiderweb Attack', 'Nothing of a true Spider''s slow and patient trapping technique, and all of Snagla''s flair for... well, everything that the aforementioned is not!', 'wh_type_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (479, 'd1000000-0000-0000-0000-0000000001df', 'wh3_dlc26_character_abilities_squig_thinkin', 'Squig Thinkin''', 'A Squig''s tactical acumen extends to hearing and following the loudest belly growl around, a nod towards a dangerous and rudimentary sentience often exploited by Night Goblins.', 'wh_type_summon_unit', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (480, 'd1000000-0000-0000-0000-0000000001e0', 'wh3_dlc26_character_abilities_were_you_goin', 'Where You Goin!?', 'If anyone even thinks of fleeing a battle in the Bruiser''s presence, they find themselves flung head over heels in the thick of it.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (481, 'd1000000-0000-0000-0000-0000000001e1', 'wh3_dlc26_character_passive_belly_stance', 'Belly Stance', '"If I don'' move, they don'' move. Simple as that."', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (482, 'd1000000-0000-0000-0000-0000000001e2', 'wh3_dlc26_character_passive_blood_thirst', 'The Blood Tally', 'Blood brings life to Skarr just as water breathes life into a shark. Churn more blood, and so he lives, by the will of Khorne.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (483, 'd1000000-0000-0000-0000-0000000001e3', 'wh3_dlc26_character_passive_bloodborn', 'Bloodborn', 'Pushing Skarr to the brink of defeat fills some of his enemies with glee – those who do not know any better.', 'wh_type_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (484, 'd1000000-0000-0000-0000-0000000001e4', 'wh3_dlc26_character_passive_da_great_leader', '{{tr:character_skills_localised_name_wh3_dlc26_skill_innate_grn_gorbad}}', '{{tr:character_skills_localised_description_wh3_dlc26_skill_innate_grn_gorbad}}', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (485, 'd1000000-0000-0000-0000-0000000001e5', 'wh3_dlc26_character_passive_dreaded_aura', 'Dreaded Aura', 'Where Bragg walks, he walks alone, donning his dark leather hood in the manner of a human hangman to capitalise on his grim persona.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (486, 'd1000000-0000-0000-0000-0000000001e6', 'wh3_dlc26_character_passive_forboding_executioner', 'Foreboding Executioner', 'Once marked for death, one must prepare for Bragg''s lumbering shadow looming into view. What no one can prepare for is the Gutgouger''s lunge towards their neck...', 'wh_type_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (487, 'd1000000-0000-0000-0000-0000000001e7', 'wh3_dlc26_character_passive_gold_glorious_gold', 'Gold, Glorious Gold!', 'Setting their constant, slavering hunger aside, there''s nothing that matters to Ogre mercenaries more than gold. The sight of a brimming war-chest reminds them what they''re fighting for when it matters most.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (488, 'd1000000-0000-0000-0000-0000000001e8', 'wh3_dlc26_character_passive_skaramors_butchers', 'Skaramor''s Butchers', 'Murder your own brothers in war and receive Khorne’s favour: tried and tested. From then on, however, murder them only a little: the foe takes precedence.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (489, 'd1000000-0000-0000-0000-0000000001e9', 'wh3_dlc26_character_passive_warpaint', 'Savage Charms', 'Haphazard, though weirdly pleasing to the eye, everyone knows nothing hardens the Greenskins'' resolve better than pleasing their aesthetic sensibilities.', 'wh_type_area_of_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (490, 'd1000000-0000-0000-0000-0000000001ea', 'wh3_dlc26_lord_abilities_blood_sacrifice', 'Blood Sacrifice', '"Blood, I can spare. Your foes, you cannot."', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (491, 'd1000000-0000-0000-0000-0000000001eb', 'wh3_dlc26_lord_abilities_eye_of_khorne', 'Eye of Khorne', 'Should Arbaal''s resolve shatter, an eternity as a Chaos Spawn awaits him. A similar fate also awaits anyone in his vicinity, for a short and painful while.', 'wh_type_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (492, 'd1000000-0000-0000-0000-0000000001ec', 'wh3_dlc26_lord_abilities_gaze_of_khorne', 'Fury of the Blood God', 'Khorne''s gaze falls on all war, at all times, but only Arbaal''s feats are capable of riveting His attention. Where it falls, infernos rise.', 'wh_type_explosion', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (493, 'd1000000-0000-0000-0000-0000000001ed', 'wh3_dlc26_lord_abilities_murderous_exhortations', 'Murderous Exhortations', 'Just a small taste of what awaits the aspirants in the Brazen Cage can undo the minds and bodies of anyone else.', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (494, 'd1000000-0000-0000-0000-0000000001ee', 'wh3_dlc26_lord_abilities_pilgrimage_of_skulls', 'Pilgrimage of Skulls', 'Never forget the path I have set you upon! If anything stands across it, bleed it, burn it, break it!"', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (495, 'd1000000-0000-0000-0000-0000000001ef', 'wh3_dlc26_lord_abilities_wild_abandon', 'Wild Abandon', 'The Bloodspeaker asks the impossible of his followers, and they do it. Many die afterwards. But before that, they kill.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (496, 'd1000000-0000-0000-0000-0000000001f0', 'wh3_dlc26_lord_passive_been_there_done_that', 'Been There, Done That', 'Been there, done that, got the breastplate. And the scars.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (497, 'd1000000-0000-0000-0000-0000000001f1', 'wh3_dlc26_lord_passive_gruesome_display', 'Gruesome Display', 'It could be any head. It could, indeed, be every head. This is why its eyes open such a wide vista of horrors to anyone who sees it.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (498, 'd1000000-0000-0000-0000-0000000001f2', 'wh3_dlc26_lord_passive_thirst_for_challenge', 'Thirst for Challenge', 'Considering Arbaal without an army at his back may offer consolation, in the abstract. For thousands of years the devastating reality has amply refuted this.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (499, 'd1000000-0000-0000-0000-0000000001f3', 'wh3_dlc26_unit_abilities_acid_vomit', 'Acid Burps', 'A copious natural by-product of this noisome Colossal Squig''s healthy digestion. Just don''t step in it.', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (500, 'd1000000-0000-0000-0000-0000000001f4', 'wh3_dlc26_unit_abilities_blow_apart', 'Blow Apart', 'If it stays digested, anything this Colossal Squig eats is generally no longer considered a threat. Once it dies, all such considerations fall to the wayside.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (501, 'd1000000-0000-0000-0000-0000000001f5', 'wh3_dlc26_unit_abilities_force_of_total_destruction', 'Force of Total Destruction', 'Even simple destruction can be harnessed by a greater will. With Mangler Squigs, the metaphor is lost but the harnessing remains, in a terrifyingly literal sense.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (502, 'd1000000-0000-0000-0000-0000000001f6', 'wh3_dlc26_unit_abilities_immovable_bulwark', 'Immovable Bulwark', '"Nuffin'' ain''t gettin'' past us."', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (503, 'd1000000-0000-0000-0000-0000000001f7', 'wh3_dlc26_unit_abilities_maneater_smoke_bomb', 'Maneater Smoke Bomb', '"Get ''em flailin'' an'' confused. Makes fightin'' more fun. Get ''em smoked. Makes ''em taste better."', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (504, 'd1000000-0000-0000-0000-0000000001f8', 'wh3_dlc26_unit_abilities_marked_for_eatin', 'Marked for Eatin''', 'Picky eaters are frowned upon amongst the Ogres. Picky fighters, however, are some of the deadliest amongst them.', 'wh_type_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (505, 'd1000000-0000-0000-0000-0000000001f9', 'wh3_dlc26_unit_abilities_unstoppable_choppas', 'Unstoppable Choppas', 'When Orcs are determined to cleave something in half, very few things can stop them from doing so.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (506, 'd1000000-0000-0000-0000-0000000001fa', 'wh3_dlc26_unit_passive_aura_of_frost', 'Aura of Frost', 'The walking embodiment of Winter itself, Yhetees channel the dark season''s freezing weather to maim and kill their enemies.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (507, 'd1000000-0000-0000-0000-0000000001fb', 'wh3_dlc26_unit_passive_bloodstorm', 'Bloodstorm', 'A Wrathmonger''s otherworldly storm takes on a decidedly worldly character in battle – bits of bone and gobs of flesh… and blood. So much blood.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (508, 'd1000000-0000-0000-0000-0000000001fc', 'wh3_dlc26_unit_passive_carrion_frenzy', 'Carrion Frenzy', 'The absolute carnage around Ogre mercenaries provides rich pickings for carrion-eaters, who do their bit for the war effort by taking more than their fill before battle is even done.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (509, 'd1000000-0000-0000-0000-0000000001fd', 'wh3_dlc26_unit_passive_fury_of_the_skullthrone', 'Fury of the Skull Throne', 'As if a raging Khorngor needs any reminders on, well, rage… though the dull fear of defeat and Khorne''s displeasure provides a useful prod.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (510, 'd1000000-0000-0000-0000-0000000001fe', 'wh3_dlc26_unit_passive_grey_supremacy', 'Grey Supremacy', 'Running away from fear is what keeps you alive. Running towards fear is what makes you strong. The greatest Yhetees bring this wisdom with them down from the mountains.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (511, 'd1000000-0000-0000-0000-0000000001ff', 'wh3_dlc26_unit_passive_hellraiser', 'Hellraiser', 'That which is forged in Khorne’s own crucible moves with otherworldly speed to serve the cause of murder.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (512, 'd1000000-0000-0000-0000-000000000200', 'wh3_dlc26_unit_passive_piggy_back_joust', 'Piggyback Joust!', 'These Gnoblars love to joust each other when away from the battlefield, but will more-than happily practice on live foes to hone their, er, chops.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (513, 'd1000000-0000-0000-0000-000000000201', 'wh3_dlc26_unit_passive_runes_of_binding', 'Runes of Binding', 'The fate of a Slaughterbrute is bound to its master. If its master lives, it kills at his behest. If not, it simply kills.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (514, 'd1000000-0000-0000-0000-000000000202', 'wh3_dlc26_unit_passive_uncanny_coordination', 'Uncanny Coordination', 'Maybe it''s herd mentality, but in greater numbers, Gnoblars are a far more unified fighting force.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (515, 'd1000000-0000-0000-0000-000000000203', 'wh3_dlc27_character_abilities_captain_of_the_phoenix_guard', 'Captain of the Phoenix Guard', 'Being closest to the thoughts of the Creator God marks Caradryan with the divine strength to lead Asuryan''s guardians.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (516, 'd1000000-0000-0000-0000-000000000204', 'wh3_dlc27_character_abilities_iron_hand_captain', 'Iron-Handed Captain', 'A leader who can instil a fear of failure can also bring out the greatest feats of valour.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (517, 'd1000000-0000-0000-0000-000000000205', 'wh3_dlc27_character_abilities_master_of_mists_custom', '{{tr:unit_abilities_onscreen_name_wh3_dlc27_character_abilities_master_of_mists}}', 'In one moment, the still morning fog; in the next, Asur regiments charging forth, clouds of whistling death falling ahead of them.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (518, 'd1000000-0000-0000-0000-000000000206', 'wh3_dlc27_character_abilities_murderous_mastery', '{{tr:unit_abilities_onscreen_name_wh2_main_faction_abilities_murderous_mastery}}', '{{tr:unit_abilities_tooltip_text_wh2_main_faction_abilities_murderous_mastery}}', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (519, 'd1000000-0000-0000-0000-000000000207', 'wh3_dlc27_character_abilities_nightmaw', 'Nightmaw', 'Betrayed, torn to pieces, and fused together as one, what was once Sayl’s fellow seer-apprentices is now something monstrous that awaits beckoning from the shadows…', 'wh_type_wind', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (520, 'd1000000-0000-0000-0000-000000000208', 'wh3_dlc27_character_abilities_slezuzus_voice', 'Daemonic Whispers', 'A Daemonic presence seems to influence Styrkaar and those around him, bending their will to give him thanks and praise even as he disembowels them.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (521, 'd1000000-0000-0000-0000-000000000209', 'wh3_dlc27_character_abilities_the_black_tongue', 'The Black Tongue', 'This Slaaneshi Lord’s noxious combination of herbs magically sublimates a pungent and debilitating aroma that quite literally strangles the tongue.', 'wh_type_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (522, 'd1000000-0000-0000-0000-00000000020a', 'wh3_dlc27_character_passive_backstabbing_sorcery', '{{tr:character_skills_localised_name_wh3_dlc27_skill_nor_sayl_unique_1}}', '{{tr:character_skills_localised_description_wh3_dlc27_skill_nor_sayl_unique_1}}', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (523, 'd1000000-0000-0000-0000-00000000020b', 'wh3_dlc27_character_passive_glorious_slaughter', 'Glorious Slaughter', '"When the flock breaks and the lambs scatter… that is when slaughter truly becomes a delight."', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (524, 'd1000000-0000-0000-0000-00000000020c', 'wh3_dlc27_character_passive_infernal_puppet', 'Infernal Puppet', 'Coaxed into combat by a Lord of Slaanesh, there is no telling what you might witness. Yet one thing is certain: you shall be at your wits’ end.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (525, 'd1000000-0000-0000-0000-00000000020d', 'wh3_dlc27_character_passive_mark_of_asuryan', 'Mark of Asuryan', 'The rune of the Creator upon Caradryan''s brow glows brightest in times of danger, scorching any foe who comes near.', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (526, 'd1000000-0000-0000-0000-00000000020e', 'wh3_dlc27_character_passive_thrill_of_battle', '{{tr:character_skills_localised_name_wh3_dlc27_skill_nor_beorg_bearstruck_unique_1}}', '{{tr:character_skills_localised_description_wh3_dlc27_skill_nor_beorg_bearstruck_unique_1}}', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (527, 'd1000000-0000-0000-0000-00000000020f', 'wh3_dlc27_character_passive_war_cry', '{{tr:character_skills_localised_name_wh3_dlc27_skill_nor_beorg_bearstruck_unique_4}}', '{{tr:character_skills_localised_description_wh3_dlc27_skill_nor_beorg_bearstruck_unique_4}}', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (528, 'd1000000-0000-0000-0000-000000000210', 'wh3_dlc27_hero_abilities_favoured_by_the_matriarch', '{{tr:character_skills_localised_name_wh3_dlc27_skill_nor_fimir_noble_unique_1}}', '{{tr:character_skills_localised_description_wh3_dlc27_skill_nor_fimir_noble_unique_1}}', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (529, 'd1000000-0000-0000-0000-000000000211', 'wh3_dlc27_hero_passive_disarm', 'Disarm', 'Standing in the presence of near-perfection can be intoxicating, and in the case of Slaanesh’s alluring champions, quite often fatal.', 'wh_type_area_of_hexes', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (530, 'd1000000-0000-0000-0000-000000000212', 'wh3_dlc27_hero_passive_shrouding_mists', 'Shrouding Mists', 'The obscuring fog that shrouds the Fimir’s boggy fortresses follows them onto the battlefield, shielding them from more than just prying eyes and the harsh sun.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (531, 'd1000000-0000-0000-0000-000000000213', 'wh3_dlc27_lord_abilities_chanson_of_caging', '{{tr:character_skills_localised_name_wh3_dlc27_skill_sla_masque_unique_1}}', '{{tr:character_skills_localised_description_wh3_dlc27_skill_sla_masque_unique_1}}', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (532, 'd1000000-0000-0000-0000-000000000214', 'wh3_dlc27_lord_abilities_daggerdance', '{{tr:character_skills_localised_name_wh3_dlc27_skill_sla_dechala_unique_3}}', '{{tr:character_skills_localised_description_wh3_dlc27_skill_sla_dechala_unique_3}}', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (533, 'd1000000-0000-0000-0000-000000000215', 'wh3_dlc27_lord_abilities_dance_of_destruction', 'Dance of Destruction', 'Battle provides the stage to please one’s master, where sensuous movements and the eerie whistling of whirling blades entrances followers into heedless destruction.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (534, 'd1000000-0000-0000-0000-000000000216', 'wh3_dlc27_lord_abilities_offering_to_the_gods', '{{tr:character_skills_localised_name_wh3_dlc27_skill_nor_great_shaman_sorcerer_unique_5}}', '{{tr:character_skills_localised_description_wh3_dlc27_skill_nor_great_shaman_sorcerer_unique_5}}', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (535, 'd1000000-0000-0000-0000-000000000217', 'wh3_dlc27_lord_abilities_quicksilver_strike', '{{tr:character_skills_localised_name_wh3_dlc27_skill_hef_sea_helm_quicksilver_strike}}', '{{tr:character_skills_localised_description_wh3_dlc27_skill_hef_sea_helm_quicksilver_strike}}', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (536, 'd1000000-0000-0000-0000-000000000218', 'wh3_dlc27_lord_abilities_the_dance_of_dreaming', 'The Dance of Dreaming', 'The foe''s purpose is no longer victory or survival, but measuring up to the impossibly exacting standards of the dance that the battle has turned into.', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (537, 'd1000000-0000-0000-0000-000000000219', 'wh3_dlc27_lord_abilities_the_praise_of_slaanesh', '{{tr:character_skills_localised_name_wh3_dlc27_skill_sla_dechala_unique_1}}', '{{tr:character_skills_localised_description_wh3_dlc27_skill_sla_dechala_unique_1}}', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (538, 'd1000000-0000-0000-0000-00000000021a', 'wh3_dlc27_lord_abilities_the_waltz_of_lethargy', '{{tr:character_skills_localised_name_wh3_dlc27_skill_sla_masque_unique_6}}', '{{tr:character_skills_localised_description_wh3_dlc27_skill_sla_masque_unique_6}}', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (539, 'd1000000-0000-0000-0000-00000000021b', 'wh3_dlc27_lord_abilities_whirlwind_of_pleasure', '{{tr:character_skills_localised_name_wh3_dlc27_skill_sla_dechala_unique_5}}', '{{tr:character_skills_localised_description_wh3_dlc27_skill_sla_dechala_unique_5}}', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (540, 'd1000000-0000-0000-0000-00000000021c', 'wh3_dlc27_lord_passive_naval_discipline', 'Naval Discipline', 'By the call of its mighty Sea Lords, the Asur fleet demonstrates why it is renowned as the greatest naval power in the world, its training superior to all others.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (541, 'd1000000-0000-0000-0000-00000000021d', 'wh3_dlc27_qb_unit_abilities_ascendants_hubris', 'Ascendant''s Hubris', 'To kill the Ascendant is to kill his pride. But while he lives, it is far greater than others of his kin.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (542, 'd1000000-0000-0000-0000-00000000021e', 'wh3_dlc27_qb_unit_abilities_bitter_sting', 'Bitter Sting', 'The surest mark of enduring malice is prolonging one''s depredations on the weak and weary.', 'wh_type_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (543, 'd1000000-0000-0000-0000-00000000021f', 'wh3_dlc27_qb_unit_abilities_bloodsport', 'Bloodsport', 'The growing piles of the dead will serve as a source of satisfaction for the twisted, rudimentary self-awareness in the depths of this Preyton''s mind.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (544, 'd1000000-0000-0000-0000-000000000220', 'wh3_dlc27_qb_unit_abilities_brutality', 'Brutality', 'This Ghorgon''s body, if damaged enough, can be induced to feed upon itself. Unfortunately, this only fuels its ferocious hunger.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (545, 'd1000000-0000-0000-0000-000000000221', 'wh3_dlc27_qb_unit_abilities_copious_phlegm', 'Copious Phlegm', 'The sound is indescribable. The smell is indescribable. The effects are indescribable. Everything is indescribable.', 'wh_type_explosion', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (546, 'd1000000-0000-0000-0000-000000000222', 'wh3_dlc27_qb_unit_abilities_corrosive_coating', 'Corrosive Coating', 'The slime fends off the mundane. The source of the creature''s "blessings" fends off anything else that comes into contact with it.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (547, 'd1000000-0000-0000-0000-000000000223', 'wh3_dlc27_qb_unit_abilities_dissolving_bone', 'Dissolving Bone', 'This Carrion Eater''s acidic froth is a sign of its ravening appetite and a means to satisfy it, dissolving both flesh and bone of its smaller Carrion prey.', 'wh_type_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (548, 'd1000000-0000-0000-0000-000000000224', 'wh3_dlc27_qb_unit_abilities_frenzied_challenge', 'Frenzied Challenge', 'Faced with this creature''s challenge, one either fights or flees. Yet who would flee and doom themselves to nightmares of becoming its meal? Fight it is.', 'wh_type_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (549, 'd1000000-0000-0000-0000-000000000225', 'wh3_dlc27_qb_unit_abilities_guttural_roar', 'Guttural Roar', 'This is not a warning for evildoers to go. It is a promise of what is to come.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (550, 'd1000000-0000-0000-0000-000000000226', 'wh3_dlc27_qb_unit_abilities_insanity', 'Insanity', 'Does insanity lie in the creature''s blistering psychic emanations, or in its enemy''s decision to stay in their proximity despite everything...?', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (551, 'd1000000-0000-0000-0000-000000000227', 'wh3_dlc27_qb_unit_abilities_insatiable_hunger', 'Insatiable Hunger', 'The Carrion Eater''s hunger breaks down any form resistance, beginning with the victim''s means of protection and ending with the final hopeless flutters of its body.', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (552, 'd1000000-0000-0000-0000-000000000228', 'wh3_dlc27_qb_unit_abilities_petrifying_aura', 'Petrifying Aura', 'In a depraved twist of its master''s will, those who return this creature''s baleful gaze retain torturous mobility… for a while.', 'wh_type_area_of_hexes', 300, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (553, 'd1000000-0000-0000-0000-000000000229', 'wh3_dlc27_qb_unit_abilities_razor_sharp_teeth', 'Diligent Chewing', 'It is extremely unlikely for the Runt to choke on anything that enters his maw. Yet something has taught him to be thorough nevertheless.', 'wh_type_augment', 250, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (554, 'd1000000-0000-0000-0000-00000000022a', 'wh3_dlc27_qb_unit_abilities_revel_in_fear', 'Revel in Fear', 'The Ascendant''s need for sustenance exceeds his fleshly appetite. He feeds on his own superiority, finding it in the eyes of terror-stricken foes.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (555, 'd1000000-0000-0000-0000-00000000022b', 'wh3_dlc27_qb_unit_abilities_runt_of_the_litter', 'Runt of the Litter', 'Not knowing one''s size comes hand in hand with not knowing one''s strength. The Runt needn''t skimp on either when threatened.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (556, 'd1000000-0000-0000-0000-00000000022c', 'wh3_dlc27_qb_unit_abilities_shatter', 'Shatter', 'The sculpted victims of the Cockatrice retain just enough awareness to fully experience their final change.', 'wh_type_direct_damage', 300, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (557, 'd1000000-0000-0000-0000-00000000022d', 'wh3_dlc27_qb_unit_abilities_terrible_malice', 'Terrible Malice', 'The more terrible the pain, the more this creature has fulfilled its purpose – which is terrible pain.', 'wh_type_direct_damage', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (558, 'd1000000-0000-0000-0000-00000000022e', 'wh3_dlc27_qb_unit_abilities_too_stubborn_to_die', 'Too Stubborn to Die', 'Hate, if strong enough, outlives everything. There is no hate greater than that for a singular rival who carries a promise of death.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (559, 'd1000000-0000-0000-0000-00000000022f', 'wh3_dlc27_qb_unit_abilities_undoubtful_pride', 'Overbearing Pride', 'By his nature and long-lived experience, the Wise One is immune to paltry stratagems, standing his ground and wreaking havoc no matter what.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (560, 'd1000000-0000-0000-0000-000000000230', 'wh3_dlc27_qb_unit_abilities_visions_of_madness', 'Visions of Madness', 'Desperate bloodlust is a mark of borderline derangement – yet some creatures care not for the limits of mind.', 'wh_type_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (561, 'd1000000-0000-0000-0000-000000000231', 'wh3_dlc27_qb_unit_passive_living_furnace', 'Living Furnace', 'The monster''s very presence is a crucible. In it, most are reduced to cinders – but some are reforged, their smouldering strength renewed.', 'wh_type_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (562, 'd1000000-0000-0000-0000-000000000232', 'wh3_dlc27_qb_unit_passive_molten_body', 'Molten Body', 'To reach its flesh, those who would quell this living inferno must first fight the fires of Hashut himself.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (563, 'd1000000-0000-0000-0000-000000000233', 'wh3_dlc27_spell_bound_lash_of_slaanesh', 'Lash of Slaanesh', '{{tr:unit_abilities_tooltip_text_wh3_main_spell_bound_lash_of_slaanesh}}', 'wh_type_breath', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (564, 'd1000000-0000-0000-0000-000000000234', 'wh3_dlc27_spell_bound_runecaller_death_doom_and_darkness', 'Doom & Darkness', 'Spirits of the departed assail the Wizard’s foes, sapping their resolve and causing dread among their numbers.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (565, 'd1000000-0000-0000-0000-000000000235', 'wh3_dlc27_spell_bound_runecaller_flock_of_doom', 'Flock of Doom', 'With a mighty bellow, the spellcaster invokes Corvus the Crow Lord, summoning his servants to peck at the foe''s eyes.', 'wh_type_area_of_direct_damage', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (566, 'd1000000-0000-0000-0000-000000000236', 'wh3_dlc27_spell_bound_soul_stealer', '{{tr:unit_abilities_onscreen_name_wh2_dlc10_spell_bound_soul_stealer_ror}}', '{{tr:unit_abilities_tooltip_text_wh2_dlc10_spell_bound_soul_stealer_ror}}', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (567, 'd1000000-0000-0000-0000-000000000237', 'wh3_dlc27_spell_mists_the_writhing_mist_bound', '{{tr:unit_abilities_onscreen_name_wh3_dlc27_spell_mists_the_writhing_mist}}', '{{tr:unit_abilities_tooltip_text_wh3_dlc27_spell_mists_the_writhing_mist}}', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (568, 'd1000000-0000-0000-0000-000000000238', 'wh3_dlc27_unit_abilities_burrow', 'Deep Tunneling', 'A path torn through earth and stone precedes furious devastation bursting forth from below. Running is not a plan.', 'wh_type_explosion', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (569, 'd1000000-0000-0000-0000-000000000239', 'wh3_dlc27_unit_abilities_consuming_hatred', 'All-Consuming Hatred', 'The innate hatred carried within a Preyton makes it despise itself almost as much as its foes, whose attacks are repaid with added enmity.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (570, 'd1000000-0000-0000-0000-00000000023a', 'wh3_dlc27_unit_abilities_dread_maw_surface', 'Surface', 'The terror is in knowing what its maw will do once it finally emerges.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (571, 'd1000000-0000-0000-0000-00000000023b', 'wh3_dlc27_unit_abilities_dread_maw_underground', 'Burrow', 'The dread is in not knowing when it will emerge.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (572, 'd1000000-0000-0000-0000-00000000023c', 'wh3_dlc27_unit_abilities_flaming_breath', 'Flaming Breath', 'Three snapping maws signal the Chimera’s unbridled destructive potential, with one harbouring the possibility of a fiery death.', 'wh_type_magic_missile', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (573, 'd1000000-0000-0000-0000-00000000023d', 'wh3_dlc27_unit_abilities_perfect_predator', 'Perfect Predator', 'An ever-shifting dermis of bright colours and hues turns translucent one moment, before running like molten wax to heal tainted flesh the next.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (574, 'd1000000-0000-0000-0000-00000000023e', 'wh3_dlc27_unit_passive_abyssal_cloak', 'Abyssal Cloak', 'The very sight of a Merwyrm can provoke dread and hopelessness, its aura of crushing darkness even nullifying arrows and other missiles.', 'wh_type_augment', 151, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (575, 'd1000000-0000-0000-0000-00000000023f', 'wh3_dlc27_unit_passive_barrier_boost', 'Barrier Boost', '{{tr:unit_abilities_tooltip_text_wh3_twa10_unit_passive_barrier_boost}}', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (576, 'd1000000-0000-0000-0000-000000000240', 'wh3_dlc27_unit_passive_battle_songs', 'Battle Songs', 'Whether sung in worship, or simply to embolden themselves, these riders’ songs are dreadful to the ear but pleasing to their god and fellow warriors.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (577, 'd1000000-0000-0000-0000-000000000241', 'wh3_dlc27_unit_passive_burrowing_instinct', 'Survival Instinct', 'For some war-prone creatures, the point where survival eclipses bloodlust has absolutely no in-between.', 'wh_type_hex', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (578, 'd1000000-0000-0000-0000-000000000242', 'wh3_dlc27_unit_passive_chilling_aura', 'The Chilling Aura', '{{tr:unit_abilities_tooltip_text_wh_dlc04_unit_passive_chilling_aura}}', 'wh_type_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (579, 'd1000000-0000-0000-0000-000000000243', 'wh3_dlc27_unit_passive_dual_personality_betrayer', 'Dual Personality – Betrayer', 'There is always one head more perverse and hateful than the other, pushing the Curs’d Ettin to move with violent, albeit lumbering zeal!', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (580, 'd1000000-0000-0000-0000-000000000244', 'wh3_dlc27_unit_passive_dual_personality_chaosbrand', '{{tr:unit_abilities_onscreen_name_wh3_dlc27_unit_passive_dual_personality_savage}}', 'Some Curs’d Ettin retain enough intelligence in one head to recall secrets of their old tribal magic, allowing them to convalesce when under grave threat.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (581, 'd1000000-0000-0000-0000-000000000245', 'wh3_dlc27_unit_passive_dual_personality_defiler', '{{tr:unit_abilities_onscreen_name_wh3_dlc27_unit_passive_dual_personality_betrayer}}', 'Some Curs’d Ettin retain enough intelligence in one head to recall secrets of their old tribal magic, affording them the power to nullify even the most potent magical armaments.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (582, 'd1000000-0000-0000-0000-000000000246', 'wh3_dlc27_unit_passive_dual_personality_savage', 'Dual Personality – Savage', 'A gibbering head devolved into a drooling and wailing imbecile signifies a Curs’d Ettin in its most destructive personality. Avoid its club-like arms!', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (583, 'd1000000-0000-0000-0000-000000000247', 'wh3_dlc27_unit_passive_endless_malice', 'Endless Malice', 'Seldom is a battlefield prowled by a Preyton not left strewn with corpses and dead creatures, mauled and trampled beyond any recognition.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (584, 'd1000000-0000-0000-0000-000000000248', 'wh3_dlc27_unit_passive_enfeebling_cold', 'Enfeebling Cold', 'Those who find the foolish resolve to charge the Merwyrm will find their approach hampered by an ocean’s chill that hits them bones-deep.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (585, 'd1000000-0000-0000-0000-000000000249', 'wh3_dlc27_unit_passive_momentum', 'Momentum', 'Rigorous practice over the Straits of Lothern drills the Swiftfeather Rocs in the auspicious wind-paths that husband their strength for devastating onslaught.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (586, 'd1000000-0000-0000-0000-00000000024a', 'wh3_dlc27_unit_passive_murderous_euphoria', 'Murderous Euphoria', 'Reaching the seabed of their silent obsession, the Druchii straddle the peaks of euphoria. The journey down is tiring but impossible to abandon.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (587, 'd1000000-0000-0000-0000-00000000024b', 'wh3_dlc27_unit_passive_naval_discipline', '{{tr:unit_abilities_onscreen_name_wh3_dlc27_lord_passive_naval_discipline}}', 'By the call of its mighty Sea Lords, the Asur fleet demonstrates why it is renowned as the greatest naval power in the world, its training superior to all others.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (588, 'd1000000-0000-0000-0000-00000000024c', 'wh3_dlc27_unit_passive_pleasure_through_pain', 'Pleasure Through Pain', 'Pain is not a private thing for the followers of Slaanesh. They take pleasure in sharing its gift, hoarding it within themselves to grace whomever they chose.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (589, 'd1000000-0000-0000-0000-00000000024d', 'wh3_dlc27_unit_passive_poisonous_blood', 'Poisonous Blood', 'This mottled grey fresh is shot through with pulsing veins reeking of corruption and rot – draw the Dread Maw’s blood at your peril.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (590, 'd1000000-0000-0000-0000-00000000024e', 'wh3_dlc27_unit_passive_split_up', 'Split Up', 'A cornered Sea Elemental will often unleash lesser of its kind, discharging them like scalding geysers to mercilessly flay its assailants.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (591, 'd1000000-0000-0000-0000-00000000024f', 'wh3_dlc27_unit_passive_split_up_hidden', 'HIDDEN - Split up', 'placeholder', 'wh_type_summon_unit', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (592, 'd1000000-0000-0000-0000-000000000250', 'wh3_dlc27_unit_passive_unbinding_giant_spawn_of_sla', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (593, 'd1000000-0000-0000-0000-000000000251', 'wh3_main_character_abilities_arsebelcher', 'Arsebelcher', 'Ogre diets are notoriously protein-heavy, ensuring their farts are less than fragrant! As you might expect, the enemy are not best pleased.', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (594, 'd1000000-0000-0000-0000-000000000252', 'wh3_main_character_abilities_crippling_throw', 'Crippling Throw', 'More than the usual injuries caused by something that''s much more than an ordinary spear.', 'wh_type_magic_missile', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (595, 'd1000000-0000-0000-0000-000000000253', 'wh3_main_character_abilities_dazs_song_of_winter_sunlight', 'Dazh''s Song of Winter Sunlight', '"Death is like a winter chill; No door can keep it from us; And summer yet may bloom again; Though ice be all upon us."', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (596, 'd1000000-0000-0000-0000-000000000254', 'wh3_main_character_abilities_enchanted_metallurgy', 'Enchanted Metallurgy', 'The science by which metals are extracted from their ores can be charged by magic and given purpose in war to devastating effect.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (597, 'd1000000-0000-0000-0000-000000000255', 'wh3_main_character_abilities_eruption', 'Eruption', '"That''s torn it – now ''e''s all angry like. I''d run if I were yoo… BOOM!"', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (598, 'd1000000-0000-0000-0000-000000000256', 'wh3_main_character_abilities_extra_ingredients', 'Extra Ingredients', '"A little bit of this, a pinch of that, and a touch of the other and... stand well back!"', 'wh_type_augment_of_the_winds', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (599, 'd1000000-0000-0000-0000-000000000257', 'wh3_main_character_abilities_fire_breath', 'Fire Breath', 'When you''ve had just the right cocktail of incendiary ingredients for lunch, nothing with an ounce of sense will stand in your way…', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (600, 'd1000000-0000-0000-0000-000000000258', 'wh3_main_character_abilities_flame_incarnate', 'Flame Incarnate', 'By which a vortex of fire surrounds the user; surprisingly, this improves their skills considerably.', 'wh_type_ward_save', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (601, 'd1000000-0000-0000-0000-000000000259', 'wh3_main_character_abilities_gate_of_khorne', 'Gate of Khorne', 'Khorne''s loyal Cultist forces open the gate to allow His vicious, chosen Bloodletters to surge through and consume the inauspicious enemy.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (602, 'd1000000-0000-0000-0000-00000000025a', 'wh3_main_character_abilities_gate_of_nurgle', 'Gate of Nurgle', 'The Cultist hauls open the gate to allow yet more foul, droning Plaguebearers to shuffle into existence to surround and infect the enemy.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (603, 'd1000000-0000-0000-0000-00000000025b', 'wh3_main_character_abilities_gate_of_slaanesh', 'Gate of Slaanesh', 'The Cultist holds the gate open so alluring Daemonettes can surge through and have at the foe, as if starved of sustenance for an eternity prior.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (604, 'd1000000-0000-0000-0000-00000000025c', 'wh3_main_character_abilities_gate_of_tzeentch', 'Gate of Tzeentch', 'Undiluted Change in the form of Pink Horrors tumble through into this world, giggling and capering towards the foe.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (605, 'd1000000-0000-0000-0000-00000000025d', 'wh3_main_character_abilities_glacial_blast', 'Glacial Blast', 'This eldritch explosion propels lacerating shards of ice outwards, devastating anyone caught in its deadly squall.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (606, 'd1000000-0000-0000-0000-00000000025e', 'wh3_main_character_abilities_greater_gate_of_tzeentch', 'Greater Gate of Tzeentch', 'The Cultist prises open the aperture, enabling a Lord of Change to enter reality and level great hope and towering ambition at the unsuspecting enemy.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (607, 'd1000000-0000-0000-0000-00000000025f', 'wh3_main_character_abilities_guardian_call', 'Guardian Call', 'Adepts of the Ice Court can summon forth a vicious, sabre-toothed battle-cat to savage their enemies'' ranks, tearing them to bloody shreds in decidedly short order.', 'wh_type_summon_unit', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (608, 'd1000000-0000-0000-0000-000000000260', 'wh3_main_character_abilities_ice_shard', 'Ice Shard', 'A mighty spike of the hardest ice blasts forth to impale ranks of enemies like a well-aimed cannonball from below.', 'wh_type_magic_missile', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (609, 'd1000000-0000-0000-0000-000000000261', 'wh3_main_character_abilities_locus_of_abjuration', 'Locus of Abjuration', 'The Herald''s dedication to Khorne exceeds all else, enabling them to resist magical attack via their unnatural, Daemonic aura of rancorous disdain.', 'wh_type_area_of_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (610, 'd1000000-0000-0000-0000-000000000262', 'wh3_main_character_abilities_locus_of_change', 'Locus of Change', 'Change comes in many forms… Death, in this instance, is brought down swiftly from above.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (611, 'd1000000-0000-0000-0000-000000000263', 'wh3_main_character_abilities_locus_of_conjuration', 'Locus of Conjuration', 'The more units in the immediate vicinity of this focal point, the more the Winds of Magic are recharged.', 'wh_type_area_of_augments_of_the_winds', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (612, 'd1000000-0000-0000-0000-000000000264', 'wh3_main_character_abilities_locus_of_fecundity', 'Locus of Fecundity', '"Come to my side, o pestilent comrades. Through me, the Urfather''s withering touch shall restore and renew you."', 'wh_type_area_of_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (613, 'd1000000-0000-0000-0000-000000000265', 'wh3_main_character_abilities_locus_of_fury', 'Locus of Fury', 'Anger is an energy – the most powerful force in all creation. Never doubt it.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (614, 'd1000000-0000-0000-0000-000000000266', 'wh3_main_character_abilities_locus_of_grace', 'Locus of Grace', 'The warrior glides with a beauteous, smooth elegance that enables them to simply avoid blows as if in slow motion, for the Dark Prince has blessed their every move.', 'wh_type_area_of_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (615, 'd1000000-0000-0000-0000-000000000267', 'wh3_main_character_abilities_locus_of_swiftness', 'Locus of Swiftness', 'When the most precious of rewards is but a hair''s breadth away, the chosen warrior will move with preternatural speed and agility.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (616, 'd1000000-0000-0000-0000-000000000268', 'wh3_main_character_abilities_locus_of_virulence', 'Locus of Virulence', 'Wholly and perversely against nature, those warriors elevated to Daemonhood by the Fly Lord will prosper and surge through His disgusting gifts and boons.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (617, 'd1000000-0000-0000-0000-000000000269', 'wh3_main_character_abilities_locus_of_wrath', 'Locus of Wrath', 'Khorne''s Heralds find that the pure, unadulterated ire channelled directly from the Blood God Himself drives their own impetuous vehemence to even greater heights.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (618, 'd1000000-0000-0000-0000-00000000026a', 'wh3_main_character_abilities_salyaks_lullaby', 'Salyak''s Lullaby', '"Glorious bird of shimmering white, put pain and fear to shameful flight…"', 'wh_type_area_of_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (619, 'd1000000-0000-0000-0000-00000000026b', 'wh3_main_character_abilities_tors_battle_hymn', 'Tor''s Battle Hymn', '"Thunder is strong and lightning is death, with Tor''s wrath a flash-bolt takes their breath!"', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (620, 'd1000000-0000-0000-0000-00000000026c', 'wh3_main_character_abilities_ursuns_roar', 'Ursun''s Roar', 'The blood-curdling howl of Father Bear rallies the men of Kislev to his banner, for their fortunes are forever entwined, and the fate of the Motherland hangs in the balance.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (621, 'd1000000-0000-0000-0000-00000000026d', 'wh3_main_character_passive_bellyslapper', 'Bellyslapper', 'An Ogre whose proclivity is for slapping his body, making his flesh ripple and repel the foe.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (622, 'd1000000-0000-0000-0000-00000000026e', 'wh3_main_character_passive_enduring_devotion', 'Enduring Devotion', 'When he wills it so, those loyal to the Patriarch will find their minds and bodies bolstered against attack.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (623, 'd1000000-0000-0000-0000-00000000026f', 'wh3_main_character_passive_heroic_resilience', 'Heroic Resilience', 'When calamity crashes in waves against the Motherland''s defences, its warriors always find the strength and spirit needed to succeed.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (624, 'd1000000-0000-0000-0000-000000000270', 'wh3_main_character_passive_loner', 'Loner', 'Sometimes, going at it full tilt, on your lonesome, pays dividends in skulls for the pile.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (625, 'd1000000-0000-0000-0000-000000000271', 'wh3_main_character_passive_the_courage_of_sacrifice', 'The Courage of Sacrifice', 'The Patriarch''s unshakeable belief in himself and his creed pushes the warriors around him to fight to the bitter end.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (626, 'd1000000-0000-0000-0000-000000000272', 'wh3_main_character_passive_will_of_the_dragons', 'Will of the Dragons', 'The Dragons have ruled Cathay for centuries. Their power will never be questioned by their imperial subjects, who understand their place and role in the world perfectly.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (627, 'd1000000-0000-0000-0000-000000000273', 'wh3_main_daemon_arms_abilities_blue_fire', 'Blue Fire of Chaos', 'The colour of this fire is the deep, bright azure of Change, blasted forth to confuse, beguile and burn to a crisp those whom it touches.', 'wh_type_breath', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (628, 'd1000000-0000-0000-0000-000000000274', 'wh3_main_daemon_arms_abilities_blue_fire_upgraded', 'Blue Fire of Chaos Upgraded', 'The colour of this fire is the deep, bright azure of Change, blasted forth to confuse, beguile and burn to a crisp those whom it touches.', 'wh_type_breath', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (629, 'd1000000-0000-0000-0000-000000000275', 'wh3_main_daemon_arms_abilities_gate_of_chaos', 'Gate of Chaos', 'What lies beyond the Gate of Chaos? Why, Change, of course, with all the maddening tumult which that entails.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (630, 'd1000000-0000-0000-0000-000000000276', 'wh3_main_daemon_arms_abilities_gate_of_chaos_upgraded', 'Gate of Chaos Upgraded', 'What lies beyond the Gate of Chaos? Why, Change, of course, with all the maddening tumult which that entails.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (631, 'd1000000-0000-0000-0000-000000000277', 'wh3_main_daemon_arms_abilities_mortal_blow', 'Mortal Blow', 'When all the Ruinous power inside you is charged and focused, a single, devastating blow is all that''s needed.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (632, 'd1000000-0000-0000-0000-000000000278', 'wh3_main_daemon_arms_abilities_mortal_blow_upgraded', 'Mortal Blow Upgraded', 'When all the Ruinous power inside you is charged and focused, a single, devastating blow is all that''s needed.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (633, 'd1000000-0000-0000-0000-000000000279', 'wh3_main_daemon_arms_passive_for_the_slaughter', 'For the Slaughter!', 'The longer Kharneth''s Daemonic servant remains in the fray, doing His dreadful work, the more efficient they become.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (634, 'd1000000-0000-0000-0000-00000000027a', 'wh3_main_daemon_arms_passive_for_the_slaughter_upgraded', 'For the Slaughter! Upgraded', 'The longer Kharneth''s Daemonic servant remains in the fray, doing His dreadful work, the more efficient they become.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (635, 'd1000000-0000-0000-0000-00000000027b', 'wh3_main_daemon_arms_passive_unending_feast', 'Blighted Feast', 'To the Daemon Prince in thrall to Ruin, souls provide fine and plentiful sustenance on the way to glory.', 'wh_type_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (636, 'd1000000-0000-0000-0000-00000000027c', 'wh3_main_daemon_arms_passive_unending_feast_upgraded', 'Blighted Feast Upgraded', 'To the Daemon Prince in thrall to Ruin, souls provide fine and plentiful sustenance on the way to glory.', 'wh_type_chain_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (637, 'd1000000-0000-0000-0000-00000000027d', 'wh3_main_daemon_body_abilities_chaos_armour', 'Chaos Armour', 'This finely-wrought suit of armour seems to have a mind of its own – appearing to revel in punishing foes in proportion to the mindlessness of their charge.', 'wh_type_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (638, 'd1000000-0000-0000-0000-00000000027e', 'wh3_main_daemon_body_abilities_winds_of_change', 'Winds of Change', '"Take me to the magic moment, upon glory night, where the children of tomorrow dream…"', 'wh_type_augment_of_the_winds', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (639, 'd1000000-0000-0000-0000-00000000027f', 'wh3_main_daemon_body_passive_foreboding_ignition', 'Foreboding Ignition', 'If there''s a strong chance that you might die, take as many of the enemy with you as possible.', 'wh_type_explosion', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (640, 'd1000000-0000-0000-0000-000000000280', 'wh3_main_daemon_body_passive_restore_the_blighted', 'Restore the Blighted', 'The Plague Lord likes to pull His beloved servants back from the brink, so they may continue to spread His rot untroubled by death.', 'wh_type_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (641, 'd1000000-0000-0000-0000-000000000281', 'wh3_main_daemon_body_passive_soporific_musk', 'Fiendish Musk', 'The enemy are overtaken by a somniferous perfume that induces sleep in spite of the din raging all about them.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (642, 'd1000000-0000-0000-0000-000000000282', 'wh3_main_daemon_body_passive_tempered_rage', 'Tempered Rage', 'Like steel, rage can be tempered and buffed until maximum hardness and shine have been achieved.', 'wh_type_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (643, 'd1000000-0000-0000-0000-000000000283', 'wh3_main_daemon_head_abilities_call_for_power', 'Call for Power', 'Having implored the Ruinous Powers to imbue him with the inexorable, raw power of Chaos, the Daemon Prince attacks with even greater vigour than before.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (644, 'd1000000-0000-0000-0000-000000000284', 'wh3_main_daemon_head_abilities_pestilent_regeneration', 'Pestilent Regeneration', 'From decay something new arises, always stronger, more powerful, and more disgusting than before.', 'wh_type_chain_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (645, 'd1000000-0000-0000-0000-000000000285', 'wh3_main_daemon_head_abilities_sonic_boom', 'Sonic Boom', 'A colossal, ear-splitting burst of sound will hurl the foe across the battlefield, leaving them disorientated – assuming of course they survive the experience!', 'wh_type_explosion', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (646, 'd1000000-0000-0000-0000-000000000286', 'wh3_main_daemon_head_abilities_word_of_change', 'Word of Change', 'Through His ever-willing vessel, the Dark Sorcerer of the Chaos Gods can cause broiling waves of maddening Change to engulf spellcasting foes.', 'wh_type_hex_of_the_winds', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (647, 'd1000000-0000-0000-0000-000000000287', 'wh3_main_daemon_legs_abilities_daemonic_onslaught', 'Daemonic Onslaught', 'No mortal host shall hold them back.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (648, 'd1000000-0000-0000-0000-000000000288', 'wh3_main_daemon_legs_passive_sinful_footing', 'Sinful Footing', 'There''s no chase like the pursuit of petrified mortal souls, for the prize is the sweetest of all.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (649, 'd1000000-0000-0000-0000-000000000289', 'wh3_main_daemon_tail_passive_serpentine_tail', 'Serpentine Tail', 'Though it also aids balance during the hurly-burly of brutal conflict, this appendage gives this monstrous creature a further weapon with which to smite the opponents of Ruin.', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (650, 'd1000000-0000-0000-0000-00000000028a', 'wh3_main_daemon_wings_abilities_eldritch_aura', 'Eldritch Aura', 'The dark, violent sorceries of the Chaos Gods draw further power from the Winds of Magic when they are blowing their hardest across the battlefield.', 'wh_type_area_of_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (651, 'd1000000-0000-0000-0000-00000000028b', 'wh3_main_daemon_wings_abilities_purge_the_weak', 'Purge the Weak!', 'Those who fail to make the grade are consigned to writhing, agonising forms for eternity and replaced with more promising candidates.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (652, 'd1000000-0000-0000-0000-00000000028c', 'wh3_main_daemon_wings_abilities_trophy_heads', 'Trophy Heads', 'The score must be kept just as surely as the harvested skulls be delivered to the Lord of Murder, atop His mighty Skull Throne.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (653, 'd1000000-0000-0000-0000-00000000028d', 'wh3_main_daemon_wings_abilities_winds_of_flight', 'Arcane Flight', 'The magical eddies flowing across the battlefield can be harnessed to propel the Daemon Prince ever faster, as if flying.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (654, 'd1000000-0000-0000-0000-00000000028e', 'wh3_main_hero_passive_strategist', 'Tactician', 'Strategy and tactics can be learned from a book, but only honed through experience in the field.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (655, 'd1000000-0000-0000-0000-00000000028f', 'wh3_main_item_abilities_scroll_of_destiny', 'Scroll of Destiny', 'Possession of this scroll enables the bearer – just once during a battle – to reset the Winds of Magic to their former levels.', 'wh_type_area_of_augments_of_the_winds', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (656, 'd1000000-0000-0000-0000-000000000290', 'wh3_main_lord_abilities_ballet_of_blows', 'Ballet of Blows', 'The finest combat is beautiful to behold, like the precision choreography of the most complex of dances – each delicious move bringing the Exalted Keeper of Secrets closer to the killing climax.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (657, 'd1000000-0000-0000-0000-000000000291', 'wh3_main_lord_abilities_bellow_of_endless_fury', 'Bellow of Endless Fury', 'Skarbrand summons up all his rage and hatred and concentrate it into a devastating furious howl that can shake the unprepared enemy ranks to their very core.', 'wh_type_magic_missile', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (658, 'd1000000-0000-0000-0000-000000000292', 'wh3_main_lord_abilities_bellow_of_fury', 'Bellow of Fury', 'Channelling all the rancour of the blood-crazed killer upon the Skull Throne, His chosen servant emits a bloodcurdling scream to make the unfortunate foe quake and die in their boots.', 'wh_type_magic_missile', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (659, 'd1000000-0000-0000-0000-000000000293', 'wh3_main_lord_abilities_blight_swarm', 'Blight Swarm', 'Flies, drenched in the pustulent gore of rotting intestines, swarm and surround the foe, hampering their blows and haltering their attacks.', 'wh_type_chain_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (660, 'd1000000-0000-0000-0000-000000000294', 'wh3_main_lord_abilities_bloodthirst', 'Bloodthirst', 'The all-consuming craving for blood and slaughter drives forth Khorne''s faithful servants with even greater speed and fury.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (661, 'd1000000-0000-0000-0000-000000000295', 'wh3_main_lord_abilities_burning_rage', 'Burning Rage', 'The physical manifestation of their endless, furious anger is an explosion of fiery death all around the Blood God''s Daemonic servant.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (662, 'd1000000-0000-0000-0000-000000000296', 'wh3_main_lord_abilities_deathbringer', 'Deathbringer', 'Cutting harder and deeper with each and every blow, this blade ensures that the blood of Kharneth''s enemies flows like a river across the battlefield.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (663, 'd1000000-0000-0000-0000-000000000297', 'wh3_main_lord_abilities_deathbringer_upgraded', 'Deathbringer Upgraded', 'Cutting harder and deeper with each and every blow, this blade ensures that the blood of Kharneth''s enemies flows like a river across the battlefield.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (664, 'd1000000-0000-0000-0000-000000000298', 'wh3_main_lord_abilities_everyone_has_their_price', 'Everyone Has Their Price', 'This hex makes the foe reconsider their options – perhaps leading a warband into almost certain death isn''t quite such a good idea after all?', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (665, 'd1000000-0000-0000-0000-000000000299', 'wh3_main_lord_abilities_eye_of_the_storm', 'Eye of the Storm', 'From the epicentre of the raging tempest of their righteousness, the Dragon strikes with effortless ease, sweeping the foe away like so many leaves on the wind.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (666, 'd1000000-0000-0000-0000-00000000029a', 'wh3_main_lord_abilities_fury_of_ursun', 'Fury of Ursun', 'Taking on the mantle of the Bear himself, Urskin''s furious rage terrifies his foes, walking the finest line between control and frenzy.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (667, 'd1000000-0000-0000-0000-00000000029b', 'wh3_main_lord_abilities_gaze_of_fate', 'Gaze of Fate', 'Sometimes, the abyss stares right back at you, and true perspective is revealed. The shock freezes the foe where they stand.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (668, 'd1000000-0000-0000-0000-00000000029c', 'wh3_main_lord_abilities_hidden_in_time', 'Hidden in Time', 'Seconds into the past or future is the perfect hiding place when fighting an adversary tied to the present.', 'wh_type_hiding', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (669, 'd1000000-0000-0000-0000-00000000029d', 'wh3_main_lord_abilities_inspired_assault_i', 'Inspired Assault I', 'The most noble, educated and experienced among us have the means to think laterally, the confidence to know that victory is close at hand, and most importantly, the power to inspire.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (670, 'd1000000-0000-0000-0000-00000000029e', 'wh3_main_lord_abilities_inspired_defence_i', 'Inspired Defence I', 'The ability to think several moves ahead of their opponents gives the Cathayan nobles a distinct advantage in matters of defence.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (671, 'd1000000-0000-0000-0000-00000000029f', 'wh3_main_lord_abilities_inspired_marksmanship_i', 'Inspired Marksmanship I', 'Being taught to shoot shortly after learning to walk means that by adulthood the magistrate''s arrows are true and their eyesight is as acute as the swooping hawk.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (672, 'd1000000-0000-0000-0000-0000000002a0', 'wh3_main_lord_abilities_iron_dragon_dragon_form', 'Transformation of the Dragon', 'Zhao Ming has the innate power to transmogrify from human form to Dragon and back again at will, and often at the most opportune moments.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (673, 'd1000000-0000-0000-0000-0000000002a1', 'wh3_main_lord_abilities_iron_dragon_human_form', 'Transformation of the Dragon', 'Zhao Ming has the innate power to transmogrify from Dragon form to human and back again at will, and often at the most opportune moments.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (674, 'd1000000-0000-0000-0000-0000000002a2', 'wh3_main_lord_abilities_master_of_alchemy', 'Master of Alchemy', 'Base metals may be transmuted and transformed, so that they might strike harder and better at the Celestial Emperor''s enemies.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (675, 'd1000000-0000-0000-0000-0000000002a3', 'wh3_main_lord_abilities_nurgling_tide', 'Nurgling Tide', 'A sickening wave of smiling, giggling Nurglings spills out everywhere, tumbling towards the foe only to explode, sending putrid pus and foetid rot in all directions.', 'wh_type_summon_unit', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (676, 'd1000000-0000-0000-0000-0000000002a4', 'wh3_main_lord_abilities_oracle_of_eternity', 'Oracle of Eternity', 'Whilst Kairos is consulting with the infinite he is temporarily protected from harm.', 'wh_type_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (677, 'd1000000-0000-0000-0000-0000000002a5', 'wh3_main_lord_abilities_plaguefathers_oration', 'Plaguefather''s Oration', 'Words of purpose and encouragement from Ku''gath himself stir his warriors to continue spreading disease in Nurgle''s blessed name.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (678, 'd1000000-0000-0000-0000-0000000002a6', 'wh3_main_lord_abilities_rage_embodied', 'Rage Embodied', 'Skarbrand is the very embodiment of all the Murder Lord''s pent-up choler and bile. His presence drives Khorne''s warriors to even greater fury.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (679, 'd1000000-0000-0000-0000-0000000002a7', 'wh3_main_lord_abilities_seductive_glory', 'Seductive Glory', 'When victory is thought to be close, caution is cast to the four winds and frenzy beckons enticingly.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (680, 'd1000000-0000-0000-0000-0000000002a8', 'wh3_main_lord_abilities_shadow_shroud', 'Shadow Shroud', 'The Father-in-Shadow wraps himself in a cloak of murk that protects him from lesser magicks.', 'wh_type_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (681, 'd1000000-0000-0000-0000-0000000002a9', 'wh3_main_lord_abilities_storm_dragon_dragon_form', 'Transformation of the Dragon', 'Miao Ying has the innate power to transmogrify from human form to Dragon and back again at will, and often at the most opportune moments.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (682, 'd1000000-0000-0000-0000-0000000002aa', 'wh3_main_lord_abilities_storm_dragon_human_form', 'Transformation of the Dragon', 'Miao Ying has the innate power to transmogrify from Dragon form to human and back again at will, and often at the most opportune moments.', 'wh_type_transform', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (683, 'd1000000-0000-0000-0000-0000000002ab', 'wh3_main_lord_abilities_the_dark_master', 'The Dark Master', 'If you unwisely choose not to run, strike far harder than you dare, for Be''lakor wields Ruin''s combined might to confuse and tempt and rot and slaughter his foes.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (684, 'd1000000-0000-0000-0000-0000000002ac', 'wh3_main_lord_abilities_virulent_contagion', 'Virulent Contagion', 'Sulphurous, acerbic disease is no respecter of rank, nobility or prowess in battle; all shall fall afore Nurgle''s filthy infections.', 'wh_type_chain_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (685, 'd1000000-0000-0000-0000-0000000002ad', 'wh3_main_lord_abilities_virulent_contagion_upgraded', 'Virulent Contagion Upgraded', '{{tr:unit_abilities_tooltip_text_wh3_main_lord_abilities_virulent_contagion}}', 'wh_type_chain_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (686, 'd1000000-0000-0000-0000-0000000002ae', 'wh3_main_lord_abilities_willing_prey', 'Willing Prey', 'Some beings, in their darkest heart, have a deep-seated desire for an agonising death.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (687, 'd1000000-0000-0000-0000-0000000002af', 'wh3_main_lord_abilities_wrath_of_the_storm', 'Wrath of the Storm', 'Elements thought uncontrollable can be harnessed to do the Dragon''s bidding – both to crush their enemies and protect them when in human form.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (688, 'd1000000-0000-0000-0000-0000000002b0', 'wh3_main_lord_abilities_wrathful_reaper', 'Wrathful Reaper', 'Skarbrand runs rampant, twin axes hacking and cleaving until there is no one left to kill.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (689, 'd1000000-0000-0000-0000-0000000002b1', 'wh3_main_lord_passive_aura_of_majesty', 'Aura of Majesty', 'When battle is brought with shock and awe by the Lords of the Celestial Empire, some weaker creatures find themselves unable to mount a competent defence.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (690, 'd1000000-0000-0000-0000-0000000002b2', 'wh3_main_lord_passive_blaze_of_devotion', 'Blaze of Devotion', 'When Kostaltyn is in the thick of the bloodiest melee, the men around him will fight harder and longer, aided by the righteous fire of their Motherland.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (691, 'd1000000-0000-0000-0000-0000000002b3', 'wh3_main_lord_passive_disdain_of_the_dragons', 'Disdain of the Dragons', '"Looks into the eyes of the Dragon and despair!"', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (692, 'd1000000-0000-0000-0000-0000000002b4', 'wh3_main_lord_passive_feasting_on_fear', 'Feasting on Fear', 'Others'' fear is meat and drink to the Perfect Prince''s Feasters of Pain.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (693, 'd1000000-0000-0000-0000-0000000002b5', 'wh3_main_lord_passive_fetid_stench', 'Foetid Stench', 'The malodorous stink of decay eventually wears down even the hardest, most experienced combatants, dampening their spirits and resolve to press on.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (694, 'd1000000-0000-0000-0000-0000000002b6', 'wh3_main_lord_passive_fuelled_by_rage', 'Fuelled by Rage', 'Unbridled rage courses through the veins of Kharneth''s followers, raising them up and restoring them for the slaughter to follow.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (695, 'd1000000-0000-0000-0000-0000000002b7', 'wh3_main_lord_passive_glamour_of_slaanesh', 'Glamour of Slaanesh', 'The pure, unadulterated temptation that glorious perfection provides is as alluring as gold or the finest jewels.', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (696, 'd1000000-0000-0000-0000-0000000002b8', 'wh3_main_lord_passive_hardened_scale', 'Hardened Scale', 'The Dragon is ever-resilient to magical attack – both scales and will are like the hardest metal known to mortal men.', 'wh_type_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (697, 'd1000000-0000-0000-0000-0000000002b9', 'wh3_main_lord_passive_harvester_of_souls', 'Harvester of Souls', '"Distributor of pain... Your loss shall be my gain!"', 'wh_type_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (698, 'd1000000-0000-0000-0000-0000000002ba', 'wh3_main_lord_passive_hoardmaster', 'Hoardmaster', 'The ability to lead your force from the front and melee with the best of ''em is not something to be sniffed at.', 'wh_type_area_of_augments', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (699, 'd1000000-0000-0000-0000-0000000002bb', 'wh3_main_lord_passive_lord_of_torment', 'Lord of Torment', 'The greater Be''lakor''s power, the weaker his adversaries'' resolve becomes, until they are but fodder for the Dark Master''s blade.', 'wh_type_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (700, 'd1000000-0000-0000-0000-0000000002bc', 'wh3_main_lord_passive_nurgling_infestation', 'Nurgling Infestation', 'By his presence alone, Ku''gath can ensure that the Nurglings around him are restored to optimal bloated fiendishness.', 'wh_type_area_of_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (701, 'd1000000-0000-0000-0000-0000000002bd', 'wh3_main_lord_passive_pestilent_decay', 'Pestilent Decay', 'Death comes to us all in the end. None can resist the Urfather''s gift of vile decomposition forever…', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (702, 'd1000000-0000-0000-0000-0000000002be', 'wh3_main_lord_passive_prismatic_plurality', 'Prismatic Plurality', 'No matter the incantation, others'' abilities are restored far quicker than would normally be the case.', 'wh_type_augment_of_the_winds', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (703, 'd1000000-0000-0000-0000-0000000002bf', 'wh3_main_lord_passive_revel_in_slaughter', 'Revel in Slaughter', 'Seeing the bloody devastation all around them causes the lords of Kharneth to exult in triumph, further powering their carnivorous slaughter.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (704, 'd1000000-0000-0000-0000-0000000002c0', 'wh3_main_lord_passive_snacks', 'Snacks', 'Gnoblars have a number of practical applications, including healing and revitalising an Ogre when taken as a snack on the move.', 'wh_type_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (705, 'd1000000-0000-0000-0000-0000000002c1', 'wh3_main_lord_passive_soul_siphon', 'Soul Siphon', 'Along with the will to fight on, fleeing enemies find their very souls drawn from their broken bodies.', 'wh_type_area_of_direct_damage', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (706, 'd1000000-0000-0000-0000-0000000002c2', 'wh3_main_lord_passive_strategist', 'Tactician', 'Strategy and tactics can be learned from a book, but only honed through experience in the field.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (707, 'd1000000-0000-0000-0000-0000000002c3', 'wh3_main_lord_passive_ursuns_ward', 'Ursun''s Ward', 'Even at the teetering brink of death, the chosen of the Bear God will fight on, drawing on Ursun''s boundless resilience to stay alive.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (708, 'd1000000-0000-0000-0000-0000000002c4', 'wh3_main_lord_passive_warding_iron', 'Warding Iron', 'The strength of the Dragon can be passed to their loyal troops for a short while, so they may have some resistance to magical attack.', 'wh_type_area_of_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (709, 'd1000000-0000-0000-0000-0000000002c5', 'wh3_main_lord_passive_whispers_in_the_darkness', 'Whispers in the Darkness', 'Even the most steadfast among a warband may find their morale waver when the Harbinger''s voice whispers persistently in their ears.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (710, 'd1000000-0000-0000-0000-0000000002c6', 'wh3_main_lord_passive_wrath_of_khorne', 'Wrath of Khorne', 'The furious power of Khornate anger and wrath enables the Murder God''s followers to turn back others'' spells, causing them to explode in the Wizards'' faces.', 'wh_type_explosion', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (711, 'd1000000-0000-0000-0000-0000000002c7', 'wh3_main_lore_passive_blissful_rapture', 'Blissful Rapture', 'Whipped into a frenzy of ecstatic euphoria, all before the spellcaster are made oblivious to pain and defeat, driving them to even greater slaughter in Slaanesh''s precious name.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (712, 'd1000000-0000-0000-0000-0000000002c8', 'wh3_main_lore_passive_children_of_nurgle', 'Children of Nurgle', 'Kindly Grandfather Nurgle watches over His beloved offspring, nurturing their diseases to ensure they flourish and prosper.', 'wh_type_area_of_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (713, 'd1000000-0000-0000-0000-0000000002c9', 'wh3_main_lore_passive_fires_of_change', 'Fires of Change', '"Come, bathe in the purifying flames – be… different, be reborn anew from ash and bone."', 'wh_type_area_of_ward_save', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (714, 'd1000000-0000-0000-0000-0000000002ca', 'wh3_main_mount_bound_celestial_comet', 'Celestial Comet', 'When the War Compass is so primed, even heavenly bodies are not outside its devastating reach.', 'wh_type_bombardment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (715, 'd1000000-0000-0000-0000-0000000002cb', 'wh3_main_mount_bound_celestial_lightning', 'Celestial Lightning', 'The War Compass funnels deadly electricity from the heavens to sear and burn and smite the foe.', 'wh_type_bombardment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (716, 'd1000000-0000-0000-0000-0000000002cc', 'wh3_main_mount_passive_totem_of_endless_bloodletting', 'Totem of Endless Bloodletting', 'The more you kill, the more blood that you spill in His name, the more you will exsanguinate the enemies of the Blood God for His greater glory.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (717, 'd1000000-0000-0000-0000-0000000002cd', 'wh3_main_pro_quest_passive_favour_of_the_ruinous_powers', 'Favour of the Ruinous Powers', 'When the Dark Gods bless the assembled faithful from atop their mighty battle-altars, loyalty is assured for evermore.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (718, 'd1000000-0000-0000-0000-0000000002ce', 'wh3_main_spell_bound_lash_of_slaanesh_keeper_of_secrets', 'Lash of Slaanesh', 'The exquisite kiss of the Dark Prince''s three-tailed whip strikes the enemy with a delicious fury.', 'wh_type_breath', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (719, 'd1000000-0000-0000-0000-0000000002cf', 'wh3_main_spell_bound_pestilent_breath', 'Pestilent Breath', 'The spellcaster utters the vilest of phrases and belches forth an impossibly foul, poisonous cloud.', 'wh_type_breath', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (720, 'd1000000-0000-0000-0000-0000000002d0', 'wh3_main_spell_nurgle_miasma_of_pestilence_bound', 'Miasma of Pestilence', 'The most putrescent vapour fills the air, loosening lunches and bowels, and causing violent, crippling vomiting seizures in nearby foes.', 'wh_type_hex', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (721, 'd1000000-0000-0000-0000-0000000002d1', 'wh3_main_spell_nurgle_stream_of_corruption_bound', 'Stream of Corruption', 'A poisonous spurt of diseased gas and bile spews forth from the spellcaster''s diseased lungs, drenching the enemy in vile, choking pus.', 'wh_type_breath', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (722, 'd1000000-0000-0000-0000-0000000002d2', 'wh3_main_spell_slaanesh_acquiescence_bound', 'Acquiescence', 'The spellcaster''s corrupting touch puts their victims into a blissful, euphoric state for a short time, rendering them little able to move, let alone defend themselves.', 'wh_type_hex', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (723, 'd1000000-0000-0000-0000-0000000002d3', 'wh3_main_spell_slaanesh_hysterical_frenzy_bound', 'Hysterical Frenzy', 'The caster''s victims are engulfed by a torrent of unreasoning emotion, excruciating pain and blissful rapture, causing them to embark on a riotous, clawing rampage.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (724, 'd1000000-0000-0000-0000-0000000002d4', 'wh3_main_spell_slaanesh_phantasmagoria_bound', 'Phantasmagoria', 'A complex sigil is performed, transfixing the enemy with a shifting array of hallucinatory images that disjoint and befuddle, inviting their deaths.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (725, 'd1000000-0000-0000-0000-0000000002d5', 'wh3_main_spell_tzeentch_blue_fire_of_tzeentch_bound', 'Blue Fire of Tzeentch', 'With a twist of the hand, the spellcaster causes the bodies of their opponents to be consumed by coruscating blue flames.', 'wh_type_magic_missiles', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (726, 'd1000000-0000-0000-0000-0000000002d6', 'wh3_main_spell_tzeentch_pink_fire_of_tzeentch_bound', 'Pink Fire of Tzeentch', 'A roiling tide of iridescent energy flows from the spellcaster, enveloping their enemies in a cone of searing magical flame.', 'wh_type_breath', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (727, 'd1000000-0000-0000-0000-0000000002d7', 'wh3_main_unit_abilities_elemental_breath', 'Elemental Breath', 'When the land itself fights back, the enemy is petrified by its freezing touch, meaning the slightest gust will see them shatter into dust.', 'wh_type_magic_missiles', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (728, 'd1000000-0000-0000-0000-0000000002d8', 'wh3_main_unit_abilities_gnoblar_traps', 'Gnoblar Traps', 'Gnoblars are at least as sneaky and trapsy as ordinary gobbos, as you may just find out!', 'wh_type_hex', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (729, 'd1000000-0000-0000-0000-0000000002d9', 'wh3_main_unit_abilities_necrotic_explosion', 'Necrotic Explosion', 'When a mass of filthy, pus-soaked Nurglings spontaneously combust before the foe, not one among them will remain untouched by the Plague Lord''s foul rot.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (730, 'd1000000-0000-0000-0000-0000000002da', 'wh3_main_unit_abilities_sky_junk_bomb', 'Sky-Junk Bomb', 'Control the skies above the battlefield and you can be assured of success upon on the ground below – gravity is your ally, remember.', 'wh_type_bombardment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (731, 'd1000000-0000-0000-0000-0000000002db', 'wh3_main_unit_abilities_stun_bomb', 'Heaven''s Flash', 'Ignition of this gunpowder mixture causes shavings to quickly scatter into a foul, painful cloud, leaving enemies vulnerable to the cut-and-thrust of close quarters combat.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (732, 'd1000000-0000-0000-0000-0000000002dc', 'wh3_main_unit_passive_arcane_mirth', 'Arcane Mirth', 'When not fighting, Squealers can be put to good use conjuring up a fresh batch of magical mischief to lay the enemy low.', 'wh_type_augment_of_the_winds', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (733, 'd1000000-0000-0000-0000-0000000002dd', 'wh3_main_unit_passive_aura_of_immolation', 'Aura of Immolation', 'War is the crucible that melts all things.', 'wh_type_area_of_hexes', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (734, 'd1000000-0000-0000-0000-0000000002de', 'wh3_main_unit_passive_aura_of_mutation', 'Aura of Mutation', 'Change isn''t always welcome… or survivable, for that matter.', 'wh_type_area_of_direct_damage', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (735, 'd1000000-0000-0000-0000-0000000002df', 'wh3_main_unit_passive_battle_harmony_yang', 'Battle Harmony: Yang', 'There must be balance in all things: dark and light, moon and sun, female and male.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (736, 'd1000000-0000-0000-0000-0000000002e0', 'wh3_main_unit_passive_battle_harmony_yin', 'Battle Harmony: Yin', 'There must be balance in all things: dark and light, moon and sun, female and male.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (737, 'd1000000-0000-0000-0000-0000000002e1', 'wh3_main_unit_passive_by_our_blood', 'By Our Blood', 'Kislevite warriors are inherently stronger than weak-hearted Empire-men, who know nothing of the hardship and strife of lives lived on the unforgiving steppes.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (738, 'd1000000-0000-0000-0000-0000000002e2', 'wh3_main_unit_passive_cloud_of_flies', 'Cloud of Flies', 'Through His endless pestilent blessings, the Plague Lord''s followers thrive and surge forward when others would simply wither and die.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (739, 'd1000000-0000-0000-0000-0000000002e3', 'wh3_main_unit_passive_daemonic_instability_daemon', 'Daemonic Instability', 'As the Daemon''s courage falters, their mortal form crumbles and fades from this reality.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (740, 'd1000000-0000-0000-0000-0000000002e4', 'wh3_main_unit_passive_daemonic_instability_daemon_ii', 'Banished!', 'Once the Daemon''s courage has failed them, they will fall back through the portal to the Chaos Realm whence they belong.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (741, 'd1000000-0000-0000-0000-0000000002e5', 'wh3_main_unit_passive_daemonic_instability_khorne', 'Daemonic Instability', 'As the Daemon''s courage falters, their mortal form crumbles and fades from this reality.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (742, 'd1000000-0000-0000-0000-0000000002e6', 'wh3_main_unit_passive_daemonic_instability_khorne_ii', 'Banished!', 'Once the Daemon''s courage has failed them, they will fall back through the portal to the Chaos Realm whence they belong.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (743, 'd1000000-0000-0000-0000-0000000002e7', 'wh3_main_unit_passive_daemonic_instability_nurgle', 'Daemonic Instability', 'As the Daemon''s courage falters, their mortal form crumbles and fades from this reality.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (744, 'd1000000-0000-0000-0000-0000000002e8', 'wh3_main_unit_passive_daemonic_instability_nurgle_ii', 'Banished!', 'Once the Daemon''s courage has failed them, they will fall back through the portal to the Chaos Realm whence they belong.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (745, 'd1000000-0000-0000-0000-0000000002e9', 'wh3_main_unit_passive_daemonic_instability_slaanesh', 'Daemonic Instability', 'As the Daemon''s courage falters, their mortal form crumbles and fades from this reality.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (746, 'd1000000-0000-0000-0000-0000000002ea', 'wh3_main_unit_passive_daemonic_instability_slaanesh_ii', 'Banished!', 'Once the Daemon''s courage has failed them, they will fall back through the portal to the Chaos Realm whence they belong.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (747, 'd1000000-0000-0000-0000-0000000002eb', 'wh3_main_unit_passive_daemonic_instability_tzeentch', 'Daemonic Instability', 'As the Daemon''s courage falters, their mortal form crumbles and fades from this reality.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (748, 'd1000000-0000-0000-0000-0000000002ec', 'wh3_main_unit_passive_daemonic_instability_tzeentch_ii', 'Banished!', 'Once the Daemon''s courage has failed them, they will fall back through the portal to the Chaos Realm whence they belong.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (749, 'd1000000-0000-0000-0000-0000000002ed', 'wh3_main_unit_passive_defensive_stance', 'Defensive Stance', 'Become like the mountain: immovable, stronger over time, and nigh-on impossible to assail.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (750, 'd1000000-0000-0000-0000-0000000002ee', 'wh3_main_unit_passive_eye_of_the_dragon', 'Eye of the Dragon', 'The higher you go, the further you can see, like the Dragons in flight above Cathay''s harmonious landscape.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (751, 'd1000000-0000-0000-0000-0000000002ef', 'wh3_main_unit_passive_feasting_on_fear', 'Feasting on Fear', 'Others'' fear is meat and drink to the Perfect Prince''s Feasters of Pain.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (752, 'd1000000-0000-0000-0000-0000000002f0', 'wh3_main_unit_passive_gorefeast', 'Gorefeast', 'When the bloodlust and frenzy are at their utmost levels, minor wounds are healed by the Blood God''s towering, unassailable will.', 'wh_type_regeneration', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (753, 'd1000000-0000-0000-0000-0000000002f1', 'wh3_main_unit_passive_hellblade', 'Hellblade', 'The shrieking swords of the Horned Ones become more effective the longer the battle rages and the greater the number of piteous souls they harvest.', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (754, 'd1000000-0000-0000-0000-0000000002f2', 'wh3_main_unit_passive_nexus_of_the_elemental_winds', 'Nexus of Elemental Winds', 'Only the most powerful magic-users can harness the Winds of Magic where they intersect and the power they generate is at its strongest.', 'wh_type_augment_of_the_winds', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (755, 'd1000000-0000-0000-0000-0000000002f3', 'wh3_main_unit_passive_single_entity', 'Wounds', 'Even the greatest foes can be laid low with terrible injuries, and the greater the damage done, the less able they will be to effectively continue the fray.', 'wh_type_hex', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (756, 'd1000000-0000-0000-0000-0000000002f4', 'wh3_main_unit_passive_skullfeast', 'Skullfeast', 'As the Skullcannon devours the helpless foe, their skulls feed its incessant hunger for fresh ammunition.', 'wh_type_regeneration', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (757, 'd1000000-0000-0000-0000-0000000002f5', 'wh3_main_unit_passive_slime_trail', 'Slime Trail', 'Attacking the Fly Lord''s most faithful servants is made all the more difficult by the magical slime that slows enemy warriors and restricts their strikes.', 'wh_type_area_of_hexes', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (758, 'd1000000-0000-0000-0000-0000000002f6', 'wh3_main_unit_passive_soul_hunters', 'Soul Hunters', 'The exquisite carnage sets the Hellstriders'' souls on fire, girding and driving them further for the slaughter.', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (759, 'd1000000-0000-0000-0000-0000000002f7', 'wh3_main_unit_passive_soulscent', 'Soulscent', '"Mmmm... meat... I can smell innocence at fifty yards!"', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (760, 'd1000000-0000-0000-0000-0000000002f8', 'wh3_main_unit_passive_unbinding_ancestral_warriors', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (761, 'd1000000-0000-0000-0000-0000000002f9', 'wh3_main_unit_passive_unbinding_bloodletters', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (762, 'd1000000-0000-0000-0000-0000000002fa', 'wh3_main_unit_passive_unbinding_bloodthirster', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (763, 'd1000000-0000-0000-0000-0000000002fb', 'wh3_main_unit_passive_unbinding_blue_horrors', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (764, 'd1000000-0000-0000-0000-0000000002fc', 'wh3_main_unit_passive_unbinding_chaos_furies', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (765, 'd1000000-0000-0000-0000-0000000002fd', 'wh3_main_unit_passive_unbinding_daemonettes', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (766, 'd1000000-0000-0000-0000-0000000002fe', 'wh3_main_unit_passive_unbinding_elemental_bear', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (767, 'd1000000-0000-0000-0000-0000000002ff', 'wh3_main_unit_passive_unbinding_gorger', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, disappearing back to the winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (768, 'd1000000-0000-0000-0000-000000000300', 'wh3_main_unit_passive_unbinding_great_unclean_one', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (769, 'd1000000-0000-0000-0000-000000000301', 'wh3_main_unit_passive_unbinding_keeper_of_secrets', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (770, 'd1000000-0000-0000-0000-000000000302', 'wh3_main_unit_passive_unbinding_lord_of_change', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (771, 'd1000000-0000-0000-0000-000000000303', 'wh3_main_unit_passive_unbinding_nurglings', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (772, 'd1000000-0000-0000-0000-000000000304', 'wh3_main_unit_passive_unbinding_pink_horrors', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (773, 'd1000000-0000-0000-0000-000000000305', 'wh3_main_unit_passive_unbinding_plaguebearers', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (774, 'd1000000-0000-0000-0000-000000000306', 'wh3_main_unit_passive_unbinding_snow_leopard', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, eventually disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (775, 'd1000000-0000-0000-0000-000000000307', 'wh3_main_weapon_abilities_godkiller_pistol', 'Damned Pistol', 'As Kurnz has become corrupted, so too has this gift from the Red Tzar. Who knows what power it now holds?', 'wh_type_magic_missile', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (776, 'd1000000-0000-0000-0000-000000000308', 'wh3_main_weapon_passive_blade_of_shadows', 'Blade of Shadow', 'As more and more hapless opponents fall to Be''lakor''s Daemonic blade, so its hunger increases and its bite becomes ever more savage.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (777, 'd1000000-0000-0000-0000-000000000309', 'wh3_pro10_cataclysm_fire_magma_storm_bound', 'Magma Storm', 'The Wizard sets a fire within the very rock itself, causing the ground to splinter and the raging lifeblood of the world to gush forth and consume the enemy.', 'wh_type_vortex', 250, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (778, 'd1000000-0000-0000-0000-00000000030a', 'wh3_pro11_hero_passive_bane_of_the_dead', 'Bane of the Dead', 'Somewhere in the vestigial remains of Undead souls, a spark of awareness flickers to life upon seeing Harry, reminding them of their dreaded deaths.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (779, 'd1000000-0000-0000-0000-00000000030b', 'wh3_pro12_hero_abilities_karanaks_howl', 'Karanak''s Howl', 'As leagues untold fall away beneath his clawed feet, Karanak’s bestial howls echo through the void, drawing other Flesh Hounds to his presence.', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (780, 'd1000000-0000-0000-0000-00000000030c', 'wh3_pro12_hero_abilities_prey_of_the_blood_god', 'Prey of the Blood God', 'With the odour of his victim thick in his nostrils, Karanak''s prey draws closer, the blood scent stronger, until there is no escape…', 'wh_type_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (781, 'd1000000-0000-0000-0000-00000000030d', 'wh3_pro12_hero_passive_endless_hunter', 'Endless Hunter', 'Karanak tracks the blood scent across space and time, until the battlefield offers no hiding place from Khorne’s chosen hunter.', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (782, 'd1000000-0000-0000-0000-00000000030e', 'wh3_pro12_hero_passive_talon_of_the_skull_throne', 'Talon of the Skull Throne', 'Karanak''s kills are quicksilver perfection, the better to swiftly feed his hunger and his master''s need for spilt blood.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (783, 'd1000000-0000-0000-0000-00000000030f', 'wh3_twa06_unit_abilities_dazs_song_of_winter_sunlight', 'Dazh''s Song of Winter Sunlight', '"Death is like a winter chill; No door can keep it from us; And summer yet may bloom again; Though ice be all upon us."', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (784, 'd1000000-0000-0000-0000-000000000310', 'wh3_twa06_unit_active_conduit_of_infinity', 'Conduit of Infinity', 'Reach into the realm of the Raven God and his blessings may just reach back.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (785, 'd1000000-0000-0000-0000-000000000311', 'wh3_twa06_unit_passive_adaptive_tactics', 'Adaptive Tactics', 'The best plans are born at the brink of defeat, turning the tide when things seem most dire.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (786, 'd1000000-0000-0000-0000-000000000312', 'wh3_twa06_unit_passive_festering_gate', 'Festering Gate', '"Behold the festering hordes; from the gate they pour, ever undying in its shadow!"', 'wh_type_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (787, 'd1000000-0000-0000-0000-000000000313', 'wh3_twa06_unit_passive_gloom_of_flies', 'Gloom of Flies', '"The flies! By the Gods, so many flies!"', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (788, 'd1000000-0000-0000-0000-000000000314', 'wh3_twa06_unit_passive_hungering_blades', 'Hungering Blades', 'Quench the soil in blood; every drop is but murderous motivation!', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (789, 'd1000000-0000-0000-0000-000000000315', 'wh3_twa07_spell_bound_call_of_tor', 'Call of Tor', 'All fear the wrath of the storm-god Tor, striking foes down in a barrage of divine lightning!', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (790, 'd1000000-0000-0000-0000-000000000316', 'wh3_twa07_unit_abilities_searing_torrent', 'Searing Torrent', 'Angry spirits inhabit discs of great power, spewing Tzeentchian fire on all those below.', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (791, 'd1000000-0000-0000-0000-000000000317', 'wh3_twa07_unit_passive_mantle_of_immolation', 'Mantle of Immolation', 'Few can tolerate the scorching heat of Khorne''s rage, leaving them vulnerable to the fiery winds that sweep from His realm.', 'wh_type_area_of_hexes', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (792, 'd1000000-0000-0000-0000-000000000318', 'wh3_twa07_unit_passive_miasma_of_rot', 'Miasma of Rot', 'Clouds of gas leak from toxic spores — a reeking restorative to all those aligned with the Lord of Decay.', 'wh_type_area_of_augments', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (793, 'd1000000-0000-0000-0000-000000000319', 'wh3_twa07_unit_passive_obsessive_adoration', 'Obsessive Adoration', 'An idol of Chaos, when lavished with attention, is sure to show off in the presence of such adoring followers.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (794, 'd1000000-0000-0000-0000-00000000031a', 'wh3_twa07_unit_passive_wasting_sickness', 'The Wasting Sickness', 'Once the dreaded Wasting Sickness sets in, the muscles of the infected wither as their bones crumble to dust.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (795, 'd1000000-0000-0000-0000-00000000031b', 'wh3_twa08_spell_bound_enfeebling_foe_keeper_of_secrets_ror', 'The Enfeebling Foe', 'By means of the Lore of Shadows, the Wizard causes the enemy to be worn down by their own burdens until they are enervated to a sorry standstill.', 'wh_type_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (796, 'd1000000-0000-0000-0000-00000000031c', 'wh3_twa08_spell_bound_heart_of_winter_elemental_bear_ror', 'Heart of Winter', 'At one with the frozen plains and snowy tundra of Kislev, wherever this one goes, they bring the icy heart of the Motherland with them.', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (797, 'd1000000-0000-0000-0000-00000000031d', 'wh3_twa08_spell_bound_searing_doom', 'Searing Doom', 'A spray of sizzling silver slivers rain from the sky to impale the caster''s enemy.', 'wh_type_bombardment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (798, 'd1000000-0000-0000-0000-00000000031e', 'wh3_twa08_spell_bound_spirit_leech_great_unclean_one_ror', 'Spirit Leech', 'Just as a leech draws blood, the Wizard extends an ebon hand towards the chosen foe, sucking away their spirit through the tainted Lore of Death.', 'wh_type_direct_damage', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (799, 'd1000000-0000-0000-0000-00000000031f', 'wh3_twa08_unit_abilities_defiling_deluge', 'Defiling Deluge', 'By which the Great Unclean One calls down a disgusting shower of putrid yuck to heal themselves and harm those foes unfortunate enough to be caught in it.', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (800, 'd1000000-0000-0000-0000-000000000320', 'wh3_twa08_unit_abilities_glacial_defence', 'Glacial Defence', 'An icy carapace surrounds the Stonehorn, slowing the lumbering beast down further while adding a layer of natural armour to their defences.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (801, 'd1000000-0000-0000-0000-000000000321', 'wh3_twa08_unit_passive_goreshell', 'Goreshell', 'The closer to monstrous foes the Bloody Fist is, the less likely it is to die. Truly a blessing from Khorne Himself!', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (802, 'd1000000-0000-0000-0000-000000000322', 'wh3_twa08_unit_passive_redirecting_aura', 'Redirecting Aura', 'This little bit of fiendish battle magick rains missiles straight back to the attacker, which, with a bit of luck, ought to put paid to further outbursts!', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (803, 'd1000000-0000-0000-0000-000000000323', 'wh3_twa10_unit_passive_barrier_boost', 'Barrier Boost', 'Loose threads of arcane power from nearby incantations are plucked from the breeze and woven into the barrier, reinforcing its strength.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (804, 'd1000000-0000-0000-0000-000000000324', 'wh3_twa10_unit_passive_blisterback', 'Blisterback', 'Blisters bubble up from bulbous flesh, so assailants risk being doused in festering filth with every strike.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (805, 'd1000000-0000-0000-0000-000000000325', 'wh3_twa10_unit_passive_waterbirth', 'Waterbirth', 'Submerged in filthy, stagnant water, wounds inexplicably knit together, and skin becomes whole. More curious are the grotesque boils that flourish and erupt, birthing a new sibling.', 'wh_type_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (806, 'd1000000-0000-0000-0000-000000000326', 'wh_dlc02_unit_passive_the_flag_of_blood_keep', 'The Flag of Blood Keep', 'The Flag of the Blood Keep flashes violently; the Blood Knights run their enemies down.', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (807, 'd1000000-0000-0000-0000-000000000327', 'wh_dlc03_character_abilities_apocalyptic_vision', 'Apocalyptic Vision', 'In fitful dreams, he sees the end... The world collapsing in on itself, leaving nothing but ashes and aberration.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (808, 'd1000000-0000-0000-0000-000000000328', 'wh_dlc03_character_abilities_blood_lust', 'Blood Lust', '"The blood is the prize. The blood is the prize! THE BLOOD IS THE PRIZE!"', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (809, 'd1000000-0000-0000-0000-000000000329', 'wh_dlc03_character_abilities_call_of_violence', 'Call of Violence', '"We feel it. We all feel it. The pull to war. The tug of battle. The NEED to kill."', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (810, 'd1000000-0000-0000-0000-00000000032a', 'wh_dlc03_character_abilities_foe_seeker', 'Foe-Seeker', 'The Cloven Ones are compelled to seek out ever-greater enemies, whose bodies shall be riven in twain.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (811, 'd1000000-0000-0000-0000-00000000032b', 'wh_dlc03_hero_passive_something_wicked_this_way_comes', 'Something Wicked This Way Comes', 'The presence of the Dark Omen is an awful thing that saps the foe''s will to fight on.', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (812, 'd1000000-0000-0000-0000-00000000032c', 'wh_dlc03_hero_passive_unholy_power', 'Unholy Power', 'Malagor has a dread agenda given unto him by the Dark Gods themselves.', 'wh_type_augment_of_the_winds', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (813, 'd1000000-0000-0000-0000-00000000032d', 'wh_dlc03_lord_passive_crush_the_weak', 'Crush the Weak', 'When caught within radius of Todbringer, those enemies whose morale is already weak must face further penalties to their melee abilities.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (814, 'd1000000-0000-0000-0000-00000000032e', 'wh_dlc03_quest_passive_poisoning', 'Poisoned', 'The lame Beastlord is poisoned! The beast weakens - now is the time to strike!', 'wh_type_area_of_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (815, 'd1000000-0000-0000-0000-00000000032f', 'wh_dlc03_unit_abilities_slaughterers_call', 'Slaughterer''s Call', 'The Minotaur Lord''s blood-lust is infectious - his followers revel in the murder and gore!', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (816, 'd1000000-0000-0000-0000-000000000330', 'wh_dlc03_unit_passive_bloodgreed', 'Bloodgreed', 'Becoming more savage and frenzied the greater the scent and sight of blood.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (817, 'd1000000-0000-0000-0000-000000000331', 'wh_dlc03_unit_passive_drunken', 'Rowdy', 'These troops are emboldened when fighting, drinking and feasting together, although such ‘bravery’ is only temporary at best.', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (818, 'd1000000-0000-0000-0000-000000000332', 'wh_dlc03_unit_passive_primal_fury', 'Primal Fury', 'Goaded by Chieftains and enraged by intruders on their blood-grounds, Beastmen become consumed by a savage furore!', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (819, 'd1000000-0000-0000-0000-000000000333', 'wh_dlc03_unit_passive_soul_eater', 'Soul Eater', 'Cygors crave the souls of enemy Wizards more than anything else.', 'wh_type_area_of_hexes', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (820, 'd1000000-0000-0000-0000-000000000334', 'wh_dlc03_unit_passive_unbinding_chaos_spawn', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, disappearing back to the winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (821, 'd1000000-0000-0000-0000-000000000335', 'wh_dlc04_hero_passive_divine_power', 'Divine Power', 'Such is the strength of Sigmar''s favour that enemies fail to act in the presence of such brilliance.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (822, 'd1000000-0000-0000-0000-000000000336', 'wh_dlc04_lord_abilities_beguile', 'Master of Beguilement', 'This Vampire Lord feints and shades, confounding their enemy into missteps and errors.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (823, 'd1000000-0000-0000-0000-000000000337', 'wh_dlc04_lord_passive_aura_of_dark_majesty', 'Aura of Dark Grandeur', 'Vlad motivates his devoted followers with his majestic presence; the Lord of Undeath is without peer.', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (824, 'd1000000-0000-0000-0000-000000000338', 'wh_dlc04_spell_bound_banishment', 'Banishment', 'Creatures of the dark beware, for the Mage casts a ball of pure light to banish enemies of White Wizardry.', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (825, 'd1000000-0000-0000-0000-000000000339', 'wh_dlc04_spell_bound_banishment_innate', 'Banishment', 'Creatures of the dark beware, for the Mage casts a ball of pure light to banish enemies of White Wizardry.', 'wh_type_vortex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (826, 'd1000000-0000-0000-0000-00000000033a', 'wh_dlc04_spell_bound_hammer_of_sigmar_upgraded', 'Grand Hammer of Sigmar', 'The Warrior Priest implores Sigmar to imbue him with a modicum of divine strength, and now his hammer glows bright with power!', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (827, 'd1000000-0000-0000-0000-00000000033b', 'wh_dlc04_spell_bound_net_of_amyntok', 'Net of Amyntok', 'The Wizard casts an arcane net, created to hold the Great Deceiver himself. Any caught in its strands will struggle to act.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (828, 'd1000000-0000-0000-0000-00000000033c', 'wh_dlc04_spell_bound_shield_of_faith_upgraded', 'Grand Shield of Faith', 'The Warrior Priest’s faith manifests in the form of a shield as hard as castle-forged steel.', 'wh_type_area_of_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (829, 'd1000000-0000-0000-0000-00000000033d', 'wh_dlc04_spell_bound_soulfire_upgraded', 'Grand Soulfire', 'A battle prayer that bathes the Warrior Priest in white, holy fire, sears Sigmar’s foes but leaves the supplicant unharmed.', 'wh_type_bombardment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (830, 'd1000000-0000-0000-0000-00000000033e', 'wh_dlc04_unit_passive_balefire', 'Balefire', 'Balefire contains trace elements of Warpstone, so the burning braziers slowly drive mortal men to madness.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (831, 'd1000000-0000-0000-0000-00000000033f', 'wh_dlc04_unit_passive_blasphemous_tome', 'Blasphemous Tome', 'The unholy, never-to-be spoken words of this ancient grimoire cause the Winds of Magic to blow like a hurricane.', 'wh_type_augment_of_the_winds', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (832, 'd1000000-0000-0000-0000-000000000340', 'wh_dlc04_unit_passive_chilling_aura', 'The Chilling Aura', 'As if the enemy were caught in a blizzard or wading through treacle, the ice-cold aura slows any unit within range to a near-standstill.', 'wh_type_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (833, 'd1000000-0000-0000-0000-000000000341', 'wh_dlc04_unit_passive_strength_of_the_penitent', 'Strength of the Penitent', 'As the final battle between good and evil looms, the flagellants ready to embrace death. The time is near; the end is nigh!', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (834, 'd1000000-0000-0000-0000-000000000342', 'wh_dlc04_unit_passive_the_reliquary_binding', 'The Reliquary Binding', 'This depraved artefact, when held aloft, restores energy to those who swear fealty to its vileness.', 'wh_type_area_of_regeneration', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (835, 'd1000000-0000-0000-0000-000000000343', 'wh_dlc04_unit_passive_the_reliquary_corruption', 'The Reliquary Corruption', 'Those who dare to stand against this profane monument will suffer from its corrupting influence, to their demise.', 'wh_type_area_of_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (836, 'd1000000-0000-0000-0000-000000000344', 'wh_dlc04_unit_passive_unbinding_wight_king', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, disappearing back to the winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (837, 'd1000000-0000-0000-0000-000000000345', 'wh_dlc04_unit_passive_unholy_lodestone', 'Unholy Lodestone', 'The ringing of the arcane bell atop the Corpse Cart inspires Undead minions to continue fighting, even when grievously wounded.', 'wh_type_area_of_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (838, 'd1000000-0000-0000-0000-000000000346', 'wh_dlc04_unit_passive_vigour_mortis', 'Vigour Mortis', 'The Corpse Cart hardens shattered spirits and emboldens tattered bodies to ever greater acts of violence.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (839, 'd1000000-0000-0000-0000-000000000347', 'wh_dlc05_character_abilities_prey_of_anath_raema', 'Prey of Anath Raema', 'By all means summon the bloodthirsty Goddess of the Hunt to assist you, but always make sure you thank her afterwards…', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (840, 'd1000000-0000-0000-0000-000000000348', 'wh_dlc05_hero_abilities_arrow_of_kurnous', 'Arrow of Kurnous', 'The God of the Hunt blesses this arrow so it can travel great distances with unwavering accuracy and terrifying power.', 'wh_type_magic_missiles', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (841, 'd1000000-0000-0000-0000-000000000349', 'wh_dlc05_hero_passive_blessing_of_the_ancients', 'Blessing of the Ancients', 'The magical power permeating the forests is bestowed upon those who defend it.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (842, 'd1000000-0000-0000-0000-00000000034a', 'wh_dlc05_hero_passive_hawkish_precision', 'Hawkish Precision', 'The truly hawk-eyed always hit their targets. Always.', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (843, 'd1000000-0000-0000-0000-00000000034b', 'wh_dlc05_lord_abilities_lamentation_of_despair', 'Lamentation of Despairs', 'The Despairs are among the most feared Spites within Athel Loren, their arrival always foretelling imminent death.', 'wh_type_magic_missiles', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (844, 'd1000000-0000-0000-0000-00000000034c', 'wh_dlc05_lord_abilities_spirit_essence_of_chaos', 'Spirit-Essence of Chaos', 'To summon the essence of Chaos is to unleash its Ruinous fury upon any and all who witness it.', 'wh_type_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (845, 'd1000000-0000-0000-0000-00000000034d', 'wh_dlc05_lord_ablities_grey_wolves', 'Hounds of Orion', 'Orion''s wolves run with their Lord, defending his person with great savagery and scant regard for their own lives.', 'wh_type_vortex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (846, 'd1000000-0000-0000-0000-00000000034e', 'wh_dlc05_lord_passive_call_of_the_woods', 'Call of the Woods', 'The living embodiment of the forest; through them, their warriors feel a greater call to war.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (847, 'd1000000-0000-0000-0000-00000000034f', 'wh_dlc05_lord_passive_howl_of_the_forest', 'Howl of the Forest', 'Elven troops will fight for Athel Loren, for their very souls are tethered to its fate.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (848, 'd1000000-0000-0000-0000-000000000350', 'wh_dlc05_lord_passive_the_eye_of_kurnous', 'The Eye of Kurnous', 'Setting their eye upon the foe, the general imbues their troops with Kurnous'' spirit and the will to see his enemies destroyed.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (849, 'd1000000-0000-0000-0000-000000000351', 'wh_dlc05_lore_passive_smoke_and_mirrors', 'Smoke & Mirrors', 'A conjured shadow is just as obfuscating as a real one - the Shadow Wizard is master or mistress of the ''concealing'' arts.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (850, 'd1000000-0000-0000-0000-000000000352', 'wh_dlc05_spell_bound_shield_of_thorns', 'Shield of Thorns', 'Prickly gorse bursts from the ground around the caster''s allies, protecting them from attack like a spiky, living shield.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (851, 'd1000000-0000-0000-0000-000000000353', 'wh_dlc05_spell_bound_the_curse_of_anraheir', 'The Curse of Anraheir', 'At the spellcaster''s command, nebulous nature spirits assail the foe, clawing with hands not nearly as insubstantial as they first appear.', 'wh_type_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (852, 'd1000000-0000-0000-0000-000000000354', 'wh_dlc05_unit_abilities_storm_of_blades', 'Storm of Blades', 'What beauty and violence there is in the dance? A flurry of blades and a certain savagery of intent...', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (853, 'd1000000-0000-0000-0000-000000000355', 'wh_dlc05_unit_abilities_the_shadows_coil', 'The Shadow''s Coil', 'The wending and twisting of the Wardancers hardens their spirits and their bodies against would-be attackers.', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (854, 'd1000000-0000-0000-0000-000000000356', 'wh_dlc05_unit_abilities_woven_mist', 'Woven Mist', 'The Wardancer threads and loops, contorting to create an ethereal fabric that turns aside arrows and bolts.', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (855, 'd1000000-0000-0000-0000-000000000357', 'wh_dlc05_unit_passive_ancient_protector', '{{tr:unit_abilities_onscreen_name_wh_dlc08_quest_passive_ancient_protector}}', '{{tr:unit_abilities_tooltip_text_wh_dlc08_quest_passive_ancient_protector}}', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (856, 'd1000000-0000-0000-0000-000000000358', 'wh_dlc05_unit_passive_guardians_of_the_wildwood', 'Guardians of the Wildwood', 'The minds of these warriors are turned over entirely to the defence of the Wildwood; nothing else affects them.', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (857, 'd1000000-0000-0000-0000-000000000359', 'wh_dlc05_weapon_abilities_el_syf', 'El Syf', 'The so-called ''Northern Sword'' fears no duel; anyone who dares confront him will surely meet their death!', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (858, 'd1000000-0000-0000-0000-00000000035a', 'wh_dlc05_weapon_abilities_hawks_talon', 'Hawk''s Talon', 'Nature manifests at Orion''s call, raining a flurry of arrows upon the enemy in defence of Athel Loren.', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (859, 'd1000000-0000-0000-0000-00000000035b', 'wh_dlc06_character_abilities_effagee_of_da_git', '''Effagee'' of da Git', 'Recently, Wurrzag has taken to carrying a doll or ‘effagee’ of his foes and sticking pins in them to “stop da gitz from gettin’ away”.', 'wh_type_direct_damage', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (860, 'd1000000-0000-0000-0000-00000000035c', 'wh_dlc06_lord_abilities_mighty_oath_stone', 'Mighty Oath Stone', 'Belegar carries his enormous Oath Stone everywhere. In dire times, he stands tauntingly atop it to fight to the end.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (861, 'd1000000-0000-0000-0000-00000000035d', 'wh_dlc06_lord_abilities_revenge_incarnate', 'Revenge Incarnate', 'Centuries of Dwarf grudges flow through Belegar''s veins, who uses them to wreak vengeance upon his enemies.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (862, 'd1000000-0000-0000-0000-00000000035e', 'wh_dlc06_lord_abilities_spite_of_da_bad_moon', 'Spite of Da Bad Moon', 'Da Bad Moon offers heightened pugnacity to its weird and disgusting worshippers, spurring them to dish out even more pain.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (863, 'd1000000-0000-0000-0000-00000000035f', 'wh_dlc06_lord_abilities_tricksy_traps', 'Tricksy Traps', 'The Night Goblins are delighted and emboldened by Skarsnik''s sly, furtive plans and fiendish machinations.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (864, 'd1000000-0000-0000-0000-000000000360', 'wh_dlc06_lord_passive_locus_of_power', 'Locus of Power', 'The dense power exuded from the Anvil dampens any enemy magics hurled at Dawi nearby.', 'wh_type_explosion', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (865, 'd1000000-0000-0000-0000-000000000361', 'wh_dlc06_lord_passive_warpaint_of_wurrzag', 'Warpaint of Wurrzag', 'The terrifying visage painted upon Wurrzag affects enemies'' concentration, allowing him to take full advantage of their confusion!', 'wh_type_area_of_ward_save', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (866, 'd1000000-0000-0000-0000-000000000362', 'wh_dlc06_lord_passive_wurrzags_revenge', 'Wurrzag''s Revenge', 'Wurrzag inflicts a cloud of confusion upon his enemies, whose words ring hollow and spells fly false.', 'wh_type_hex', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (867, 'd1000000-0000-0000-0000-000000000363', 'wh_dlc06_quest_passive_squigs_go_boom', 'Squigs Go Boom', 'Not all Squigs have lasting usefulness. Some have a more fleeting... ''percussive'' utility.', 'wh_type_explosion', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (868, 'd1000000-0000-0000-0000-000000000364', 'wh_dlc06_unit_abilities_marked_by_ulthar', 'Marked by Ulthar', 'Those marked for death by the mighty Ranger or his crew may find their armour and shield of little practical use…', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (869, 'd1000000-0000-0000-0000-000000000365', 'wh_dlc06_unit_abilities_maternal_instinct', 'Maternal Instinct', 'Somewhat surprisingly, even the deadliest Arachnarok feels protective of her brood, and can draw them to her at will.', 'wh_type_summon_unit', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (870, 'd1000000-0000-0000-0000-000000000366', 'wh_dlc06_unit_abilities_skyhammer_bomb', 'Skyhammer Bomb', 'The Gyrobomber is fitted with much larger ordnance than the Gyrocopter. Should the multiple payloads hit their intended target the results will be quite spectacular!', 'wh_type_bombardment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (871, 'd1000000-0000-0000-0000-000000000367', 'wh_dlc06_unit_abilities_smoke_bomb', 'Smoke Bomb', 'Clogging the senses with acrid, stinging smoke leaves an enemy completely vulnerable.', 'wh_type_area_of_hexes', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (872, 'd1000000-0000-0000-0000-000000000368', 'wh_dlc06_unit_abilities_the_loons_of_eight_peaks', 'The Loons of Eight Peaks', 'The Goblin Fanatics of Karak Eight Peaks eschew the use of balls with their chains, favouring shaved Dwarfs instead!', 'wh_type_vortex', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (873, 'd1000000-0000-0000-0000-000000000369', 'wh_dlc06_unit_passive_liquid_fortification', 'Liquid Fortification', 'A touch of Bugman''s Courage can keep a Dawi standing and fighting, a touch unsteadily, on their feet.', 'wh_type_regeneration', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (874, 'd1000000-0000-0000-0000-00000000036a', 'wh_dlc06_unit_passive_opportunist_murderer', 'Opportunist Murderer', 'Greenskins are never gracious in victory. Wherever they can press an unfair advantage, they will!', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (875, 'd1000000-0000-0000-0000-00000000036b', 'wh_dlc06_unit_passive_power_of_the_dragonback', 'Power of the Dragonback', 'Strong and tenacious, the Dawi’s hardy, passionate nature can be put to lethally good use on the battlefield.', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (876, 'd1000000-0000-0000-0000-00000000036c', 'wh_dlc06_unit_passive_squigs_go_wild', 'Squigs Go Wild', 'If a Squig is not told what to bite, it will bite anything. Me, you, itself - anything!', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (877, 'd1000000-0000-0000-0000-00000000036d', 'wh_dlc06_unit_passive_the_old_grumblers', 'The Old Grumblers', 'Age, beard-length, and the courage that binds them; motivation, if any were needed, to fight on to the end.', 'wh_type_area_of_augments', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (878, 'd1000000-0000-0000-0000-00000000036e', 'wh_dlc07_character_abilities_heroic_killing_blow', 'Heroic Killing Blow', 'There are powerful beings who can decapitate a dragon or plunge a sword into the heart of a griffon in one mighty strike.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (879, 'd1000000-0000-0000-0000-00000000036f', 'wh_dlc07_hero_abilities_dolorous_blade', 'Dolorous Blade', 'Glowing with an uncanny light, each stroke of this sword effortlessly carves the foe clean through.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (880, 'd1000000-0000-0000-0000-000000000370', 'wh_dlc07_hero_passive_sacred_guardian', 'Sacred Guardian', '“None shall pass!”', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (881, 'd1000000-0000-0000-0000-000000000371', 'wh_dlc07_lord_abilities_favour_of_the_fay', 'Favour of the Fay', '"I didn''t know how empty was my soul... until it was filled."', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (882, 'd1000000-0000-0000-0000-000000000372', 'wh_dlc07_lord_abilities_lions_shield', 'The Lion''s Shield', 'King Louen’s shield has protected him from the first days of his Knighthood; strengthened by enchantment, it will continue to do so.', 'wh_type_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (883, 'd1000000-0000-0000-0000-000000000373', 'wh_dlc07_lord_passive_mist_of_the_lady', 'Mist of the Lady', 'The unearthly vapour moves around the foe, in between and inside – those found wanting are scarred by the Lady’s enchanted touch.', 'wh_type_area_of_hexes', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (884, 'd1000000-0000-0000-0000-000000000374', 'wh_dlc07_lord_passive_spirit_of_the_tempest', 'Spirit of the Tempest', 'More than just a Knight, Alberic is a true leader of men whose warriors are emboldened by his fighting spirit in battle.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (885, 'd1000000-0000-0000-0000-000000000375', 'wh_dlc07_unit_formation_lance', 'Lance', 'Forming a wedge before the charge enables mounted Knights to smash through enemy lines, causing great disarray among their ranks.', 'wh_type_formation', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (886, 'd1000000-0000-0000-0000-000000000376', 'wh_dlc07_unit_passive_icon_of_devotion', 'Icon of Devotion', 'Far more than allegiance or loyalty, true dedication to Lady and kingdom further empowers her Knights on the field.', 'wh_type_area_of_augments', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (887, 'd1000000-0000-0000-0000-000000000377', 'wh_dlc07_unit_passive_impetuous', 'Impetuous', 'On the battlefield, the Knights Errant are impetuous, eager to earn fame and honour in the thick of the fight. They charge boldly into the fray, heedless of danger and earning either great honour or a glorious death.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (888, 'd1000000-0000-0000-0000-000000000378', 'wh_dlc07_unit_passive_the_peasants_duty', 'The Peasant''s Duty', 'Thou shalt give unto thine glorious liege the taxes that he requires. Thou shalt labour all but feast days, and no more than a tenth-share shall you keep for kith and kin. Rejoice! For a Knight of Bretonnia provides your shield!', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (889, 'd1000000-0000-0000-0000-000000000379', 'wh_dlc08_character_abilities_hunter_of_champions', 'Hunter of Champions', 'Cursed to wander the length and breadth of the world, his never-ending quest to challenge and best the most gifted warriors.', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (890, 'd1000000-0000-0000-0000-00000000037a', 'wh_dlc08_hero_passive_ruinous_flesh', 'Ruinous Flesh', 'Werekin flesh is scored with the symbols and marks of the Dark Gods, granting additional arcane protection to their ravaged physical forms.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (891, 'd1000000-0000-0000-0000-00000000037b', 'wh_dlc08_lord_abilities_copious_vomit', 'Copious Vomit', '"HUUUURGGEHH!!! BLUUUURGGEHH!!! HUUUUUUUURRRRRGGGGGGGGGGEHH!!!"', 'wh_type_magic_missile', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (892, 'd1000000-0000-0000-0000-00000000037c', 'wh_dlc08_lord_abilities_fight_or_die', 'Fight or Die!', 'There is no other choice. There never was.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (893, 'd1000000-0000-0000-0000-00000000037d', 'wh_dlc08_lord_abilities_seafang', 'Seafang', 'There''s no outrunning the terrible, flying Longship known as the ''Seafang''; once in its sights, an agonising, merciless death is your only possible destination.', 'wh_type_wind', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (894, 'd1000000-0000-0000-0000-00000000037e', 'wh_dlc08_lord_passive_daring_deathblow', 'Extremely Daring Deathblow', 'It''s a crazy piece of acrobatics, for sure, but it might just work; if it does, his opponent has no chance.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (895, 'd1000000-0000-0000-0000-00000000037f', 'wh_dlc08_lord_passive_rage', 'Rage', '{{tr:unit_abilities_tooltip_text_wh_dlc08_unit_passive_rage}}', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (896, 'd1000000-0000-0000-0000-000000000380', 'wh_dlc08_unit_passive_berserk', 'Berserk', 'When going berserk, savage, barely-controllable warriors become savage, completely-uncontrollable warriors; best keep your distance!', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (897, 'd1000000-0000-0000-0000-000000000381', 'wh_dlc08_unit_passive_favour_of_the_ruinous_powers', 'Favour of the Ruinous Powers', 'When the Dark Gods bless the faithful assembled from atop their mighty battle-altars, loyalty is assured forevermore.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (898, 'd1000000-0000-0000-0000-000000000382', 'wh_dlc08_unit_passive_from_the_mist', 'From the Mist', 'Dark figures move and twist within the magical miasma woven by the Fimir Balefiends as additional protection against the foe.', 'wh_type_ward_save', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (899, 'd1000000-0000-0000-0000-000000000383', 'wh_dlc08_unit_passive_rage', 'Rage', 'All it takes is the white-hot heat of battle to turn the issue of poor anger management into a violent advantage.', 'wh_type_augment', 30, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (900, 'd1000000-0000-0000-0000-000000000384', 'wh_dlc15_quest_passive_primal_rage', 'Primal Rage', 'Each blow and every move only serve to make it a stronger and less-forgiving opponent.', 'wh_type_augment', 30, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (901, 'd1000000-0000-0000-0000-000000000385', 'wh_dlc15_unit_passive_unbinding_rogue_idol', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (902, 'd1000000-0000-0000-0000-000000000386', 'wh_main_character_abilities_arcane_conduit', 'Arcane Conduit', 'A strong mind is needed to channel the Winds of Magic. Those that have such a gift become arcane conduits – funnelling the magical tempests to their cause.', 'wh_type_augment_of_the_winds', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (903, 'd1000000-0000-0000-0000-000000000387', 'wh_main_character_abilities_blood_lust', 'Blood Lust', 'Vampires have long had a savage and unstoppable bloodlust. They will continue to slaughter until the foe has either been turned to Undeath or lies dead at their feet.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (904, 'd1000000-0000-0000-0000-000000000388', 'wh_main_character_abilities_deadly_onslaught', 'Deadly Onslaught', 'Such is the power and ferocity of the champion, that those who stand in his way will falter against the warrior''s impact.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (905, 'd1000000-0000-0000-0000-000000000389', 'wh_main_character_abilities_foe_seeker', 'Foe-Seeker', 'There are those who wish nothing more than to be at the heart of battle, seeking foes to vanquish.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (906, 'd1000000-0000-0000-0000-00000000038a', 'wh_main_character_abilities_foe_seeker_summoned', '{{tr:unit_abilities_onscreen_name_wh_main_character_abilities_foe_seeker}}', 'There are those who wish nothing more than to be at the heart of battle, seeking foes to vanquish.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (907, 'd1000000-0000-0000-0000-00000000038b', 'wh_main_character_abilities_get_back_ere', 'Get Back ''Ere!', 'Da Boss ain''t ready to run an'' so expects da boyz to stay put too!', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (908, 'd1000000-0000-0000-0000-00000000038c', 'wh_main_character_abilities_heroic_killing_blow', 'Heroic Killing Blow', 'There are powerful beings who can decapitate a dragon or plunge a sword into the heart of a griffon in one mighty strike.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (909, 'd1000000-0000-0000-0000-00000000038d', 'wh_main_character_abilities_magical_animus', 'Magical Animus', 'With an arcane cry, all around rally to fight in battle once more.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (910, 'd1000000-0000-0000-0000-00000000038e', 'wh_main_character_abilities_rally', 'Rally!', 'To rally the troops and bring them back to the fore takes strong leadership skills and an iron will.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (911, 'd1000000-0000-0000-0000-00000000038f', 'wh_main_character_abilities_red_fury', 'Red Fury', 'Vampires have long had a savage and unstoppable bloodlust. They will continue to slaughter until their enemies lie dead at their feet, or have been turned to Undeath.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (912, 'd1000000-0000-0000-0000-000000000390', 'wh_main_character_abilities_stand_or_die', 'Stand or Die!', 'Those whose word is law ensure their troops will not run by issuing this dread order.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (913, 'd1000000-0000-0000-0000-000000000391', 'wh_main_character_abilities_stand_your_ground', 'Stand Your Ground!', 'On the battlefield, the craven''s path is an easy one, but for those champions that choose to stand? Fortune will surely favour them and their troops.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (914, 'd1000000-0000-0000-0000-000000000392', 'wh_main_character_abilities_undeath_resurgent', 'Undeath Resurgent', 'Arise! Do not falter! Do not crumble! Back to life once more!', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (915, 'd1000000-0000-0000-0000-000000000393', 'wh_main_character_passive_benediction', 'Benediction', 'The Warrior Priest passes the blessings of the Heldenhammer to the brave men around him.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (916, 'd1000000-0000-0000-0000-000000000394', 'wh_main_character_passive_dark_benediction', 'Dark Benediction', 'Dark Blessings given freely from long-dead souls follow in the Wight Kings'' wake. And so the dead strive for Unlife...', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (917, 'd1000000-0000-0000-0000-000000000395', 'wh_main_character_passive_evasion', 'Evasion', 'Those with such skills can evade enemy attacks with ease and break from combat, should they feel that it is tactically important to do so.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (918, 'd1000000-0000-0000-0000-000000000396', 'wh_main_character_passive_master_of_the_dead', 'Master of the Dead', 'Necromancers can not only marshal the dead, but leech the power from any souls fleeing their mortal remains.', 'wh_type_area_of_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (919, 'd1000000-0000-0000-0000-000000000397', 'wh_main_hero_abilities_accusation', 'Accusation', 'The Witch Hunter levels his finger across the battlefield and accuses one of the enemy of arch-heresy!', 'wh_type_hex', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (920, 'd1000000-0000-0000-0000-000000000398', 'wh_main_hero_abilities_ballistics_calibration', 'Ballistics Calibration', 'This Hero has an eye for accuracy, firing rates and enemy sweet spots. War machines will benefit from his presence.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (921, 'd1000000-0000-0000-0000-000000000399', 'wh_main_hero_abilities_immortal_will', 'Immortal Will', 'Immortal spirits will refuse to leave the bounds of the mortal plane, and so cannot be put to rest with ease.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (922, 'd1000000-0000-0000-0000-00000000039a', 'wh_main_hero_abilities_mad_cap_mushrooms', 'Mad Cap Mushrooms', 'Night Goblin Shamans brew a pungent fungus potion that, when drunk, will send the Fanatics into a spinning, whirling cyclone of death!', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (923, 'd1000000-0000-0000-0000-00000000039b', 'wh_main_hero_abilities_slippery', 'Slippery', 'Those who are "slippery" cannot be cornered or pinned - they simply "slip" away…', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (924, 'd1000000-0000-0000-0000-00000000039c', 'wh_main_hero_passive_aura_of_the_lady', 'Aura of the Lady', 'The Lady of the Lake protects her Knights from the devious enchantments of the enemy.', 'wh_type_area_of_ward_save', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (925, 'd1000000-0000-0000-0000-00000000039d', 'wh_main_hero_passive_extra_powder', 'Extra Powder', 'There are those who have a knack for pushing artillery and their crews to new heights, allowing such machines to fire further than ever before.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (926, 'd1000000-0000-0000-0000-00000000039e', 'wh_main_hero_passive_forgefire', 'Forgefire', 'The fires of a Runesmith’s forge burn brighter and hotter, its blessing upon an ally’s weapons increasing their potency.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (927, 'd1000000-0000-0000-0000-00000000039f', 'wh_main_hero_passive_swarm_of_flies', 'Swarm of Flies', 'Flies surround them, making combat even harder as the swarm buzzes into mouths, ears and other vulnerable orifices!', 'wh_type_area_of_hexes', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (928, 'd1000000-0000-0000-0000-0000000003a0', 'wh_main_lord_abilities_lord_of_the_storm', 'Lord of the Storm', 'The ancient Shaggoth summons forth lightning to strike down his prey.', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (929, 'd1000000-0000-0000-0000-0000000003a1', 'wh_main_lord_passive_beloved_son_of_bretonnia', 'Beloved Son of Bretonnia', 'Should the Royarch of fair Bretonnia fall, then the anger in its Knights and smallfolk shall be fierce.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (930, 'd1000000-0000-0000-0000-0000000003a2', 'wh_main_lord_passive_deathblow', 'Deathblow', 'Such is the strength within this warrior that when they strike it is sure to be a deathblow!', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (931, 'd1000000-0000-0000-0000-0000000003a3', 'wh_main_lord_passive_get_on_wiv_it', 'Get on Wiv it!', 'Azhag has no tolerance for infighting, when he issues an order the boyz must ''get on wiv it'' or pay with a particularly grisly death.', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (932, 'd1000000-0000-0000-0000-0000000003a4', 'wh_main_lord_passive_high_king', 'High King', 'The High King is the embodiment of the Karaz Ankor. Should he be wounded or even fall then the Dwarfs will rise in a vengeful rage!', 'wh_type_area_of_augments', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (933, 'd1000000-0000-0000-0000-0000000003a5', 'wh_main_lord_passive_hold_the_line', 'Hold the Line!', 'Those in command of the ranks will issue their orders with a ferocious bark, expecting instant obeisance.', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (934, 'd1000000-0000-0000-0000-0000000003a6', 'wh_main_lord_passive_the_blessing_of_the_lady', 'The Blessing of the Lady', 'The Lady''s blessing is a wondrous gift freely graced upon all Bretonnian subjects, should they but kneel and utter their devotion.', 'wh_type_ward_save', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (935, 'd1000000-0000-0000-0000-0000000003a7', 'wh_main_lord_passive_the_blessing_of_the_lady_unit_upgrade', 'The Blessing of the Lady', 'The Lady''s blessing is a wondrous gift freely graced upon all Bretonnian subjects, should they but kneel and utter their devotion.', 'wh_type_ward_save', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (936, 'd1000000-0000-0000-0000-0000000003a8', 'wh_main_lord_passive_the_hunger', 'The Hunger', 'As the Vampires rip apart their victims they feast on the blood that spills forth – gaining in strength and lost stamina.', 'wh_type_regeneration', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (937, 'd1000000-0000-0000-0000-0000000003a9', 'wh_main_lord_passive_the_ladys_champion', 'The Lady''s Champion', 'Those that claim the honour of the Lady''s Champion benefit from her protection even more than Knights who have supped from the Grail.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (938, 'd1000000-0000-0000-0000-0000000003aa', 'wh_main_mount_abilities_locus_of_hysh', 'Locus of Hysh', 'As Hysh gathers and swirls around the Luminark, it creates a becalming eddy that other magical winds struggle to penetrate.', 'wh_type_hex_of_the_winds', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (939, 'd1000000-0000-0000-0000-0000000003ab', 'wh_main_mount_passive_aura_of_protection', 'Aura of Protection', 'The magical aura surrounding this unit protects allies from harm.', 'wh_type_ward_save', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (940, 'd1000000-0000-0000-0000-0000000003ac', 'wh_main_mount_passive_bloodroar', 'Bloodroar', 'The mighty griffon lets out a blood-curdling roar, chilling his enemies.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (941, 'd1000000-0000-0000-0000-0000000003ad', 'wh_main_spell_bound_bironas_timewarp', 'Birona''s Timewarp', 'The Wizard infuses his allies with Light Magic, freeing them from the passage of time and speeding up their actions.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (942, 'd1000000-0000-0000-0000-0000000003ae', 'wh_main_spell_bound_chain_lightning_ror', 'Chain Lightning', 'Lightning arcs across the battlefield, leaping from foe-to-foe with crackling fury until there are none left within the storm.', 'wh_type_vortex', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (943, 'd1000000-0000-0000-0000-0000000003af', 'wh_main_spell_bound_hammer_of_sigmar', 'Hammer of Sigmar', 'The Warrior Priest implores Sigmar to imbue him with a modicum of divine strength, and now his hammer glows bright with power!', 'wh_type_area_of_augments', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (944, 'd1000000-0000-0000-0000-0000000003b0', 'wh_main_spell_bound_shield_of_faith', 'Shield of Faith', 'The Warrior Priest’s faith manifests in the form of a shield as hard as castle-forged steel.', 'wh_type_area_of_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (945, 'd1000000-0000-0000-0000-0000000003b1', 'wh_main_spell_bound_soulfire', 'Soulfire', 'A battle prayer that bathes the Warrior Priest in white, holy fire, sears Sigmar’s foes but leaves the supplicant unharmed.', 'wh_type_bombardment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (946, 'd1000000-0000-0000-0000-0000000003b2', 'wh_main_spell_light_shems_burning_gaze_bound', 'Shem''s Burning Gaze', 'Bolts of cleansing energy fly from the Wizard’s hands, searing evil wherever they strike.', 'wh_type_magic_missiles', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (947, 'd1000000-0000-0000-0000-0000000003b3', 'wh_main_unit_abilities_black_nimbus', 'Black Nimbus', 'A pulsing nimbus of darkness envelops the Black Coach, making it sleeker and more resistant to enemies.', 'wh_type_augment', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (948, 'd1000000-0000-0000-0000-0000000003b4', 'wh_main_unit_abilities_black_scythes', 'Black Scythes', 'The Black Coach manifests gleaming scythes, as sharp as the night is dark.', 'wh_type_augment', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (949, 'd1000000-0000-0000-0000-0000000003b5', 'wh_main_unit_abilities_blooood', 'Blooood!', 'The Hellcannon breaks its chains and rushes forwards. Increased movement speed.', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (950, 'd1000000-0000-0000-0000-0000000003b6', 'wh_main_unit_abilities_boom', 'Boom!', 'The Hellcannon''s blasts are devastating!', 'wh_type_augment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (951, 'd1000000-0000-0000-0000-0000000003b7', 'wh_main_unit_abilities_entrenchment', 'Entrenchment', 'All the sons of Grungni can dig-in, enabling them to better resist physical attacks from the foe. Any missile attacks they can make are also improved.', 'wh_type_augment', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (952, 'd1000000-0000-0000-0000-0000000003b8', 'wh_main_unit_abilities_gyrobomber_bomb', 'Gyrobomber Bomb', 'The Gyrobomber is fitted with much larger ordnance than the Gyrocopter. Should the multiple payloads hit their intended target the results will be quite spectacular!', 'wh_type_bombardment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (953, 'd1000000-0000-0000-0000-0000000003b9', 'wh_main_unit_abilities_gyrocopter_bomb', 'Gyrocopter Bomb', 'As the Gyrocopter squadron speeds over the heads of the enemy, each pilot releases a single wing-mounted bomb onto targets below.', 'wh_type_bombardment', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (954, 'd1000000-0000-0000-0000-0000000003ba', 'wh_main_unit_abilities_spinning_loons', 'Spinning Loons', 'Sent mad by drinking fungus brew, Night Goblin Fanatics are released from their mobs as a twirling cyclone of destruction armed with a large ball and chain!', 'wh_type_vortex', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (955, 'd1000000-0000-0000-0000-0000000003bb', 'wh_main_unit_abilities_unholy_vigour', 'Unholy Vigour', 'The Cairn Wraith and the skeletal steeds pulling the Black Coach are filled with unholy vigour.', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (956, 'd1000000-0000-0000-0000-0000000003bc', 'wh_main_unit_passive_deathblow', 'Deathblow', 'Such is the strength within this warrior that when they strike it is sure to be a deathblow!', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (957, 'd1000000-0000-0000-0000-0000000003bd', 'wh_main_unit_passive_frenzy', 'Frenzy', 'Some warriors care not for their own personal safety, and so work themselves into a whirlwind of destruction and mindless violence!', 'wh_type_augment', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (958, 'd1000000-0000-0000-0000-0000000003be', 'wh_main_unit_passive_regeneration', 'Regeneration', 'There are beings and creatures that can mend bone and knit flesh at an incredible rate. A mighty boon, but one stunted by fire.', 'wh_type_regeneration', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (959, 'd1000000-0000-0000-0000-0000000003bf', 'wh_main_unit_passive_unbinding_critical', 'Unbound', 'Summoned creatures exist in this world on borrowed time, disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (960, 'd1000000-0000-0000-0000-0000000003c0', 'wh_main_unit_passive_unbinding_feral_cold_ones', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (961, 'd1000000-0000-0000-0000-0000000003c1', 'wh_main_unit_passive_unstable', 'Crumbling', 'The dead do not rest easily in the Old World. Those summoned by Vampires and Necromancers no longer have mortal concerns - they serve only their master''s will.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (962, 'd1000000-0000-0000-0000-0000000003c2', 'wh_main_unit_passive_unstable_mark_ii', 'Disintegrating', 'The Dark Magic binding has failed. Both flesh and Necromantic energy slough off the subjects, leaving naught but dust.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (963, 'd1000000-0000-0000-0000-0000000003c3', 'wh_pro01_lord_abilities_flash_bomb', 'Flash Bomb', 'A bang, a flash - the foes stagger slowly and blindly whilst you take full advantage of their disarray.', 'wh_type_area_of_hexes', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (964, 'd1000000-0000-0000-0000-0000000003c4', 'wh_pro01_lord_passive_grombrindal_has_no_fear', 'Grombrindal Has No Fear', 'As battle-hardened as he is ancient, the White Dwarf will always stand his ground, no matter the pandemonium unfolding around him.', 'wh_type_area_of_augments', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (965, 'd1000000-0000-0000-0000-0000000003c5', 'wh_pro03_lord_abilities_lord_of_undeath', 'Lord of Undeath', 'The Lichemaster raises the ancient Wight to do his bidding, but Krell serves Nagash first and foremost...', 'wh_type_summon_unit', 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (966, 'd1000000-0000-0000-0000-0000000003c6', 'wh_pro03_unit_passive_unbinding_krell', 'Unbinding', 'Summoned creatures exist in this world on borrowed time, disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (967, 'd1000000-0000-0000-0000-0000000003c7', 'wh_pro03_unit_passive_unbinding_krell_upgraded', 'Unbinding', 'Summoned creatures exist in this world on borrowed time before disappearing back to the Winds from whence they came.', 'wh_type_direct_damage', 0, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (968, 'd1000000-0000-0000-0000-0000000003c8', 'wh_pro04_unit_abilities_apocalyptic_charge', 'Apocalyptic Charge', 'If you see him coming run as fast as you can… not that it will do you any good whatsoever!', 'wh_type_area_of_augments', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (969, 'd1000000-0000-0000-0000-0000000003c9', 'wh_pro04_unit_abilities_enrage', 'Enrage', 'You really don''t want to make them angry. No, *really*.', 'wh_type_ward_save', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (970, 'd1000000-0000-0000-0000-0000000003ca', 'wh_pro04_unit_abilities_loecs_shroud', 'Loec''s Shroud', 'Shadows be thy cloak and darkness thy ally.', 'wh_type_hiding', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (971, 'd1000000-0000-0000-0000-0000000003cb', 'wh_pro04_unit_abilities_soul_devourer', 'Soul Devourer', 'Sometimes less really is more; the souls of the fallen feed the engines of war.', 'wh_type_augment', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (972, 'd1000000-0000-0000-0000-0000000003cc', 'wh_pro04_unit_abilities_warp_gaze', 'Warp Gaze', 'Never make direct eye-contact with a Beastman lest it mark you out for a hideous, flesh-ripping demise.', 'wh_type_hex', 25, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (973, 'd1000000-0000-0000-0000-0000000003cd', 'wh_pro04_unit_passive_guardian', 'Guardian', 'In the midst of a bloodbath it''s good to know that someone has your back.', 'wh_type_area_of_ward_save', 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (974, 'd1000000-0000-0000-0000-0000000003ce', 'wh_pro04_unit_passive_wildfire_aura', 'The Wildfire Aura', 'The forest looks after its own.', 'wh_type_area_of_ward_save', 50, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (975, 'd1000000-0000-0000-0000-0000000003cf', 'wh_main_lore_passive_kindleflame', 'Kindleflame', 'Fire feeds fire, two blazes together are stronger and hotter than two apart. The Kindleflame intensifies such fire.', 'wh_type_area_of_ward_save_hex', 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null);
